/* QB_PHYSICS — compact curated bank (source of truth). Row {i,g,u,d,t,q,o[4],c,e}. */
window.QB_PHYSICS = [
  {"i":"phys-g11-vec-001","g":11,"u":"Vectors","d":"easy","t":"definition","q":"Which of the following is a vector quantity?","o":["Mass","Temperature","Velocity","Time"],"c":2,"e":"A vector has both magnitude and direction. Velocity specifies speed and direction, while mass, temperature and time are scalars (magnitude only)."},
  {"i":"phys-g11-vec-002","g":11,"u":"Vectors","d":"easy","t":"calculation","q":"Two forces of 3 N and 4 N act at right angles to each other on a point. What is the magnitude of their resultant?","o":["1 N","5 N","7 N","12 N"],"c":1,"e":"For perpendicular vectors, R = √(3² + 4²) = √(9 + 16) = √25 = 5 N."},
  {"i":"phys-g11-vec-003","g":11,"u":"Vectors","d":"easy","t":"conceptual","q":"When two vectors point in exactly opposite directions, the magnitude of their resultant equals:","o":["The sum of their magnitudes","The difference of their magnitudes","Zero always","The product of their magnitudes"],"c":1,"e":"Anti-parallel vectors partly cancel, so the resultant magnitude is |A − B|, the difference of the two magnitudes."},
  {"i":"phys-g11-mech-001","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A car travels 100 m in 5 s at constant velocity. What is its speed?","o":["0.05 m/s","20 m/s","500 m/s","25 m/s"],"c":1,"e":"Speed = distance / time = 100 m ÷ 5 s = 20 m/s."},
  {"i":"phys-g11-mech-002","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"definition","q":"What is the SI unit of acceleration?","o":["m/s","m/s²","m·s","N"],"c":1,"e":"Acceleration is the rate of change of velocity (m/s) per second, giving units of m/s²."},
  {"i":"phys-g11-mech-003","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"An object starts from rest and accelerates uniformly at 2 m/s² for 4 s. What is its final velocity?","o":["2 m/s","6 m/s","8 m/s","0.5 m/s"],"c":2,"e":"Using v = u + at with u = 0: v = 0 + (2)(4) = 8 m/s."},
  {"i":"phys-g11-dyn-001","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A net force of 10 N acts on a 2 kg object. What is its acceleration?","o":["20 m/s²","0.2 m/s²","5 m/s²","12 m/s²"],"c":2,"e":"Newton's second law: a = F/m = 10 N ÷ 2 kg = 5 m/s²."},
  {"i":"phys-g11-dyn-002","g":11,"u":"Dynamics","d":"easy","t":"definition","q":"Newton's first law of motion is also known as the law of:","o":["Acceleration","Inertia","Action–reaction","Gravitation"],"c":1,"e":"Newton's first law states that an object stays at rest or in uniform motion unless acted on by a net force — this tendency to resist change is inertia."},
  {"i":"phys-g11-dyn-003","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"What is the weight of a 10 kg object near Earth's surface? (g = 9.8 m/s²)","o":["1.02 N","10 N","98 N","9.8 N"],"c":2,"e":"Weight W = mg = (10 kg)(9.8 m/s²) = 98 N."},
  {"i":"phys-g11-rot-001","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"definition","q":"What is the SI unit of torque?","o":["N/m","N·m","N·m²","N·s"],"c":1,"e":"Torque = force × perpendicular distance, so its unit is newton·metre (N·m)."},
  {"i":"phys-g11-rot-002","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A force of 20 N is applied perpendicularly at the end of a 0.5 m wrench. What is the torque about the pivot?","o":["40 N·m","10 N·m","20.5 N·m","0.025 N·m"],"c":1,"e":"Torque τ = F × r = (20 N)(0.5 m) = 10 N·m."},
  {"i":"phys-g11-grav-001","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"conceptual","q":"According to Newton's law of gravitation, if the distance between two masses is doubled, the gravitational force becomes:","o":["Half","Double","One quarter","Four times"],"c":2,"e":"Gravitational force F ∝ 1/r². Doubling r gives a factor of 1/2² = 1/4, so the force becomes one quarter."},
  {"i":"phys-g11-elas-001","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"calculation","q":"A spring of stiffness 200 N/m is stretched by 0.1 m. What is the restoring force? (Hooke's law)","o":["2 N","20 N","2000 N","0.5 N"],"c":1,"e":"Hooke's law: F = kx = (200 N/m)(0.1 m) = 20 N."},
  {"i":"phys-g11-heat-001","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"definition","q":"What is the SI unit of heat energy?","o":["Watt","Newton","Joule","Pascal"],"c":2,"e":"Heat is a form of energy, and the SI unit of energy is the joule (J)."},
  {"i":"phys-g11-heat-002","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"calculation","q":"How much heat is needed to raise the temperature of 2 kg of water by 10 °C? (c = 4200 J/kg·°C)","o":["8400 J","84000 J","420 J","21000 J"],"c":1,"e":"Q = mcΔT = (2 kg)(4200 J/kg·°C)(10 °C) = 84000 J."},
  {"i":"phys-g12-estat-001","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"definition","q":"Like charges __________ and unlike charges __________.","o":["attract; repel","repel; attract","attract; attract","repel; repel"],"c":1,"e":"By Coulomb's law, charges of the same sign repel each other, while charges of opposite sign attract."},
  {"i":"phys-g12-estat-002","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"definition","q":"What is the SI unit of electric charge?","o":["Volt","Ampere","Coulomb","Farad"],"c":2,"e":"Electric charge is measured in coulombs (C); 1 C = 1 A·s."},
  {"i":"phys-g12-cap-001","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"definition","q":"What is the SI unit of capacitance?","o":["Henry","Farad","Ohm","Tesla"],"c":1,"e":"Capacitance is measured in farads (F), where 1 F = 1 coulomb per volt (C/V)."},
  {"i":"phys-g12-curr-001","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"A 12 V battery drives a current through a 4 Ω resistor. What is the current? (Ohm's law)","o":["48 A","3 A","0.33 A","16 A"],"c":1,"e":"Ohm's law: I = V/R = 12 V ÷ 4 Ω = 3 A."},
  {"i":"phys-g12-curr-002","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"Two resistors of 3 Ω and 6 Ω are connected in series. What is the total resistance?","o":["2 Ω","9 Ω","0.5 Ω","18 Ω"],"c":1,"e":"Resistors in series add directly: R_total = 3 Ω + 6 Ω = 9 Ω."},
  {"i":"phys-g12-mag-001","g":10,"u":"Magnetism","d":"easy","t":"definition","q":"What is the SI unit of magnetic flux density (magnetic field strength B)?","o":["Weber","Tesla","Henry","Gauss"],"c":1,"e":"Magnetic flux density B is measured in teslas (T); 1 T = 1 Wb/m²."},
  {"i":"phys-g12-wave-001","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"easy","t":"calculation","q":"A wave has a frequency of 50 Hz and a wavelength of 4 m. What is its speed?","o":["12.5 m/s","54 m/s","200 m/s","0.08 m/s"],"c":2,"e":"Wave speed v = fλ = (50 Hz)(4 m) = 200 m/s."},
  {"i":"phys-g12-wave-002","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"easy","t":"conceptual","q":"Which type of mirror always produces an upright, diminished (virtual) image of distant objects?","o":["Concave mirror","Plane mirror","Convex mirror","Parabolic mirror"],"c":2,"e":"A convex (diverging) mirror always forms an upright, reduced, virtual image regardless of object distance, which is why it is used as a wide-view side mirror."},
  {"i":"phys-g12-nuc-001","g":11,"u":"Nuclear Physics","d":"easy","t":"definition","q":"Which type of radiation has the greatest penetrating power?","o":["Alpha","Beta","Gamma","All equal"],"c":2,"e":"Gamma rays are high-energy photons with no charge and no mass, so they penetrate far more than the heavier alpha or lighter beta particles."},
  {"i":"phys-g12-elec-001","g":12,"u":"Electronics","d":"easy","t":"definition","q":"An ideal diode allows current to flow:","o":["In both directions equally","Only in the forward (forward-biased) direction","Only when reverse-biased","Never"],"c":1,"e":"A diode conducts only when forward-biased; when reverse-biased it blocks current, so it acts as a one-way valve for current."},
  {"i":"phys-g12-elec-002","g":12,"u":"Electronics","d":"easy","t":"conceptual","q":"A two-input AND gate outputs logic 1 only when:","o":["At least one input is 1","Both inputs are 1","Both inputs are 0","The inputs differ"],"c":1,"e":"An AND gate outputs 1 only if all inputs are 1; for two inputs that means A = 1 AND B = 1."},
  {"i":"phys-g11-vec-101","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"A vector of magnitude 10 N makes a 30° angle with the horizontal. What is its horizontal (x) component? (cos 30° ≈ 0.866)","o":["5 N","8.66 N","10 N","0.866 N"],"c":1,"e":"The x-component is Fₓ = F cos θ = 10 × cos 30° = 10 × 0.866 = 8.66 N."},
  {"i":"phys-g11-vec-102","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Two displacement vectors, 6 m east and 8 m north, are added. What is the magnitude of the resultant displacement?","o":["14 m","2 m","10 m","48 m"],"c":2,"e":"Perpendicular vectors: R = √(6² + 8²) = √(36 + 64) = √100 = 10 m."},
  {"i":"phys-g11-mech-101","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A ball is thrown vertically upward with an initial speed of 19.6 m/s. How high does it rise? (g = 9.8 m/s²)","o":["9.8 m","19.6 m","39.2 m","2 m"],"c":1,"e":"At the top v = 0. Using v² = u² − 2gh: 0 = (19.6)² − 2(9.8)h → h = 384.16 / 19.6 = 19.6 m."},
  {"i":"phys-g11-mech-102","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"An object is dropped from rest. How far does it fall in 3 s? (g = 9.8 m/s²)","o":["29.4 m","44.1 m","14.7 m","88.2 m"],"c":1,"e":"s = ½gt² = ½(9.8)(3²) = ½(9.8)(9) = 44.1 m."},
  {"i":"phys-g11-mech-103","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A projectile is launched horizontally from a 20 m high cliff. How long is it in the air before hitting the ground? (g = 10 m/s², stated)","o":["1 s","2 s","4 s","0.5 s"],"c":1,"e":"Vertical fall: 20 = ½(10)t² → t² = 4 → t = 2 s. Horizontal launch speed does not affect fall time."},
  {"i":"phys-g11-mech-104","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A car decelerates uniformly from 30 m/s to 10 m/s over 5 s. What is its acceleration?","o":["−4 m/s²","−8 m/s²","4 m/s²","−2 m/s²"],"c":0,"e":"a = (v − u)/t = (10 − 30)/5 = −20/5 = −4 m/s² (the negative sign indicates deceleration)."},
  {"i":"phys-g11-dyn-101","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 5 kg block on a frictionless surface is pushed by a 15 N horizontal force. What is the magnitude of the acceleration?","o":["75 m/s²","3 m/s²","0.33 m/s²","10 m/s²"],"c":1,"e":"With no friction, a = F/m = 15 N ÷ 5 kg = 3 m/s²."},
  {"i":"phys-g11-dyn-102","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 2 kg block rests on a surface with coefficient of static friction 0.4. What minimum horizontal force is needed to start it moving? (g = 9.8 m/s²)","o":["0.8 N","7.84 N","19.6 N","4 N"],"c":1,"e":"Maximum static friction = μmg = (0.4)(2)(9.8) = 7.84 N, so a force just exceeding 7.84 N is required."},
  {"i":"phys-g11-dyn-103","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 1000 kg car accelerates from 0 to 20 m/s in 10 s. What net force acts on it?","o":["2000 N","200 N","20000 N","500 N"],"c":0,"e":"a = 20/10 = 2 m/s²; F = ma = (1000)(2) = 2000 N."},
  {"i":"phys-g11-rot-101","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A force of 50 N is applied at 0.4 m from a pivot, at 30° to the lever arm. What is the torque? (sin 30° = 0.5)","o":["20 N·m","10 N·m","17.3 N·m","5 N·m"],"c":1,"e":"τ = rF sin θ = (0.4)(50)(sin 30°) = (0.4)(50)(0.5) = 10 N·m."},
  {"i":"phys-g11-rot-102","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"conceptual","q":"A solid disk and a hoop of the same mass and radius roll down an incline. Which reaches the bottom first?","o":["The hoop","The solid disk","They arrive together","Neither rolls"],"c":1,"e":"The solid disk has a smaller moment of inertia (½MR² vs MR² for the hoop), so more of its energy goes to translation, giving it greater linear acceleration and an earlier arrival."},
  {"i":"phys-g11-grav-101","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"conceptual","q":"The escape velocity from a planet depends on which of the following?","o":["The mass of the escaping object","The planet's mass and radius","The launch angle only","The object's color"],"c":1,"e":"Escape velocity v = √(2GM/R) depends only on the planet's mass M and radius R, not on the escaping object's mass."},
  {"i":"phys-g11-grav-102","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"The acceleration due to gravity on a planet's surface is g = GM/R². If a planet has the same mass as Earth but twice the radius, its surface gravity is:","o":["The same as Earth's","Half of Earth's","One quarter of Earth's","Twice Earth's"],"c":2,"e":"g ∝ 1/R². Doubling R gives g multiplied by 1/2² = 1/4 of Earth's value."},
  {"i":"phys-g11-elas-101","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A uniform 2 m beam carries a 60 N weight at one end. Where must a single support be placed so the beam balances, ignoring its own weight, with a 60 N weight also at the other end?","o":["At the center (1 m)","0.5 m from one end","At one end","It cannot balance"],"c":0,"e":"With equal weights at both ends, equal torques about the center are produced, so the support at the midpoint (1 m) gives balance."},
  {"i":"phys-g11-elas-102","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A wire stretches 2 mm under a 100 N load. Assuming Hooke's law, how much will it stretch under 250 N?","o":["2 mm","5 mm","1.25 mm","0.8 mm"],"c":1,"e":"Extension is proportional to load: x₂ = x₁ × (F₂/F₁) = 2 mm × (250/100) = 5 mm."},
  {"i":"phys-g11-heat-101","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"A 0.5 kg metal block absorbs 9000 J and its temperature rises by 40 °C. What is its specific heat capacity?","o":["450 J/kg·°C","180000 J/kg·°C","225 J/kg·°C","720 J/kg·°C"],"c":0,"e":"c = Q/(mΔT) = 9000 / (0.5 × 40) = 9000 / 20 = 450 J/kg·°C."},
  {"i":"phys-g11-heat-102","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"Convert 27 °C to the Kelvin scale.","o":["27 K","246 K","300 K","327 K"],"c":2,"e":"T(K) = T(°C) + 273 = 27 + 273 = 300 K."},
  {"i":"phys-g12-estat-101","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two point charges of +2 μC and +3 μC are 0.1 m apart. What is the magnitude of the force between them? (k = 9×10⁹ N·m²/C²)","o":["5.4 N","0.54 N","54 N","0.054 N"],"c":0,"e":"F = kq₁q₂/r² = (9×10⁹)(2×10⁻⁶)(3×10⁻⁶)/(0.1)² = (9×10⁹)(6×10⁻¹²)/0.01 = 0.054/0.01 = 5.4 N."},
  {"i":"phys-g12-estat-102","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"conceptual","q":"If the distance between two fixed charges is halved, the Coulomb force between them becomes:","o":["Half","Double","Four times larger","One quarter"],"c":2,"e":"F ∝ 1/r². Halving r multiplies the force by 1/(½)² = 4, so it becomes four times larger."},
  {"i":"phys-g12-cap-101","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"A 4 μF capacitor is charged to 50 V. How much charge does it store? (Q = CV)","o":["200 μC","12.5 μC","200 C","0.08 μC"],"c":0,"e":"Q = CV = (4 μF)(50 V) = 200 μC."},
  {"i":"phys-g12-cap-102","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two capacitors of 2 μF and 3 μF are connected in parallel. What is their combined capacitance?","o":["1.2 μF","5 μF","0.83 μF","6 μF"],"c":1,"e":"Capacitors in parallel add directly: C_total = 2 μF + 3 μF = 5 μF."},
  {"i":"phys-g12-curr-101","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two resistors of 4 Ω and 4 Ω are connected in parallel. What is the equivalent resistance?","o":["8 Ω","2 Ω","4 Ω","16 Ω"],"c":1,"e":"For two equal parallel resistors, R_eq = R/2 = 4/2 = 2 Ω (or 1/R_eq = 1/4 + 1/4 = 1/2)."},
  {"i":"phys-g12-curr-102","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"A device draws 2 A from a 120 V supply. What is its power consumption?","o":["60 W","240 W","122 W","0.0167 W"],"c":1,"e":"Power P = VI = (120 V)(2 A) = 240 W."},
  {"i":"phys-g12-curr-103","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"A 10 Ω resistor carries a current of 3 A. How much power does it dissipate?","o":["30 W","90 W","3.33 W","13 W"],"c":1,"e":"Power dissipated P = I²R = (3)²(10) = 9 × 10 = 90 W."},
  {"i":"phys-g12-mag-101","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A wire of length 0.5 m carries 4 A perpendicular to a 0.2 T magnetic field. What is the force on the wire? (F = BIL)","o":["0.4 N","4 N","0.04 N","2.5 N"],"c":0,"e":"F = BIL = (0.2 T)(4 A)(0.5 m) = 0.4 N."},
  {"i":"phys-g12-mag-102","g":12,"u":"Electromagnetism","d":"medium","t":"conceptual","q":"According to Lenz's law, an induced current always flows in a direction that:","o":["Increases the change in flux that caused it","Opposes the change in flux that caused it","Is independent of the flux change","Always flows clockwise"],"c":1,"e":"Lenz's law states the induced current opposes the change in magnetic flux producing it — a consequence of conservation of energy."},
  {"i":"phys-g12-acdc-101","g":12,"u":"Electromagnetism","d":"medium","t":"conceptual","q":"The key structural difference between an AC generator and a DC generator is that the DC generator uses a:","o":["Pair of slip rings","Split-ring commutator","Stronger magnet","Larger coil only"],"c":1,"e":"A DC generator uses a split-ring commutator to reverse the output connections each half-cycle, producing one-directional (DC) output, whereas an AC generator uses slip rings."},
  {"i":"phys-g12-wave-101","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"medium","t":"calculation","q":"Light travels from air into glass with refractive index 1.5. If the angle of incidence is such that sin i = 0.6, what is sin r? (Snell's law)","o":["0.9","0.4","0.6","1.5"],"c":1,"e":"Snell's law: n₁ sin i = n₂ sin r → (1)(0.6) = (1.5) sin r → sin r = 0.6/1.5 = 0.4."},
  {"i":"phys-g12-wave-102","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"medium","t":"calculation","q":"An object is placed 30 cm from a converging lens of focal length 10 cm. Using 1/f = 1/v + 1/u, what is the image distance v?","o":["7.5 cm","15 cm","20 cm","40 cm"],"c":1,"e":"1/v = 1/f − 1/u = 1/10 − 1/30 = 3/30 − 1/30 = 2/30, so v = 30/2 = 15 cm."},
  {"i":"phys-g12-nuc-101","g":11,"u":"Nuclear Physics","d":"medium","t":"calculation","q":"A radioactive isotope has a half-life of 8 days. What fraction of the original sample remains after 24 days?","o":["1/2","1/3","1/8","1/4"],"c":2,"e":"24 days = 3 half-lives, so the remaining fraction is (1/2)³ = 1/8."},
  {"i":"phys-g12-nuc-102","g":11,"u":"Nuclear Physics","d":"medium","t":"conceptual","q":"When a nucleus emits an alpha particle, its mass number A and atomic number Z change by:","o":["A decreases by 4, Z decreases by 2","A unchanged, Z increases by 1","A decreases by 2, Z decreases by 4","A decreases by 4, Z increases by 2"],"c":0,"e":"An alpha particle is a helium nucleus (⁴₂He), so emitting it lowers the mass number by 4 and the atomic number by 2."},
  {"i":"phys-g12-elec-101","g":12,"u":"Electronics","d":"medium","t":"conceptual","q":"A NOT gate (inverter) with input 1 produces an output of:","o":["1","0","Both 0 and 1","Undefined"],"c":1,"e":"A NOT gate inverts its input, so an input of 1 yields an output of 0."},
  {"i":"phys-g12-elec-102","g":12,"u":"Electronics","d":"medium","t":"conceptual","q":"In a common circuit, a transistor is most commonly used as a:","o":["Source of EMF","Switch or amplifier","Energy storage device","Permanent magnet"],"c":1,"e":"A small base current controls a larger collector current, allowing a transistor to act as an electronic switch or amplifier."},
  {"i":"phys-g11-vec-201","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"Three forces act on a point: 5 N east, 5 N north, and 5√2 N to the southwest (i.e. at 225° from east). What is the magnitude of the resultant?","o":["0 N","5 N","5√2 N","10 N"],"c":0,"e":"East+north give a resultant of magnitude 5√2 N pointing northeast (45°). The third force is 5√2 N pointing southwest (225°), exactly opposite, so the total resultant is 0 N."},
  {"i":"phys-g11-vec-202","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"A boat heads straight across a river at 4 m/s while the current flows downstream at 3 m/s. The river is 80 m wide. How far downstream does the boat land?","o":["60 m","80 m","106.7 m","100 m"],"c":0,"e":"Crossing time = width / boat speed = 80/4 = 20 s. Downstream drift = current × time = 3 × 20 = 60 m."},
  {"i":"phys-g11-mech-201","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A projectile is launched at 20 m/s at 30° above the horizontal. What is its maximum height? (g = 10 m/s², sin 30° = 0.5)","o":["5 m","10 m","20 m","2.5 m"],"c":0,"e":"Vertical component u_y = 20 sin 30° = 10 m/s. Max height H = u_y²/(2g) = 100/(20) = 5 m."},
  {"i":"phys-g11-mech-202","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A projectile launched at 40 m/s at 30° above horizontal. What is its horizontal range? (g = 10 m/s², use R = u²sin2θ/g, sin 60° ≈ 0.866)","o":["80 m","138.6 m","160 m","69.3 m"],"c":1,"e":"R = u² sin(2θ)/g = (40²)(sin 60°)/10 = (1600)(0.866)/10 = 1385.6/10 = 138.6 m."},
  {"i":"phys-g11-mech-203","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A stone is thrown upward at 30 m/s. At what times is it at a height of 40 m? (g = 10 m/s²)","o":["Only at 2 s","At 2 s and 4 s","At 1 s and 5 s","At 3 s only"],"c":1,"e":"40 = 30t − 5t² → 5t² − 30t + 40 = 0 → t² − 6t + 8 = 0 → (t−2)(t−4)=0, so t = 2 s (going up) and t = 4 s (coming down)."},
  {"i":"phys-g11-dyn-201","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"Two blocks, 3 kg and 2 kg, are connected by a string over a frictionless pulley (Atwood machine). What is the acceleration of the system? (g = 10 m/s²)","o":["2 m/s²","10 m/s²","1 m/s²","5 m/s²"],"c":0,"e":"a = (m₁ − m₂)g/(m₁ + m₂) = (3 − 2)(10)/(3 + 2) = 10/5 = 2 m/s²."},
  {"i":"phys-g11-dyn-202","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 4 kg block slides down a frictionless incline of 30°. What is its acceleration? (g = 10 m/s², sin 30° = 0.5)","o":["10 m/s²","5 m/s²","8.66 m/s²","2.5 m/s²"],"c":1,"e":"On a frictionless incline a = g sin θ = 10 × sin 30° = 10 × 0.5 = 5 m/s² (mass cancels out)."},
  {"i":"phys-g11-dyn-203","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 1500 kg car moving at 20 m/s is brought to rest in 4 s. What average braking force was applied?","o":["7500 N","30000 N","6000 N","1875 N"],"c":0,"e":"a = (0 − 20)/4 = −5 m/s². F = ma = (1500)(−5) = −7500 N; the braking force magnitude is 7500 N."},
  {"i":"phys-g11-rot-201","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A uniform 4 m plank weighing 200 N rests on two supports, one at each end. A 600 N person stands 1 m from the left support. What force does the left support exert?","o":["400 N","550 N","650 N","500 N"],"c":1,"e":"Take torques about the right support: F_left(4) = 600(3) + 200(2) = 1800 + 400 = 2200, so F_left = 2200/4 = 550 N. (Check: F_right = 800 − 550 = 250 N.)"},
  {"i":"phys-g11-rot-202","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A solid disk of moment of inertia 0.5 kg·m² experiences a net torque of 2 N·m. What is its angular acceleration?","o":["1 rad/s²","4 rad/s²","0.25 rad/s²","2.5 rad/s²"],"c":1,"e":"Rotational analogue of Newton's second law: α = τ/I = 2 N·m ÷ 0.5 kg·m² = 4 rad/s²."},
  {"i":"phys-g11-grav-201","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"Earth's escape velocity is 11.2 km/s. A planet has the same density but twice Earth's radius. What is its escape velocity? (v_esc ∝ R√ρ for constant density)","o":["5.6 km/s","11.2 km/s","22.4 km/s","44.8 km/s"],"c":2,"e":"For constant density, M ∝ R³, so v_esc = √(2GM/R) ∝ √(R³/R) = R. Doubling R doubles v_esc to 22.4 km/s."},
  {"i":"phys-g11-grav-202","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A satellite orbits Earth at radius r. If it moves to an orbit of radius 4r, by what factor does its orbital period change? (Kepler's third law: T² ∝ r³)","o":["4","8","16","64"],"c":1,"e":"T² ∝ r³, so T ∝ r^(3/2). Increasing r by 4 gives T multiplied by 4^(3/2) = (√4)³ = 2³ = 8."},
  {"i":"phys-g11-elas-201","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A wire of length 2 m and cross-sectional area 1×10⁻⁶ m² stretches by 1 mm under a 100 N load. What is the Young's modulus? (Y = FL/(AΔL))","o":["2×10¹¹ Pa","2×10⁸ Pa","5×10⁻¹² Pa","1×10¹¹ Pa"],"c":0,"e":"Y = FL/(AΔL) = (100 × 2)/(1×10⁻⁶ × 1×10⁻³) = 200/(1×10⁻⁹) = 2×10¹¹ Pa."},
  {"i":"phys-g11-elas-202","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A 100 N sign hangs from the midpoint of a horizontal wire fixed at both ends. Each half of the wire makes a 30° angle below the horizontal. What is the tension in each half? (sin 30° = 0.5)","o":["50 N","100 N","200 N","57.7 N"],"c":1,"e":"Vertical equilibrium: 2T sin 30° = 100 → 2T(0.5) = 100 → T = 100 N in each half of the wire."},
  {"i":"phys-g11-heat-201","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"How much heat is needed to melt 0.2 kg of ice at 0 °C into water at 0 °C? (latent heat of fusion L_f = 3.34×10⁵ J/kg)","o":["6.68×10⁴ J","1.67×10⁶ J","3.34×10⁴ J","6.68×10⁵ J"],"c":0,"e":"Q = mL_f = (0.2 kg)(3.34×10⁵ J/kg) = 6.68×10⁴ J (no temperature change occurs during melting)."},
  {"i":"phys-g11-heat-202","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"0.5 kg of water at 80 °C is mixed with 0.5 kg of water at 20 °C. Assuming no heat loss, what is the final temperature?","o":["40 °C","50 °C","60 °C","100 °C"],"c":1,"e":"With equal masses of the same substance, the final temperature is the average: (80 + 20)/2 = 50 °C (heat lost by hot water equals heat gained by cold water)."},
  {"i":"phys-g12-estat-201","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Two equal charges q are placed 2 m apart and repel with a force of 0.9 N. What is q? (k = 9×10⁹ N·m²/C²)","o":["20 μC","2 μC","0.2 μC","200 μC"],"c":0,"e":"F = kq²/r² → 0.9 = (9×10⁹)q²/(2²) → q² = 0.9×4/(9×10⁹) = 3.6/(9×10⁹) = 4×10⁻¹⁰ → q = 2×10⁻⁵ C = 20 μC."},
  {"i":"phys-g12-estat-202","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A point charge of 4 μC creates an electric field at a point 0.2 m away. What is the field magnitude? (E = kq/r², k = 9×10⁹ N·m²/C²)","o":["9×10⁵ N/C","1.8×10⁵ N/C","3.6×10⁴ N/C","9×10⁶ N/C"],"c":0,"e":"E = kq/r² = (9×10⁹)(4×10⁻⁶)/(0.2²) = (3.6×10⁴)/0.04 = 9×10⁵ N/C."},
  {"i":"phys-g12-cap-201","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Two capacitors, 6 μF and 3 μF, are connected in series. What is the equivalent capacitance?","o":["9 μF","2 μF","4.5 μF","0.5 μF"],"c":1,"e":"In series 1/C = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2, so C_eq = 2 μF."},
  {"i":"phys-g12-cap-202","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A 10 μF capacitor is charged to 200 V. How much energy is stored? (E = ½CV²)","o":["0.2 J","2 J","0.1 J","20 J"],"c":0,"e":"E = ½CV² = ½(10×10⁻⁶)(200²) = ½(10×10⁻⁶)(40000) = ½(0.4) = 0.2 J."},
  {"i":"phys-g12-curr-201","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A 6 Ω resistor is in series with a parallel combination of two 4 Ω resistors. What is the total resistance of the network?","o":["14 Ω","8 Ω","2 Ω","10 Ω"],"c":1,"e":"The two 4 Ω in parallel give 2 Ω; in series with 6 Ω gives 6 + 2 = 8 Ω."},
  {"i":"phys-g12-curr-202","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A 12 V battery is connected to a 2 Ω resistor in series with a 4 Ω resistor. What is the voltage across the 4 Ω resistor?","o":["4 V","8 V","12 V","6 V"],"c":1,"e":"Total R = 6 Ω, so I = 12/6 = 2 A. Voltage across the 4 Ω resistor = IR = (2)(4) = 8 V."},
  {"i":"phys-g12-curr-203","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A battery of EMF 10 V and internal resistance 0.5 Ω is connected to a 4.5 Ω external resistor. What is the terminal voltage?","o":["10 V","9 V","1 V","8 V"],"c":1,"e":"I = EMF/(R + r) = 10/(4.5 + 0.5) = 10/5 = 2 A. Terminal voltage = IR = (2)(4.5) = 9 V."},
  {"i":"phys-g12-mag-201","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A coil of 200 turns experiences a uniform change of magnetic flux of 0.01 Wb in 0.5 s. What is the magnitude of the induced EMF? (Faraday's law)","o":["4 V","0.4 V","40 V","2 V"],"c":0,"e":"EMF = N(ΔΦ/Δt) = 200 × (0.01/0.5) = 200 × 0.02 = 4 V."},
  {"i":"phys-g12-mag-202","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A proton (charge 1.6×10⁻¹⁹ C) moves at 2×10⁶ m/s perpendicular to a 0.5 T field. What is the magnetic force on it? (F = qvB)","o":["1.6×10⁻¹³ N","1.6×10⁻¹⁹ N","3.2×10⁻¹³ N","8×10⁻¹⁴ N"],"c":0,"e":"F = qvB = (1.6×10⁻¹⁹)(2×10⁶)(0.5) = (1.6×10⁻¹⁹)(1×10⁶) = 1.6×10⁻¹³ N."},
  {"i":"phys-g12-acdc-201","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A generator coil of 100 turns and area 0.02 m² rotates at angular speed 50 rad/s in a 0.4 T field. What is the peak EMF? (EMF₀ = NBAω)","o":["40 V","4 V","400 V","0.4 V"],"c":0,"e":"Peak EMF = NBAω = (100)(0.4)(0.02)(50) = (100)(0.4)(1) = 40 V."},
  {"i":"phys-g12-wave-201","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"hard","t":"calculation","q":"A glass has refractive index 1.5. What is its critical angle for total internal reflection? (sin θc = 1/n, arcsin(0.667) ≈ 41.8°)","o":["30°","41.8°","48.2°","60°"],"c":1,"e":"sin θc = 1/n = 1/1.5 = 0.667, so θc = arcsin(0.667) ≈ 41.8°."},
  {"i":"phys-g12-wave-202","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"hard","t":"calculation","q":"An object 4 cm tall is placed 30 cm from a converging lens of focal length 10 cm. What is the height of the image? (image distance v = 15 cm)","o":["8 cm","2 cm","4 cm","1 cm"],"c":1,"e":"Magnification m = v/u = 15/30 = 0.5, so image height = 0.5 × 4 cm = 2 cm (inverted, real)."},
  {"i":"phys-g12-nuc-201","g":11,"u":"Nuclear Physics","d":"hard","t":"calculation","q":"A sample initially has 800 g of a radioactive isotope with half-life 5 years. How much remains after 15 years?","o":["100 g","200 g","50 g","400 g"],"c":0,"e":"15 years = 3 half-lives, so remaining = 800 × (1/2)³ = 800 × 1/8 = 100 g."},
  {"i":"phys-g12-nuc-202","g":11,"u":"Nuclear Physics","d":"hard","t":"calculation","q":"Calculate the energy equivalent of a mass defect of 2×10⁻²⁸ kg. (c = 3×10⁸ m/s, E = mc²)","o":["1.8×10⁻¹¹ J","6×10⁻²⁰ J","1.8×10⁻¹⁹ J","9×10⁻¹² J"],"c":0,"e":"E = mc² = (2×10⁻²⁸)(3×10⁸)² = (2×10⁻²⁸)(9×10¹⁶) = 1.8×10⁻¹¹ J."},
  {"i":"phys-g12-elec-201","g":12,"u":"Electronics","d":"hard","t":"conceptual","q":"A NAND gate has both inputs tied together to a single signal A. The combined gate behaves as which single gate?","o":["AND gate","OR gate","NOT gate","XOR gate"],"c":2,"e":"NAND(A, A) = NOT(A AND A) = NOT(A), so tying both NAND inputs together produces an inverter (NOT gate)."},
  {"i":"phys-g12-elec-202","g":12,"u":"Electronics","d":"hard","t":"conceptual","q":"A full-wave rectifier compared with a half-wave rectifier of the same AC input produces an output with:","o":["Lower average DC and double ripple period","Higher average DC and lower ripple","No DC component","Identical output"],"c":1,"e":"A full-wave rectifier inverts the negative half-cycles instead of discarding them, giving a higher average DC value and smaller, higher-frequency ripple than a half-wave rectifier."},
  {"i":"phys-g11-vec-301","g":11,"u":"Vectors","d":"impossible","t":"calculation","q":"Two vectors of equal magnitude A have a resultant of magnitude A. What is the angle between them?","o":["60°","90°","120°","150°"],"c":2,"e":"R² = A² + A² + 2A²cos θ = A² → 2 + 2cos θ = 1 → cos θ = −1/2 → θ = 120°."},
  {"i":"phys-g11-vec-302","g":11,"u":"Vectors","d":"impossible","t":"calculation","q":"A river flows at 3 m/s. A swimmer who swims at 5 m/s relative to the water wants to cross straight to the opposite bank. At what angle (from the straight-across direction, i.e. upstream) must she aim, and what is her crossing speed?","o":["37° upstream, 4 m/s","53° upstream, 4 m/s","37° upstream, 3 m/s","30° upstream, 4.33 m/s"],"c":0,"e":"To cancel the current she aims upstream so that 5 sin θ = 3 → sin θ = 0.6 → θ = 37°. Her across-bank speed = 5 cos 37° = 5(0.8) = 4 m/s."},
  {"i":"phys-g11-mech-301","g":11,"u":"Motion in One and Two Dimensions","d":"impossible","t":"calculation","q":"A ball is projected at 25 m/s at 53° above horizontal from ground level. At what horizontal distance does it reach a height of 15 m on the way UP? (g = 10 m/s², sin 53° = 0.8, cos 53° = 0.6)","o":["9 m","12 m","15 m","6 m"],"c":2,"e":"u_y = 25(0.8) = 20 m/s; set 15 = 20t − 5t² → t² − 4t + 3 = 0 → t = 1 s (going up) or 3 s. At t = 1 s the horizontal distance x = u_x t = (25×0.6)(1) = 15 m."},
  {"i":"phys-g11-mech-302","g":11,"u":"Motion in One and Two Dimensions","d":"impossible","t":"calculation","q":"Two balls are thrown vertically from the ground, the second 1 s after the first, each at 20 m/s. At what height above the ground do they meet? (g = 10 m/s²)","o":["15 m","18.75 m","20 m","11.25 m"],"c":1,"e":"Ball 1: y₁ = 20t − 5t². Ball 2 (launched 1 s later): y₂ = 20(t−1) − 5(t−1)². Set equal: 20t − 5t² = 20(t−1) − 5(t−1)² → 0 = −20 + 5(2t − 1) → 10t = 25 → t = 2.5 s. y₁ = 20(2.5) − 5(2.5²) = 50 − 31.25 = 18.75 m."},
  {"i":"phys-g11-dyn-301","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A 2 kg block on a 30° incline is connected over a pulley to a hanging 3 kg block. The incline is frictionless. What is the acceleration of the system? (g = 10 m/s², sin 30° = 0.5)","o":["4 m/s²","2 m/s²","5 m/s²","6 m/s²"],"c":0,"e":"Driving force = hanging weight − component of incline weight = 3(10) − 2(10)(0.5) = 30 − 10 = 20 N. a = 20/(2+3) = 20/5 = 4 m/s²."},
  {"i":"phys-g11-dyn-302","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A 1 kg ball moving at 6 m/s collides head-on and elastically with a stationary 2 kg ball. What is the velocity of the 1 kg ball after the collision?","o":["+2 m/s","−2 m/s","0 m/s","+4 m/s"],"c":1,"e":"Elastic collision: v₁' = ((m₁−m₂)/(m₁+m₂))u₁ = ((1−2)/3)(6) = (−1/3)(6) = −2 m/s, so the lighter ball bounces back at 2 m/s."},
  {"i":"phys-g11-rot-301","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"A solid sphere (I = (2/5)mr²) rolls without slipping down an incline of angle 30°. What is its linear acceleration? (g = 10 m/s², sin 30° = 0.5)","o":["5 m/s²","3.57 m/s²","2.5 m/s²","10 m/s²"],"c":1,"e":"For a rolling body a = g sin θ /(1 + I/mr²) = 10(0.5)/(1 + 2/5) = 5/(7/5) = 5 × 5/7 = 25/7 ≈ 3.57 m/s²."},
  {"i":"phys-g11-rot-302","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"A figure skater spinning at 2 rev/s pulls in her arms, reducing her moment of inertia to one third of its original value. What is her new angular speed? (conservation of angular momentum)","o":["2 rev/s","6 rev/s","0.67 rev/s","3 rev/s"],"c":1,"e":"Angular momentum is conserved: I₁ω₁ = I₂ω₂. With I₂ = I₁/3, ω₂ = ω₁(I₁/I₂) = 2 × 3 = 6 rev/s."},
  {"i":"phys-g11-grav-301","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"A satellite is in a circular orbit just above a planet's surface where surface gravity is g and radius is R. Its orbital speed equals √(gR). For Earth (g = 9.8 m/s², R = 6.4×10⁶ m), this orbital speed is approximately:","o":["7.9 km/s","11.2 km/s","3.1 km/s","5.6 km/s"],"c":0,"e":"v = √(gR) = √(9.8 × 6.4×10⁶) = √(6.27×10⁷) ≈ 7920 m/s ≈ 7.9 km/s (the well-known low-Earth-orbit speed)."},
  {"i":"phys-g11-grav-302","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"Escape velocity is related to circular orbital velocity at the same radius by which factor? (v_esc / v_orbit)","o":["2","√2","1/2","4"],"c":1,"e":"v_orbit = √(GM/R) and v_esc = √(2GM/R), so v_esc/v_orbit = √2 (about 1.414)."},
  {"i":"phys-g11-elas-301","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"impossible","t":"calculation","q":"A uniform ladder of weight 200 N leans against a frictionless wall at 60° to the ground. The floor provides friction. What minimum coefficient of friction at the floor prevents slipping? (tan 60° ≈ 1.73)","o":["0.29","0.58","0.87","1.73"],"c":0,"e":"Taking torques and force balance for a ladder at angle θ to the floor, μ_min = 1/(2 tan θ) = 1/(2 × 1.73) = 1/3.46 ≈ 0.29."},
  {"i":"phys-g11-elas-302","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"impossible","t":"calculation","q":"Two wires of the same material and length but radii r and 2r support the same load in turn. The ratio of their extensions (thin : thick) is:","o":["1 : 1","2 : 1","4 : 1","1 : 4"],"c":2,"e":"Extension ΔL = FL/(AY) ∝ 1/A ∝ 1/r². For radii r and 2r, areas are in ratio 1:4, so extensions are in ratio 4:1 (the thin wire stretches four times as much)."},
  {"i":"phys-g11-heat-301","g":11,"u":"Heat Conduction & Calorimetry","d":"impossible","t":"calculation","q":"A 0.1 kg block of ice at 0 °C is dropped into 0.5 kg of water at 40 °C in an insulated container. (L_f = 3.34×10⁵ J/kg, c_water = 4200 J/kg·°C). What is the final temperature, to the nearest degree?","o":["0 °C with ice remaining","About 20 °C","About 28 °C","About 34 °C"],"c":1,"e":"Heat to melt the ice = mL_f = 0.1×3.34×10⁵ = 3.34×10⁴ J. Energy balance: 0.5(4200)(40−T) = 3.34×10⁴ + 0.1(4200)T → 84000 − 2100T = 33400 + 420T → 50600 = 2520T → T ≈ 20 °C."},
  {"i":"phys-g11-heat-302","g":11,"u":"Heat Conduction & Calorimetry","d":"impossible","t":"calculation","q":"An ideal monatomic gas doubles its absolute temperature at constant volume. By what factor does its pressure change? (Gay-Lussac's law: P/T = constant)","o":["Halves","Doubles","Quadruples","Unchanged"],"c":1,"e":"At constant volume P ∝ T (Gay-Lussac's law). Doubling the absolute temperature doubles the pressure."},
  {"i":"phys-g12-estat-301","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"Three equal charges +q sit at the corners of an equilateral triangle of side a. What is the magnitude of the net force on any one charge? (let F₀ = kq²/a²)","o":["F₀","2F₀","√3 F₀","3F₀"],"c":2,"e":"Each of the two other charges exerts F₀ at 60° to each other. Net = √(F₀² + F₀² + 2F₀²cos60°) = √(2F₀² + F₀²) = √3 F₀."},
  {"i":"phys-g12-estat-302","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"Charges +4q and +q are fixed at a distance d apart. At what point on the line between them is the electric field zero? (distance from the +q charge)","o":["d/2","d/3","d/4","2d/3"],"c":1,"e":"Set fields equal: k(4q)/x² = k(q)/(d−x)² where x is from +4q. → 4(d−x)² = x² → 2(d−x) = x → x = 2d/3 from +4q, which is d/3 from the +q charge."},
  {"i":"phys-g12-cap-301","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"A parallel-plate capacitor is charged by a battery, then disconnected, then a dielectric of constant k = 2 is inserted. What happens to the voltage across it?","o":["Doubles","Halves","Unchanged","Becomes zero"],"c":1,"e":"Disconnected means charge Q is fixed. Inserting the dielectric makes C' = kC = 2C, and V = Q/C', so V halves (V' = Q/2C = V/2)."},
  {"i":"phys-g12-cap-302","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"A 3 μF and a 6 μF capacitor are connected in series across a 9 V battery. What is the charge on each capacitor?","o":["18 μC","27 μC","9 μC","54 μC"],"c":0,"e":"Series equivalent C = (3×6)/(3+6) = 18/9 = 2 μF. Charge Q = CV = (2 μF)(9 V) = 18 μC, and series capacitors carry equal charge, so each holds 18 μC."},
  {"i":"phys-g12-curr-301","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"In a balanced Wheatstone bridge, three arms are 2 Ω, 4 Ω, and 6 Ω. If the 2 Ω and 4 Ω form one pair (P and Q) and 6 Ω is R, what is the fourth resistance S for balance? (P/Q = R/S)","o":["3 Ω","12 Ω","8 Ω","6 Ω"],"c":1,"e":"Balance condition P/Q = R/S → 2/4 = 6/S → S = 6 × 4/2 = 12 Ω."},
  {"i":"phys-g12-curr-302","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"Twelve identical 1 Ω resistors form the edges of a cube. What is the equivalent resistance between two opposite (diagonal) corners of the cube?","o":["1 Ω","5/6 Ω","3/4 Ω","7/12 Ω"],"c":1,"e":"By symmetry the current splits 3-3-3 then 6 then 3-3-3, giving R = (1/3 + 1/6 + 1/3)R = (5/6)(1) = 5/6 Ω between opposite corners."},
  {"i":"phys-g12-mag-301","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"A conducting rod of length 0.5 m moves at 4 m/s perpendicular to a 0.3 T magnetic field. What EMF is induced across its ends? (EMF = BLv)","o":["0.6 V","6 V","0.06 V","1.2 V"],"c":0,"e":"Motional EMF = BLv = (0.3 T)(0.5 m)(4 m/s) = 0.6 V."},
  {"i":"phys-g12-mag-302","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"An ideal transformer steps 240 V down to 12 V. If the secondary delivers 5 A to a load, what is the current drawn from the primary? (P_in = P_out for ideal)","o":["0.25 A","5 A","100 A","1 A"],"c":0,"e":"For an ideal transformer V_p I_p = V_s I_s → I_p = (12 × 5)/240 = 60/240 = 0.25 A."},
  {"i":"phys-g12-acdc-301","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"An AC supply has a peak voltage of 311 V. What is its RMS voltage? (V_rms = V_peak/√2)","o":["440 V","220 V","311 V","155 V"],"c":1,"e":"V_rms = V_peak/√2 = 311/1.414 ≈ 220 V (the standard mains RMS value)."},
  {"i":"phys-g12-wave-301","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"impossible","t":"calculation","q":"In Young's double-slit experiment, slits 0.5 mm apart are 2 m from the screen, lit by 500 nm light. What is the fringe spacing? (Δy = λD/d)","o":["2 mm","0.5 mm","1 mm","4 mm"],"c":0,"e":"Δy = λD/d = (500×10⁻⁹ × 2)/(0.5×10⁻³) = (1×10⁻⁶)/(0.5×10⁻³) = 2×10⁻³ m = 2 mm."},
  {"i":"phys-g12-wave-302","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"impossible","t":"calculation","q":"An object is placed at the focal point (u = f) of a converging lens. Where is the image formed?","o":["At 2f","At the focal point on the other side","At infinity","At the lens"],"c":2,"e":"Using 1/v = 1/f − 1/u with u = f: 1/v = 1/f − 1/f = 0, so v = infinity — the emerging rays are parallel and the image is at infinity."},
  {"i":"phys-g12-nuc-301","g":11,"u":"Nuclear Physics","d":"impossible","t":"calculation","q":"A radioactive source has an activity that falls to 12.5% of its initial value after 30 hours. What is its half-life?","o":["5 hours","10 hours","15 hours","7.5 hours"],"c":1,"e":"12.5% = 1/8 = (1/2)³, so 3 half-lives occurred in 30 hours, giving a half-life of 30/3 = 10 hours."},
  {"i":"phys-g12-nuc-302","g":11,"u":"Nuclear Physics","d":"impossible","t":"conceptual","q":"In the decay ²³⁸₉₂U → ²³⁴₉₀Th + X, what is particle X?","o":["A beta particle","A gamma photon","An alpha particle","A neutron"],"c":2,"e":"Mass number drops by 4 (238→234) and atomic number drops by 2 (92→90), which matches emission of an alpha particle (⁴₂He)."},
  {"i":"phys-g12-elec-301","g":12,"u":"Electronics","d":"impossible","t":"conceptual","q":"Two NOR gates: the output of the first (inputs A and B) feeds both inputs of the second. What single logic function does the overall circuit perform?","o":["A AND B","A OR B","A NAND B","NOT A"],"c":1,"e":"First gate gives NOR(A,B) = NOT(A OR B). Feeding that into a NOR used as an inverter gives NOT(NOT(A OR B)) = A OR B."},
  {"i":"phys-g12-elec-302","g":12,"u":"Electronics","d":"impossible","t":"calculation","q":"A silicon diode (forward drop 0.7 V) is in series with a 230 Ω resistor across a 5 V DC supply. What is the current through the diode?","o":["21.7 mA","18.7 mA","25 mA","2.17 mA"],"c":1,"e":"Voltage across the resistor = 5 − 0.7 = 4.3 V. I = V/R = 4.3/230 ≈ 0.0187 A = 18.7 mA."},
  {"i":"phys-b2-0001","g":9,"u":"Physics & Human Society","d":"easy","t":"definition","q":"Physics is best defined as the branch of science that studies:","o":["Living organisms and their life processes","Matter, energy and their interactions","The composition and reactions of substances","The structure of the Earth's rocks"],"c":1,"e":"Physics studies matter, energy, and the interactions between them. Biology studies life and chemistry studies substances."},
  {"i":"phys-b2-0002","g":9,"u":"Physics & Human Society","d":"easy","t":"application","q":"Which everyday Ethiopian technology most directly applies the physics of electricity and magnetism?","o":["A wooden mortar (mukecha) for grinding","An electric generator at a hydropower dam","A clay water pot (insira) for cooling","A bamboo basket (sefed) for sorting grain"],"c":1,"e":"A generator converts mechanical energy to electrical energy using electromagnetic induction, a core application of electricity and magnetism."},
  {"i":"phys-b2-0003","g":9,"u":"Physical Quantities","d":"easy","t":"definition","q":"Which of the following is a base (fundamental) physical quantity in the SI system?","o":["Force","Speed","Mass","Density"],"c":2,"e":"Mass is a base SI quantity (kilogram). Force, speed and density are derived quantities."},
  {"i":"phys-b2-0004","g":9,"u":"Physical Quantities","d":"easy","t":"definition","q":"The SI unit of electric current is the:","o":["Volt","Ampere","Ohm","Watt"],"c":1,"e":"Electric current is a base SI quantity measured in amperes (A)."},
  {"i":"phys-b2-0005","g":9,"u":"Motion in a Straight Line","d":"easy","t":"calculation","q":"A car travels 150 m in 10 s at constant speed. Its speed is:","o":["15 m/s","1.5 m/s","150 m/s","25 m/s"],"c":0,"e":"Speed = distance ÷ time = 150 m ÷ 10 s = 15 m/s."},
  {"i":"phys-b2-0006","g":9,"u":"Motion in a Straight Line","d":"easy","t":"calculation","q":"A bus starting from rest reaches 20 m/s in 5 s. Its acceleration is:","o":["100 m/s²","4 m/s²","0.25 m/s²","15 m/s²"],"c":1,"e":"a = (v − u)/t = (20 − 0)/5 = 4 m/s²."},
  {"i":"phys-b2-0007","g":9,"u":"Motion in a Straight Line","d":"easy","t":"definition","q":"The quantity that describes the rate of change of velocity is:","o":["Speed","Displacement","Acceleration","Momentum"],"c":2,"e":"Acceleration is defined as the rate of change of velocity with time."},
  {"i":"phys-b2-0008","g":9,"u":"Motion in a Straight Line","d":"easy","t":"calculation","q":"A stone is dropped from rest and falls for 2 s. Using g = 9.8 m/s², its velocity just before hitting the ground is:","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"v = u + gt = 0 + 9.8 × 2 = 19.6 m/s."},
  {"i":"phys-b2-0009","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"calculation","q":"A net force of 12 N acts on a 4 kg object. Its acceleration is:","o":["48 m/s²","3 m/s²","0.33 m/s²","16 m/s²"],"c":1,"e":"From Newton's second law, a = F/m = 12 N ÷ 4 kg = 3 m/s²."},
  {"i":"phys-b2-0010","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"calculation","q":"The weight of a 10 kg sack of teff on Earth (g = 9.8 m/s²) is:","o":["10 N","98 N","9.8 N","980 N"],"c":1,"e":"Weight W = mg = 10 kg × 9.8 m/s² = 98 N."},
  {"i":"phys-b2-0011","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"calculation","q":"A worker pushes a box with 50 N of force, moving it 4 m in the direction of the force. The work done is:","o":["200 J","54 J","12.5 J","46 J"],"c":0,"e":"Work W = F × d = 50 N × 4 m = 200 J."},
  {"i":"phys-b2-0012","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"conceptual","q":"Newton's first law of motion states that an object will:","o":["Always accelerate when a force acts","Stay at rest or move uniformly unless a net force acts on it","Move faster as its mass increases","Stop immediately when pushed"],"c":1,"e":"Newton's first law (inertia): an object keeps its state of rest or uniform motion unless acted on by a net external force."},
  {"i":"phys-b2-0013","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"calculation","q":"A machine does 600 J of work in 3 s. Its power output is:","o":["1800 W","200 W","603 W","0.005 W"],"c":1,"e":"Power P = work/time = 600 J ÷ 3 s = 200 W."},
  {"i":"phys-b2-0014","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"calculation","q":"A 2 kg ball moves at 5 m/s. Its momentum is:","o":["2.5 kg·m/s","7 kg·m/s","10 kg·m/s","25 kg·m/s"],"c":2,"e":"Momentum p = mv = 2 kg × 5 m/s = 10 kg·m/s."},
  {"i":"phys-b2-0015","g":9,"u":"Simple Machines","d":"easy","t":"calculation","q":"A lever uses a 200 N effort to lift a 600 N load. Its mechanical advantage is:","o":["3","0.33","800","400"],"c":0,"e":"Mechanical advantage = load ÷ effort = 600 N ÷ 200 N = 3."},
  {"i":"phys-b2-0016","g":9,"u":"Simple Machines","d":"easy","t":"definition","q":"Which of the following is an example of a simple machine?","o":["A pulley","A battery","A thermometer","A loudspeaker"],"c":0,"e":"A pulley is a simple machine. The others are not classed as simple machines."},
  {"i":"phys-b2-0017","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"easy","t":"calculation","q":"A pendulum completes 20 full oscillations in 10 s. Its frequency is:","o":["0.5 Hz","2 Hz","200 Hz","10 Hz"],"c":1,"e":"Frequency = number of oscillations ÷ time = 20 ÷ 10 = 2 Hz."},
  {"i":"phys-b2-0018","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"easy","t":"conceptual","q":"Sound waves require a medium to travel because they are:","o":["Electromagnetic waves","Mechanical waves","Light waves","Radio waves"],"c":1,"e":"Sound is a mechanical wave; it needs a material medium (such as air) to propagate and cannot travel through a vacuum."},
  {"i":"phys-b2-0019","g":9,"u":"Temperature & Thermometer","d":"easy","t":"calculation","q":"Water boils at 100 °C at sea level. On the Kelvin scale this temperature is:","o":["100 K","173 K","373 K","273 K"],"c":2,"e":"T(K) = T(°C) + 273 = 100 + 273 = 373 K."},
  {"i":"phys-b2-0020","g":9,"u":"Temperature & Thermometer","d":"easy","t":"definition","q":"The instrument used to measure temperature is the:","o":["Barometer","Thermometer","Ammeter","Voltmeter"],"c":1,"e":"A thermometer measures temperature; a barometer measures pressure and ammeters/voltmeters measure electrical quantities."},
  {"i":"phys-b2-0021","g":9,"u":"Physics & Human Society","d":"medium","t":"conceptual","q":"A farmer in Ethiopia uses weather forecasting to decide when to plant teff. Which branch of physics most directly underpins the technology used to predict atmospheric conditions?","o":["Thermodynamics and fluid dynamics","Nuclear physics","Optics only","Quantum electronics only"],"c":0,"e":"Weather prediction relies on thermodynamics (heat transfer) and fluid dynamics (air movement) to model the atmosphere, so option A is correct."},
  {"i":"phys-b2-0022","g":9,"u":"Physics & Human Society","d":"medium","t":"definition","q":"In the scientific method, a tentative testable explanation proposed before experiments are carried out is called a:","o":["Law","Hypothesis","Conclusion","Constant"],"c":1,"e":"A hypothesis is a tentative, testable explanation proposed before experimentation; a law is a confirmed general statement and a conclusion comes after testing."},
  {"i":"phys-b2-0023","g":9,"u":"Physical Quantities","d":"medium","t":"calculation","q":"A rectangular Ethiopian flag measures 1.5 m by 0.9 m. What is its area expressed in standard SI units?","o":["1.35 m²","2.4 m²","13.5 m²","0.135 m²"],"c":0,"e":"Area = length × width = 1.5 m × 0.9 m = 1.35 m²."},
  {"i":"phys-b2-0024","g":9,"u":"Physical Quantities","d":"medium","t":"calculation","q":"A length is measured as 4.5 × 10³ mm. Expressed in metres, this equals:","o":["4.5 m","45 m","0.45 m","450 m"],"c":0,"e":"4.5 × 10³ mm = 4500 mm, and dividing by 1000 mm/m gives 4.5 m."},
  {"i":"phys-b2-0025","g":9,"u":"Physical Quantities","d":"medium","t":"definition","q":"The SI base unit of electric current is the:","o":["Volt","Ohm","Ampere","Coulomb"],"c":2,"e":"The ampere (A) is the SI base unit of electric current; the volt, ohm and coulomb are derived units."},
  {"i":"phys-b2-0026","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A bus travelling from Addis Ababa covers 240 km in 4 hours. What is its average speed?","o":["60 km/h","48 km/h","80 km/h","960 km/h"],"c":0,"e":"Average speed = distance ÷ time = 240 km ÷ 4 h = 60 km/h."},
  {"i":"phys-b2-0027","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A car accelerates uniformly from rest to 20 m/s in 5 s. What is its acceleration?","o":["100 m/s²","4 m/s²","0.25 m/s²","15 m/s²"],"c":1,"e":"a = (v − u)/t = (20 − 0)/5 = 4 m/s²."},
  {"i":"phys-b2-0028","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A stone is dropped from rest from a cliff and falls for 3 s. Using g = 9.8 m/s², what is its speed just before impact?","o":["29.4 m/s","9.8 m/s","3.27 m/s","88.2 m/s"],"c":0,"e":"v = u + gt = 0 + 9.8 × 3 = 29.4 m/s."},
  {"i":"phys-b2-0029","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A runner moves 100 m east then 60 m west along a straight track. What is the magnitude of the displacement?","o":["160 m east","40 m east","40 m west","160 m west"],"c":1,"e":"Displacement = 100 m east − 60 m west = 40 m east (taking east positive)."},
  {"i":"phys-b2-0030","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A car moving at 15 m/s decelerates uniformly at 3 m/s². How far does it travel before stopping?","o":["37.5 m","5 m","45 m","22.5 m"],"c":0,"e":"Using v² = u² − 2as with v=0: s = u²/(2a) = 15²/(2×3) = 225/6 = 37.5 m."},
  {"i":"phys-b2-0031","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A net force of 12 N acts on a 4 kg crate on a frictionless floor. What is the acceleration?","o":["48 m/s²","3 m/s²","0.33 m/s²","16 m/s²"],"c":1,"e":"By Newton's second law, a = F/m = 12 N ÷ 4 kg = 3 m/s²."},
  {"i":"phys-b2-0032","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A worker pushes a box with a horizontal force of 50 N over a distance of 6 m in the direction of the force. How much work is done?","o":["300 J","56 J","8.3 J","44 J"],"c":0,"e":"Work = force × distance = 50 N × 6 m = 300 J."},
  {"i":"phys-b2-0033","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A 2 kg object is lifted vertically 5 m (g = 9.8 m/s²). What is the gain in gravitational potential energy?","o":["10 J","98 J","49 J","19.6 J"],"c":1,"e":"PE = mgh = 2 × 9.8 × 5 = 98 J."},
  {"i":"phys-b2-0034","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A machine does 600 J of work in 3 s. What is its power output?","o":["1800 W","200 W","0.005 W","300 W"],"c":1,"e":"Power = work ÷ time = 600 J ÷ 3 s = 200 W."},
  {"i":"phys-b2-0035","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A 3 kg ball moves at 4 m/s. What is its kinetic energy?","o":["12 J","24 J","48 J","6 J"],"c":1,"e":"KE = ½mv² = ½ × 3 × 4² = ½ × 3 × 16 = 24 J."},
  {"i":"phys-b2-0036","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"What is the weight of a 10 kg sack of grain on Earth (g = 9.8 m/s²)?","o":["10 N","98 N","9.8 N","980 N"],"c":1,"e":"Weight = mg = 10 kg × 9.8 m/s² = 98 N."},
  {"i":"phys-b2-0037","g":9,"u":"Simple Machines","d":"medium","t":"calculation","q":"A lever has an effort arm of 2 m and a load arm of 0.5 m. What is its ideal mechanical advantage?","o":["1.0","4.0","2.5","0.25"],"c":1,"e":"For a lever, MA = effort arm ÷ load arm = 2 ÷ 0.5 = 4."},
  {"i":"phys-b2-0038","g":9,"u":"Simple Machines","d":"medium","t":"calculation","q":"A machine receives 500 J of work input and delivers 400 J of useful output. What is its efficiency?","o":["80%","125%","100%","20%"],"c":0,"e":"Efficiency = (useful output ÷ input) × 100 = (400/500) × 100 = 80%."},
  {"i":"phys-b2-0039","g":9,"u":"Simple Machines","d":"medium","t":"calculation","q":"An inclined plane is 6 m long and rises to a height of 1.5 m. What is its ideal mechanical advantage?","o":["4.0","0.25","9.0","7.5"],"c":0,"e":"For an inclined plane, MA = length ÷ height = 6 ÷ 1.5 = 4."},
  {"i":"phys-b2-0040","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"medium","t":"calculation","q":"A pendulum completes 30 oscillations in 60 s. What is its frequency?","o":["0.5 Hz","2 Hz","30 Hz","1800 Hz"],"c":0,"e":"Frequency = number of oscillations ÷ time = 30 ÷ 60 = 0.5 Hz."},
  {"i":"phys-b2-0041","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"medium","t":"calculation","q":"A sound wave has a frequency of 170 Hz and travels at 340 m/s in air. What is its wavelength?","o":["2 m","0.5 m","510 m","57800 m"],"c":0,"e":"Using v = fλ, λ = v/f = 340 ÷ 170 = 2 m."},
  {"i":"phys-b2-0042","g":9,"u":"Temperature & Thermometer","d":"medium","t":"calculation","q":"A temperature of 30 °C is converted to the Kelvin scale. What is the value?","o":["303 K","243 K","30 K","573 K"],"c":0,"e":"K = °C + 273 = 30 + 273 = 303 K."},
  {"i":"phys-b2-0043","g":9,"u":"Motion in a Straight Line","d":"hard","t":"calculation","q":"A bus leaves Adama at rest and accelerates uniformly at 2 m/s² for 8 s, then travels at constant velocity for 12 s. What total distance does it cover?","o":["64 m","256 m","192 m","320 m"],"c":1,"e":"Phase 1: v = at = 2×8 = 16 m/s; s₁ = ½at² = ½×2×64 = 64 m. Phase 2: s₂ = vt = 16×12 = 192 m. Total = 64 + 192 = 256 m."},
  {"i":"phys-b2-0044","g":9,"u":"Motion in a Straight Line","d":"hard","t":"calculation","q":"A stone is thrown vertically upward at 19.6 m/s (g = 9.8 m/s²). How long after launch is it moving downward at a speed of 9.8 m/s?","o":["1.0 s","2.0 s","3.0 s","4.0 s"],"c":2,"e":"Taking up as positive, v = u − gt; moving down at 9.8 means v = −9.8: −9.8 = 19.6 − 9.8t → 9.8t = 29.4 → t = 3.0 s."},
  {"i":"phys-b2-0045","g":9,"u":"Motion in a Straight Line","d":"hard","t":"calculation","q":"A car decelerates uniformly from 30 m/s to 10 m/s over a distance of 80 m. What is the magnitude of its acceleration?","o":["2.5 m/s²","5.0 m/s²","10 m/s²","4.0 m/s²"],"c":1,"e":"Using v² = u² + 2as: 10² = 30² + 2a(80) → 100 = 900 + 160a → a = −800/160 = −5.0 m/s². Magnitude = 5.0 m/s²."},
  {"i":"phys-b2-0046","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"calculation","q":"A 5 kg block is pulled along a horizontal floor by a 30 N force directed at 60° above the horizontal. If friction is 8 N, what is the block's acceleration? (cos 60° = 0.5)","o":["1.4 m/s²","3.0 m/s²","4.4 m/s²","2.4 m/s²"],"c":0,"e":"Horizontal component of pull = 30 cos60° = 15 N. Net force = 15 − 8 = 7 N. a = F/m = 7/5 = 1.4 m/s²."},
  {"i":"phys-b2-0047","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"calculation","q":"A 2 kg ball moving at 4 m/s collides head-on with a stationary 6 kg ball and they stick together. What is their common velocity after collision?","o":["0.5 m/s","1.0 m/s","1.33 m/s","2.0 m/s"],"c":1,"e":"Conservation of momentum: (2×4) + 0 = (2+6)v → 8 = 8v → v = 1.0 m/s."},
  {"i":"phys-b2-0048","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"calculation","q":"A pump raises 600 kg of water to a height of 15 m in 30 s. What is its useful power output? (g = 9.8 m/s²)","o":["2940 W","294 W","8820 W","1470 W"],"c":0,"e":"Work = mgh = 600×9.8×15 = 88200 J. Power = W/t = 88200/30 = 2940 W."},
  {"i":"phys-b2-0049","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"calculation","q":"A 0.5 kg ball is dropped from a height of 5 m and rebounds to 3.2 m. How much mechanical energy is lost in the bounce? (g = 9.8 m/s²)","o":["8.82 J","24.5 J","15.68 J","4.41 J"],"c":0,"e":"Energy lost = mgΔh = mg(5 − 3.2) = 0.5×9.8×1.8 = 8.82 J."},
  {"i":"phys-b2-0050","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"application","q":"A 1200 kg car rounds a flat circular curve of radius 50 m at 15 m/s. What minimum frictional force is needed to keep it on the curve?","o":["3600 N","5400 N","2700 N","9000 N"],"c":1,"e":"Centripetal force = mv²/r = 1200×15²/50 = 1200×225/50 = 5400 N, which friction must supply."},
  {"i":"phys-b2-0051","g":9,"u":"Simple Machines","d":"hard","t":"calculation","q":"On a lever the load is 0.4 m from the fulcrum and the effort is applied 1.6 m from the fulcrum. For an ideal lever lifting a 200 N load, what effort is needed and what is the mechanical advantage?","o":["50 N, MA = 4","800 N, MA = 4","50 N, MA = 0.25","100 N, MA = 2"],"c":0,"e":"Principle of moments: E×1.6 = 200×0.4 → E = 80/1.6 = 50 N. MA = load/effort = 200/50 = 4."},
  {"i":"phys-b2-0052","g":9,"u":"Simple Machines","d":"hard","t":"calculation","q":"An inclined plane 6 m long raises a load to a height of 1.5 m. If the plane is 75% efficient, what effort is needed to raise a 400 N load along it?","o":["100 N","133 N","75 N","125 N"],"c":1,"e":"Ideal effort = load×height/length = 400×1.5/6 = 100 N. With 75% efficiency, actual effort = 100/0.75 ≈ 133 N."},
  {"i":"phys-b2-0053","g":9,"u":"Simple Machines","d":"hard","t":"application","q":"A pulley system has a velocity ratio of 5 and an efficiency of 80%. What load can it lift with an effort of 150 N?","o":["600 N","750 N","375 N","937 N"],"c":0,"e":"Efficiency = MA/VR → MA = 0.80×5 = 4. Load = MA×effort = 4×150 = 600 N."},
  {"i":"phys-b2-0054","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"hard","t":"calculation","q":"A man claps near a cliff and hears the echo 1.5 s later. If sound travels at 340 m/s, how far away is the cliff?","o":["510 m","255 m","340 m","225 m"],"c":1,"e":"Sound travels to the cliff and back: total path = 340×1.5 = 510 m. Cliff distance = 510/2 = 255 m."},
  {"i":"phys-b2-0055","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"hard","t":"calculation","q":"A simple pendulum makes 30 complete oscillations in 60 s. What are its frequency and period?","o":["f = 2 Hz, T = 0.5 s","f = 0.5 Hz, T = 2 s","f = 2 Hz, T = 2 s","f = 0.5 Hz, T = 0.5 s"],"c":1,"e":"f = oscillations/time = 30/60 = 0.5 Hz. T = 1/f = 1/0.5 = 2 s."},
  {"i":"phys-b2-0056","g":9,"u":"Physical Quantities","d":"hard","t":"calculation","q":"A rectangular metal sheet measures 2.0 m by 0.50 m with a thickness of 1.0 cm and a mass of 8.0 kg. What is the density of the metal?","o":["800 kg/m³","8000 kg/m³","1600 kg/m³","80 kg/m³"],"c":0,"e":"Volume = 2.0×0.50×0.010 = 0.010 m³. Density = mass/volume = 8.0/0.010 = 800 kg/m³."},
  {"i":"phys-b2-0057","g":9,"u":"Temperature & Thermometer","d":"hard","t":"calculation","q":"A temperature reads 40 °C. What is this on the Kelvin scale and the Fahrenheit scale?","o":["313 K and 104 °F","313 K and 72 °F","233 K and 104 °F","313 K and 40 °F"],"c":0,"e":"K = °C + 273 = 40 + 273 = 313 K. °F = (9/5)×40 + 32 = 72 + 32 = 104 °F."},
  {"i":"phys-b2-0058","g":9,"u":"Physics & Human Society","d":"hard","t":"conceptual","q":"A student measures the same time of fall five times and averages the results. The MAIN purpose of repeating and averaging the measurement is to:","o":["Reduce the effect of random errors","Eliminate systematic (zero) errors","Change the true value being measured","Increase the unit of the quantity"],"c":0,"e":"Averaging repeated readings reduces random errors that scatter above and below the true value; systematic (zero) errors are not removed by averaging."},
  {"i":"phys-b2-0059","g":9,"u":"Motion in a Straight Line","d":"impossible","t":"calculation","q":"A stone is thrown vertically upward from the edge of a cliff with speed 14 m/s. It lands at the base of the cliff 4.0 s later. Taking g = 9.8 m/s² and upward as positive, what is the height of the cliff (vertical distance from launch point down to the base)?","o":["22.4 m","78.4 m","21.6 m","56.0 m"],"c":0,"e":"Net displacement s = ut + ½at² = (14)(4.0) + ½(−9.8)(16) = 56 − 78.4 = −22.4 m; the negative sign means it ends 22.4 m below the launch point, so the cliff height is 22.4 m."},
  {"i":"phys-b2-0060","g":9,"u":"Force, Work, Energy & Power","d":"impossible","t":"calculation","q":"A 2.0 kg block slides from rest down a rough incline of length 5.0 m at 30° to the horizontal. Friction does −8.0 J of work over the slide. Using g = 9.8 m/s², what is the block's speed at the bottom?","o":["6.4 m/s","7.0 m/s","4.9 m/s","5.4 m/s"],"c":0,"e":"Drop height h = 5.0·sin30° = 2.5 m, so gravity work = mgh = 2.0·9.8·2.5 = 49 J. Net work = 49 − 8 = 41 J = ½mv² → v = √(2·41/2.0) = √41 ≈ 6.4 m/s."},
  {"i":"phys-b2-0061","g":9,"u":"Force, Work, Energy & Power","d":"impossible","t":"calculation","q":"Two carts on a frictionless track collide and stick together. Cart A (3.0 kg) moves right at 4.0 m/s; cart B (1.0 kg) moves left at 2.0 m/s. Immediately after the perfectly inelastic collision, what fraction of the initial kinetic energy is lost?","o":["About 52%","About 25%","About 0% (energy conserved)","About 75%"],"c":0,"e":"Momentum: 3·4 + 1·(−2) = 10 kg·m/s, total mass 4 kg → v = 2.5 m/s. KEi = ½·3·16 + ½·1·4 = 26 J; KEf = ½·4·2.5² = 12.5 J; fraction lost = (26−12.5)/26 ≈ 0.52 = 52%."},
  {"i":"phys-b2-0062","g":9,"u":"Simple Machines","d":"impossible","t":"calculation","q":"A wheel and axle raises a bucket from a well. The wheel (where the rope is pulled) has radius 40 cm and the axle has radius 8.0 cm. If the machine is 80% efficient, what effort force is needed to lift a 200 N bucket of water?","o":["50 N","40 N","32 N","64 N"],"c":0,"e":"Ideal MA = R/r = 40/8 = 5. Actual MA = efficiency × ideal MA = 0.80 × 5 = 4. Effort = Load / actual MA = 200/4 = 50 N."},
  {"i":"phys-b2-0063","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"impossible","t":"calculation","q":"A simple pendulum has period 2.0 s in Addis Ababa. It is moved to a place where g is 2.0% smaller and its length is also increased by 2.0%. Approximately what is the new period? (Use T ∝ √(L/g).)","o":["About 2.04 s","About 2.00 s","About 1.96 s","About 2.08 s"],"c":0,"e":"Since T ∝ √(L/g), ΔT/T ≈ ½(ΔL/L − Δg/g) = ½(0.02 − (−0.02)) = 0.02, a 2% increase. New T ≈ 2.00 × 1.02 = 2.04 s."},
  {"i":"phys-b2-0064","g":9,"u":"Temperature & Thermometer","d":"impossible","t":"calculation","q":"A faulty Celsius thermometer with a uniform scale reads 2 °C in melting ice and 102 °C in steam at standard pressure. When it reads 52 °C, what is the true temperature?","o":["50 °C","52 °C","54 °C","48 °C"],"c":0,"e":"The faulty scale spans 100 divisions (2→102) over the true 0→100 range, so true T = (reading − 2)/(102 − 2) × 100 = (52 − 2)/100 × 100 = 50 °C."},
  {"i":"phys-b2-0065","g":9,"u":"Physical Quantities","d":"impossible","t":"calculation","q":"The period T of a mass m on a spring of stiffness k is assumed to follow T = 2π·mˣ·kʸ. Given k has SI units N/m = kg/s², dimensional analysis fixes the exponents x and y as:","o":["x = ½, y = −½","x = −½, y = ½","x = 1, y = −1","x = ½, y = ½"],"c":0,"e":"[T] = s. [mˣkʸ] = (kg)ˣ(kg·s⁻²)ʸ = kg^(x+y)·s^(−2y). Matching s¹: −2y = 1 → y = −½; matching kg⁰: x + y = 0 → x = ½, giving T = 2π√(m/k)."},
  {"i":"phys-b2-0066","g":10,"u":"Vector Quantities","d":"easy","t":"calculation","q":"Two forces of 3 N and 4 N act on a body at right angles to each other. What is the magnitude of their resultant?","o":["1 N","5 N","7 N","12 N"],"c":1,"e":"For perpendicular vectors R = √(3² + 4²) = √(9+16) = √25 = 5 N."},
  {"i":"phys-b2-0067","g":10,"u":"Vector Quantities","d":"easy","t":"conceptual","q":"A scalar quantity is best described as one that has:","o":["Magnitude only","Direction only","Both magnitude and direction","Neither magnitude nor direction"],"c":0,"e":"A scalar is fully specified by magnitude alone (e.g. mass, time, energy), unlike a vector which also needs direction."},
  {"i":"phys-b2-0068","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A car starts from rest and accelerates uniformly at 2 m/s². What is its velocity after 5 s?","o":["2.5 m/s","7 m/s","10 m/s","20 m/s"],"c":2,"e":"Using v = u + at with u = 0: v = 0 + (2)(5) = 10 m/s."},
  {"i":"phys-b2-0069","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"An object is dropped from rest. Using g = 9.8 m/s², what is its speed after 2 s of free fall (ignore air resistance)?","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"For free fall v = gt = 9.8 × 2 = 19.6 m/s."},
  {"i":"phys-b2-0070","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"definition","q":"Acceleration is defined as the rate of change of:","o":["Distance","Velocity","Displacement","Force"],"c":1,"e":"Acceleration a = Δv/Δt, the rate of change of velocity with time."},
  {"i":"phys-b2-0071","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A bus moving at 20 m/s slows uniformly to rest in 4 s. What is the magnitude of its acceleration?","o":["4 m/s²","5 m/s²","16 m/s²","80 m/s²"],"c":1,"e":"a = (v − u)/t = (0 − 20)/4 = −5 m/s²; the magnitude is 5 m/s²."},
  {"i":"phys-b2-0072","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"definition","q":"The turning effect of a force about a pivot is called:","o":["Pressure","Moment (torque)","Momentum","Impulse"],"c":1,"e":"The moment (torque) of a force is its turning effect about a point, calculated as force × perpendicular distance."},
  {"i":"phys-b2-0073","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"calculation","q":"A force of 10 N is applied perpendicular to a spanner at a distance of 0.2 m from the bolt. What is the moment of the force?","o":["0.02 N·m","2 N·m","20 N·m","50 N·m"],"c":1,"e":"Moment = F × d = 10 × 0.2 = 2 N·m."},
  {"i":"phys-b2-0074","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"conceptual","q":"For a rigid body to be in static equilibrium, the net force and the net moment on it must both be:","o":["Maximum","Zero","Equal to its weight","Constantly increasing"],"c":1,"e":"Static equilibrium requires ΣF = 0 (no linear acceleration) and Στ = 0 (no rotation)."},
  {"i":"phys-b2-0075","g":10,"u":"Static & Current Electricity","d":"easy","t":"calculation","q":"A current of 2 A flows through a resistor of 5 Ω. What is the voltage across it?","o":["0.4 V","2.5 V","7 V","10 V"],"c":3,"e":"By Ohm's law V = IR = 2 × 5 = 10 V."},
  {"i":"phys-b2-0076","g":10,"u":"Static & Current Electricity","d":"easy","t":"calculation","q":"If a charge of 12 C passes a point in a conductor in 4 s, what is the current?","o":["0.33 A","3 A","8 A","48 A"],"c":1,"e":"Current I = Q/t = 12/4 = 3 A."},
  {"i":"phys-b2-0077","g":10,"u":"Magnetism","d":"easy","t":"conceptual","q":"When two like magnetic poles are brought close together, they:","o":["Attract each other","Repel each other","Lose their magnetism","Form a single pole"],"c":1,"e":"Like poles (N–N or S–S) repel, while unlike poles attract — a basic law of magnetism."},
  {"i":"phys-b2-0078","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"easy","t":"definition","q":"The bending of light as it passes from one transparent medium into another is called:","o":["Reflection","Refraction","Dispersion","Diffraction"],"c":1,"e":"Refraction is the change in direction of light due to a change in its speed when crossing a boundary between media of different optical density."},
  {"i":"phys-b2-0079","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"A delivery rider in Addis Ababa walks 3 km east and then 4 km north. What is the magnitude of his resultant displacement?","o":["5 km","7 km","1 km","12 km"],"c":0,"e":"For perpendicular vectors the resultant is R = √(3² + 4²) = √(9+16) = √25 = 5 km."},
  {"i":"phys-b2-0080","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"Two forces of 6 N and 8 N act at the same point at right angles to each other. What is the magnitude of their resultant?","o":["14 N","2 N","10 N","48 N"],"c":2,"e":"For perpendicular forces R = √(6² + 8²) = √(36+64) = √100 = 10 N."},
  {"i":"phys-b2-0081","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"A force of 20 N is directed at 30° above the horizontal. What is its horizontal component? (cos 30° = 0.87)","o":["10 N","17.4 N","20 N","23 N"],"c":1,"e":"The horizontal component is Fₓ = F cos θ = 20 × cos 30° = 20 × 0.87 = 17.4 N."},
  {"i":"phys-b2-0082","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A car starts from rest and accelerates uniformly at 2 m/s² for 5 s. What is its final velocity?","o":["10 m/s","2.5 m/s","7 m/s","25 m/s"],"c":0,"e":"Using v = u + at = 0 + (2)(5) = 10 m/s."},
  {"i":"phys-b2-0083","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A stone is dropped from rest from a bridge over the Blue Nile and falls for 3 s. How far does it fall? (g = 9.8 m/s²)","o":["29.4 m","44.1 m","14.7 m","88.2 m"],"c":1,"e":"Using h = ½gt² = ½(9.8)(3²) = ½(9.8)(9) = 44.1 m."},
  {"i":"phys-b2-0084","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A ball is thrown vertically upward with an initial speed of 19.6 m/s. What maximum height does it reach? (g = 9.8 m/s²)","o":["19.6 m","9.8 m","39.2 m","4.9 m"],"c":0,"e":"At maximum height v = 0, so h = u²/(2g) = (19.6²)/(2×9.8) = 384.16/19.6 = 19.6 m."},
  {"i":"phys-b2-0085","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A bus moving at 20 m/s brakes uniformly and stops in 4 s. What distance does it travel while stopping?","o":["80 m","40 m","20 m","5 m"],"c":1,"e":"Average velocity = (20+0)/2 = 10 m/s, so distance = 10 × 4 = 40 m."},
  {"i":"phys-b2-0086","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"application","q":"A box of mass 5 kg is pushed across a floor by a net force of 15 N. What is its acceleration?","o":["3 m/s²","75 m/s²","0.33 m/s²","10 m/s²"],"c":0,"e":"By Newton's second law a = F/m = 15/5 = 3 m/s²."},
  {"i":"phys-b2-0087","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A 2 kg ball moving at 6 m/s collides and sticks to a stationary 4 kg ball. What is their common velocity after collision?","o":["2 m/s","6 m/s","3 m/s","1.5 m/s"],"c":0,"e":"By conservation of momentum: (2)(6) = (2+4)v, so 12 = 6v, giving v = 2 m/s."},
  {"i":"phys-b2-0088","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"application","q":"Two satellites orbit Earth. If satellite B is at twice the orbital radius of satellite A, how does the gravitational force on B compare to A (same masses)?","o":["1/2 as large","1/4 as large","2 times as large","4 times as large"],"c":1,"e":"Gravitational force follows F ∝ 1/r². Doubling r gives F × 1/2² = 1/4 of the original force."},
  {"i":"phys-b2-0089","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A spring stretches 0.04 m when a force of 8 N is applied. What is its spring constant?","o":["200 N/m","0.32 N/m","2 N/m","320 N/m"],"c":0,"e":"By Hooke's law F = kx, so k = F/x = 8/0.04 = 200 N/m."},
  {"i":"phys-b2-0090","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A force of 12 N is applied perpendicularly at the end of a 0.5 m wrench. What is the torque about the pivot?","o":["6 N·m","24 N·m","12.5 N·m","0.04 N·m"],"c":0,"e":"Torque τ = F × r = 12 × 0.5 = 6 N·m."},
  {"i":"phys-b2-0091","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"application","q":"A uniform 2 m plank balances on a pivot at its centre. A 10 N weight hangs 0.4 m from the pivot on the left. What weight at 0.5 m on the right keeps it balanced?","o":["8 N","12.5 N","2 N","10 N"],"c":0,"e":"For equilibrium clockwise torque = anticlockwise torque: 10 × 0.4 = W × 0.5, so W = 4/0.5 = 8 N."},
  {"i":"phys-b2-0092","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"A resistor of 4 Ω carries a current of 3 A. What is the potential difference across it?","o":["12 V","1.33 V","7 V","0.75 V"],"c":0,"e":"By Ohm's law V = IR = 3 × 4 = 12 V."},
  {"i":"phys-b2-0093","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"Two resistors of 3 Ω and 6 Ω are connected in parallel. What is their combined resistance?","o":["9 Ω","2 Ω","18 Ω","4.5 Ω"],"c":1,"e":"For parallel resistors 1/R = 1/3 + 1/6 = 2/6 + 1/6 = 3/6, so R = 6/3 = 2 Ω."},
  {"i":"phys-b2-0094","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"An electric lamp draws 0.5 A from a 220 V supply. What power does it consume?","o":["110 W","440 W","220.5 W","55 W"],"c":0,"e":"Electrical power P = VI = 220 × 0.5 = 110 W."},
  {"i":"phys-b2-0095","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"medium","t":"calculation","q":"Light travels from air into glass of refractive index 1.5. If the angle of incidence is 30°, what is sin of the refraction angle? (sin 30° = 0.5)","o":["0.33","0.75","0.5","0.67"],"c":0,"e":"By Snell's law n₁sinθ₁ = n₂sinθ₂: (1)(0.5) = (1.5)sinθ₂, so sinθ₂ = 0.5/1.5 = 0.33."},
  {"i":"phys-b2-0096","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A minibus on a straight road in Adama accelerates uniformly from 8 m/s to 20 m/s while covering 84 m. How long does this take?","o":["3 s","6 s","4.2 s","10.5 s"],"c":1,"e":"a = (20²−8²)/(2·84) = 336/168 = 2 m/s². t = (20−8)/2 = 6 s. Alternatively t = 2s/(u+v) = 168/28 = 6 s."},
  {"i":"phys-b2-0097","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A stone is thrown vertically upward at 24.5 m/s from the edge of a cliff. Taking g = 9.8 m/s², what is its velocity 4 s after being thrown (upward positive)?","o":["−14.7 m/s","+14.7 m/s","−24.5 m/s","−9.8 m/s"],"c":0,"e":"v = u − gt = 24.5 − 9.8·4 = 24.5 − 39.2 = −14.7 m/s (14.7 m/s downward)."},
  {"i":"phys-b2-0098","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"application","q":"A car travels the first half of a 120 km trip at 40 km/h and the second half at 60 km/h. What is the average speed for the whole trip?","o":["50 km/h","48 km/h","52 km/h","45 km/h"],"c":1,"e":"Each half is 60 km. Time = 60/40 + 60/60 = 1.5 + 1 = 2.5 h. Average speed = 120/2.5 = 48 km/h."},
  {"i":"phys-b2-0099","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"Two forces of 6 N and 8 N act at a point. If the angle between them is 90°, what is the magnitude of their resultant?","o":["14 N","2 N","10 N","48 N"],"c":2,"e":"For perpendicular vectors R = √(6²+8²) = √100 = 10 N."},
  {"i":"phys-b2-0100","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"A boat heads directly across a river at 4 m/s while the current flows at 3 m/s parallel to the banks. The river is 40 m wide. How far downstream does the boat land?","o":["30 m","40 m","53.3 m","13.3 m"],"c":0,"e":"Crossing time = 40/4 = 10 s. Downstream drift = 3·10 = 30 m."},
  {"i":"phys-b2-0101","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A uniform plank 6 m long weighing 200 N rests on two supports, one at each end. A 600 N load sits 2 m from the left support. What force does the left support exert?","o":["300 N","500 N","400 N","600 N"],"c":1,"e":"Torques about right support: R_L·6 = 200·3 + 600·4 = 600 + 2400 = 3000, so R_L = 500 N."},
  {"i":"phys-b2-0102","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A steel wire of cross-sectional area 2×10⁻⁶ m² stretches by 0.5 mm under a 400 N load. Its original length is 2 m. What is the Young's modulus of the steel?","o":["8×10¹¹ Pa","8×10⁸ Pa","1.6×10¹² Pa","4×10¹⁰ Pa"],"c":0,"e":"Y = (F·L)/(A·ΔL) = (400·2)/(2×10⁻⁶·0.5×10⁻³) = 800/(1×10⁻⁹) = 8×10¹¹ Pa."},
  {"i":"phys-b2-0103","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"Two resistors, 6 Ω and 3 Ω, are connected in parallel, and this combination is in series with a 4 Ω resistor across a 12 V battery. What is the total current from the battery?","o":["2 A","1 A","3 A","1.5 A"],"c":0,"e":"Parallel: (6·3)/9 = 2 Ω. Total = 2 + 4 = 6 Ω. I = 12/6 = 2 A."},
  {"i":"phys-b2-0104","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"Two point charges of +4 μC and −9 μC are separated by 3 m in air (k = 9×10⁹ N·m²/C²). What is the magnitude of the electrostatic force between them?","o":["0.036 N","0.108 N","0.012 N","0.36 N"],"c":0,"e":"F = k·q₁·q₂/r² = 9×10⁹·(4×10⁻⁶·9×10⁻⁶)/9 = 9×10⁹·36×10⁻¹²/9 = 0.036 N."},
  {"i":"phys-b2-0105","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"An electric heater rated 1100 W operates on a 220 V supply. If electricity costs 1.50 birr per kWh, what is the cost of running it for 4 hours?","o":["6.60 birr","4.40 birr","1.65 birr","13.20 birr"],"c":0,"e":"Energy = 1.1 kW · 4 h = 4.4 kWh. Cost = 4.4 · 1.50 = 6.60 birr."},
  {"i":"phys-b2-0106","g":10,"u":"Magnetism","d":"hard","t":"calculation","q":"A straight wire of length 0.25 m carries a current of 8 A perpendicular to a uniform magnetic field of 0.5 T. What is the magnitude of the force on the wire?","o":["1 N","4 N","0.5 N","16 N"],"c":0,"e":"F = BIL sinθ = 0.5·8·0.25·sin90° = 1 N."},
  {"i":"phys-b2-0107","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"hard","t":"calculation","q":"A ray of light travels from air into a glass block of refractive index 1.5, striking the surface at an angle of incidence of 60°. What is the sine of the angle of refraction?","o":["0.577","0.866","0.500","1.299"],"c":0,"e":"Snell's law: sinθ₂ = (1·sin60°)/1.5 = 0.866/1.5 = 0.577."},
  {"i":"phys-b2-0108","g":10,"u":"Uniformly Accelerated Motion","d":"impossible","t":"calculation","q":"From the edge of a 19.6 m high cliff in the Entoto hills, a stone is thrown vertically upward with an initial speed of 14.7 m/s. Taking g = 9.8 m/s², what is the stone's speed the instant it strikes the ground at the base of the cliff?","o":["19.6 m/s","24.5 m/s","14.7 m/s","29.4 m/s"],"c":1,"e":"Using v² = v₀² + 2g·h with total fall accounting (or v = v₀ − gt at t = 4.0 s): solving 4.9t² − 14.7t − 19.6 = 0 gives t = 4.0 s, so v = 14.7 − 9.8(4.0) = −24.5 m/s, i.e. a speed of 24.5 m/s downward."},
  {"i":"phys-b2-0109","g":10,"u":"Vector Quantities","d":"impossible","t":"calculation","q":"A boat that moves at 5 m/s relative to still water must cross a 90 m wide river and land at the point directly opposite its start. The river current flows at 3 m/s. The boat is aimed upstream at the correct angle so its resultant path is straight across. How long does the crossing take?","o":["18 s","30 s","22.5 s","15 s"],"c":2,"e":"To cancel the 3 m/s current, the across-stream component is √(5² − 3²) = 4 m/s; time = width ÷ effective speed = 90 ÷ 4 = 22.5 s."},
  {"i":"phys-b2-0110","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"impossible","t":"calculation","q":"A uniform ladder leans against a smooth (frictionless) vertical wall, with its base on a floor whose coefficient of static friction is 0.40. What is the smallest angle the ladder can make with the floor without slipping?","o":["≈ 38.7°","≈ 51.3°","≈ 45.0°","≈ 21.8°"],"c":1,"e":"Taking torque about the base and using N_wall = μ·W at the floor gives the slip condition tanθ = 1/(2μ) = 1/(2·0.40) = 1.25, so θ = arctan(1.25) ≈ 51.3°."},
  {"i":"phys-b2-0111","g":10,"u":"Static & Current Electricity","d":"impossible","t":"calculation","q":"A battery of emf 12 V and internal resistance 0.5 Ω drives a circuit in which a 1.5 Ω resistor is in series with a parallel combination of a 3 Ω and a 6 Ω resistor. What current flows through the 6 Ω resistor?","o":["3.0 A","2.0 A","1.0 A","1.5 A"],"c":2,"e":"Parallel pair = (3·6)/(3+6) = 2 Ω; total R = 0.5 + 1.5 + 2 = 4 Ω, so total I = 12/4 = 3 A. Voltage across the pair = 3·2 = 6 V, giving I₆ = 6/6 = 1.0 A."},
  {"i":"phys-b2-0112","g":10,"u":"Magnetism","d":"impossible","t":"calculation","q":"A proton (mass 1.67×10⁻²⁷ kg, charge 1.6×10⁻¹⁹ C) enters a uniform magnetic field of 0.5 T moving at 2×10⁵ m/s perpendicular to the field. What is the radius of its circular path?","o":["4.2×10⁻³ m","8.4×10⁻³ m","2.1×10⁻³ m","1.6×10⁻¹⁴ m"],"c":0,"e":"The magnetic force supplies the centripetal force, so r = mv/(qB) = (1.67×10⁻²⁷ × 2×10⁵)/(1.6×10⁻¹⁹ × 0.5) ≈ 4.2×10⁻³ m."},
  {"i":"phys-b2-0113","g":11,"u":"Physics & Human Society","d":"easy","t":"definition","q":"Which branch of physics deals with the behaviour of objects moving at speeds close to the speed of light?","o":["Classical mechanics","Thermodynamics","Relativity","Optics"],"c":2,"e":"Relativity (Einstein) describes motion at speeds near the speed of light, where classical mechanics breaks down."},
  {"i":"phys-b2-0114","g":11,"u":"Physics & Human Society","d":"easy","t":"conceptual","q":"Which of the following is the correct SI base unit for the amount of substance?","o":["Mole (mol)","Kilogram (kg)","Kelvin (K)","Candela (cd)"],"c":0,"e":"Among the seven SI base units, the mole (mol) measures amount of substance; kg is mass, K is temperature, cd is luminous intensity."},
  {"i":"phys-b2-0115","g":11,"u":"Vectors","d":"easy","t":"calculation","q":"A vector has components 3 m east and 4 m north. What is its magnitude?","o":["5 m","7 m","1 m","12 m"],"c":0,"e":"Magnitude = √(3² + 4²) = √(9 + 16) = √25 = 5 m."},
  {"i":"phys-b2-0116","g":11,"u":"Vectors","d":"easy","t":"definition","q":"Two vectors of equal magnitude point in exactly opposite directions. What is the magnitude of their resultant?","o":["Zero","Double one vector","Equal to one vector","Half one vector"],"c":0,"e":"Opposite equal vectors cancel: their sum is zero because A + (−A) = 0."},
  {"i":"phys-b2-0117","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A ball is dropped from rest. Using g = 9.8 m/s², what is its speed after 2 s of free fall?","o":["19.6 m/s","9.8 m/s","4.9 m/s","11.8 m/s"],"c":0,"e":"v = gt = 9.8 × 2 = 19.6 m/s (taking downward as positive, starting from rest)."},
  {"i":"phys-b2-0118","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A net force of 12 N acts on a 4 kg object. What is its acceleration?","o":["3 m/s²","48 m/s²","0.33 m/s²","8 m/s²"],"c":0,"e":"From Newton's second law, a = F/m = 12/4 = 3 m/s²."},
  {"i":"phys-b2-0119","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"What is the momentum of a 2 kg object moving at 5 m/s?","o":["10 kg·m/s","2.5 kg·m/s","7 kg·m/s","25 kg·m/s"],"c":0,"e":"Momentum p = mv = 2 × 5 = 10 kg·m/s."},
  {"i":"phys-b2-0120","g":11,"u":"Dynamics","d":"easy","t":"definition","q":"Newton's third law of motion states that for every action there is:","o":["An equal and opposite reaction","A larger reaction","No reaction","A delayed reaction"],"c":0,"e":"Newton's third law: forces occur in pairs that are equal in magnitude and opposite in direction."},
  {"i":"phys-b2-0121","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"What is the weight of a 10 kg sack of teff on Earth (g = 9.8 m/s²)?","o":["98 N","10 N","9.8 N","980 N"],"c":0,"e":"Weight W = mg = 10 × 9.8 = 98 N."},
  {"i":"phys-b2-0122","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"A 12 V battery drives a current of 3 A through a resistor. What is the resistance?","o":["4 Ω","36 Ω","0.25 Ω","9 Ω"],"c":0,"e":"By Ohm's law, R = V/I = 12/3 = 4 Ω."},
  {"i":"phys-b2-0123","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"definition","q":"Like electric charges _______ each other.","o":["Repel","Attract","Neutralize","Bond with"],"c":0,"e":"Like charges (both positive or both negative) repel; only unlike charges attract."},
  {"i":"phys-b2-0124","g":11,"u":"Nuclear Physics","d":"easy","t":"definition","q":"Which type of nuclear radiation consists of helium nuclei and has the least penetrating power?","o":["Alpha","Beta","Gamma","X-ray"],"c":0,"e":"Alpha particles are helium nuclei (2 protons + 2 neutrons); they are the least penetrating and stopped by paper."},
  {"i":"phys-b2-0125","g":11,"u":"Physics & Human Society","d":"medium","t":"conceptual","q":"A research team in Addis Ababa wants to test a hypothesis about crop yields. Which sequence correctly represents the scientific method they should follow?","o":["Conclusion → Hypothesis → Observation → Experiment","Observation → Hypothesis → Experiment → Conclusion","Hypothesis → Conclusion → Observation → Experiment","Experiment → Observation → Hypothesis → Conclusion"],"c":1,"e":"The scientific method begins with observation, forms a testable hypothesis, tests it through controlled experiment, then draws a conclusion based on results."},
  {"i":"phys-b2-0126","g":11,"u":"Physics & Human Society","d":"medium","t":"application","q":"A measurement of the length of a table is recorded as 1.250 m. How many significant figures does this measurement contain?","o":["2","3","4","5"],"c":2,"e":"All non-zero digits and the trailing zero after a decimal point are significant: 1, 2, 5, 0 give 4 significant figures."},
  {"i":"phys-b2-0127","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Two forces act on a body at right angles: 6 N east and 8 N north. What is the magnitude of the resultant force?","o":["10 N","14 N","2 N","48 N"],"c":0,"e":"For perpendicular vectors R = √(6² + 8²) = √(36 + 64) = √100 = 10 N."},
  {"i":"phys-b2-0128","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"A vector of magnitude 20 N makes an angle of 30° with the horizontal. What is its horizontal component? (cos30° ≈ 0.866)","o":["10 N","17.3 N","20 N","11.5 N"],"c":1,"e":"The horizontal component is Fₓ = F cos θ = 20 × cos30° = 20 × 0.866 ≈ 17.3 N."},
  {"i":"phys-b2-0129","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A car starts from rest and accelerates uniformly at 2 m/s² for 5 s. How far does it travel in this time?","o":["10 m","25 m","50 m","20 m"],"c":1,"e":"Using s = ut + ½at² = 0 + ½(2)(5²) = ½ × 2 × 25 = 25 m."},
  {"i":"phys-b2-0130","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A ball is projected horizontally from a cliff with speed 10 m/s and lands after 2 s. What is its horizontal range? (Ignore air resistance)","o":["20 m","5 m","40 m","10 m"],"c":0,"e":"Horizontal motion has no acceleration, so range = horizontal speed × time = 10 × 2 = 20 m."},
  {"i":"phys-b2-0131","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A net force of 12 N acts on a 3 kg object. What is its acceleration?","o":["36 m/s²","0.25 m/s²","4 m/s²","9 m/s²"],"c":2,"e":"By Newton's second law a = F/m = 12/3 = 4 m/s²."},
  {"i":"phys-b2-0132","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 2 kg ball moving at 5 m/s collides and sticks to a stationary 3 kg ball. What is their common velocity after collision?","o":["2 m/s","5 m/s","2.5 m/s","1 m/s"],"c":0,"e":"By conservation of momentum: (2×5) + 0 = (2+3)v, so 10 = 5v, v = 2 m/s."},
  {"i":"phys-b2-0133","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A wheel rotating at 4 rad/s accelerates uniformly to 10 rad/s in 3 s. What is its angular acceleration?","o":["2 rad/s²","6 rad/s²","14 rad/s²","0.5 rad/s²"],"c":0,"e":"Angular acceleration α = (ω − ω₀)/t = (10 − 4)/3 = 6/3 = 2 rad/s²."},
  {"i":"phys-b2-0134","g":11,"u":"Dynamics","d":"medium","t":"application","q":"Two objects of masses m and 2m are separated by distance r. If the distance is doubled to 2r, the gravitational force between them becomes:","o":["Half the original","One quarter of the original","Double the original","Four times the original"],"c":1,"e":"Gravitational force F ∝ 1/r². Doubling r makes F a factor of 1/2² = 1/4 of the original."},
  {"i":"phys-b2-0135","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"How much heat is required to raise the temperature of 2 kg of water by 10°C? (Specific heat of water = 4200 J/(kg·°C))","o":["8400 J","42000 J","84000 J","420 J"],"c":2,"e":"Q = mcΔT = 2 × 4200 × 10 = 84000 J."},
  {"i":"phys-b2-0136","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"A metal rod has its ends kept at 100°C and 20°C. If the temperature difference doubles while all else stays constant, the rate of heat conduction:","o":["Stays the same","Doubles","Halves","Becomes four times"],"c":1,"e":"By Fourier's law the conduction rate Q/t = kAΔT/L is directly proportional to ΔT, so doubling ΔT doubles the rate."},
  {"i":"phys-b2-0137","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two point charges of +3 μC and +6 μC are 3 m apart. Using k = 9×10⁹ N·m²/C², what is the magnitude of the force between them?","o":["18×10⁻³ N","18 N","54×10⁻³ N","6×10⁻³ N"],"c":0,"e":"F = kq₁q₂/r² = 9×10⁹ × (3×10⁻⁶)(6×10⁻⁶)/3² = 9×10⁹ × 18×10⁻¹²/9 = 18×10⁻³ N."},
  {"i":"phys-b2-0138","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Three resistors of 2 Ω, 3 Ω and 5 Ω are connected in series across a 20 V battery. What current flows in the circuit?","o":["10 A","2 A","4 A","0.5 A"],"c":1,"e":"Series resistance = 2 + 3 + 5 = 10 Ω, so I = V/R = 20/10 = 2 A."},
  {"i":"phys-b2-0139","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two resistors of 6 Ω and 3 Ω are connected in parallel. What is their equivalent resistance?","o":["9 Ω","2 Ω","4.5 Ω","18 Ω"],"c":1,"e":"For parallel resistors 1/R = 1/6 + 1/3 = 1/6 + 2/6 = 3/6, so R = 2 Ω."},
  {"i":"phys-b2-0140","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A stone is thrown horizontally at 15 m/s from the top of a cliff in Lalibela and lands 45 m from the base. Taking g = 9.8 m/s², how tall is the cliff?","o":["44.1 m","30.0 m","9.0 m","22.1 m"],"c":0,"e":"Time of flight from horizontal range: t = 45/15 = 3 s. Height h = ½gt² = ½(9.8)(3²) = 44.1 m."},
  {"i":"phys-b2-0141","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A projectile is launched at 20 m/s at 30° above the horizontal. What is its maximum height? (g = 9.8 m/s²)","o":["5.10 m","10.2 m","20.4 m","2.55 m"],"c":0,"e":"H = (v sinθ)²/(2g) = (20·sin30°)²/(2·9.8) = (10)²/19.6 = 5.10 m."},
  {"i":"phys-b2-0142","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 4 kg block on a frictionless incline of 30° is connected over a pulley to a hanging 3 kg mass. What is the acceleration of the system? (g = 9.8 m/s²)","o":["1.40 m/s²","2.80 m/s²","4.20 m/s²","9.80 m/s²"],"c":0,"e":"a = (m₂g − m₁g sinθ)/(m₁+m₂) = (3·9.8 − 4·9.8·0.5)/7 = (29.4 − 19.6)/7 = 1.40 m/s²."},
  {"i":"phys-b2-0143","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 1200 kg car rounds a flat curve of radius 50 m at 15 m/s. What minimum coefficient of static friction between tyres and road is required? (g = 9.8 m/s²)","o":["0.46","0.23","0.92","0.31"],"c":0,"e":"For circular motion μmg = mv²/r, so μ = v²/(rg) = 15²/(50·9.8) = 225/490 = 0.46."},
  {"i":"phys-b2-0144","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 0.15 kg ball moving at 8 m/s strikes a wall and rebounds at 6 m/s in the opposite direction. If contact lasts 0.02 s, what average force does the wall exert?","o":["105 N","15 N","45 N","210 N"],"c":0,"e":"Δp = m(v_f − v_i) = 0.15(−6 − 8) = −2.1 kg·m/s. F = Δp/Δt = 2.1/0.02 = 105 N."},
  {"i":"phys-b2-0145","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"Two satellites orbit Earth; satellite B's orbital radius is 4 times that of satellite A. By what factor is B's orbital period larger than A's?","o":["8","4","16","2"],"c":0,"e":"Kepler's third law T² ∝ r³, so T_B/T_A = (4)^(3/2) = 8."},
  {"i":"phys-b2-0146","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A uniform disc of moment of inertia 0.5 kg·m² is spinning at 4 rad/s. A constant torque of 2 N·m is applied opposing the motion. How long until it stops?","o":["1.0 s","2.0 s","4.0 s","0.5 s"],"c":0,"e":"α = τ/I = 2/0.5 = 4 rad/s². Time to stop: t = ω/α = 4/4 = 1.0 s."},
  {"i":"phys-b2-0147","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Two point charges of +3 μC and −3 μC are placed 0.20 m apart. What is the magnitude of the force between them? (k = 9×10⁹ N·m²/C²)","o":["2.0 N","0.45 N","20 N","4.0 N"],"c":0,"e":"F = kq₁q₂/r² = 9×10⁹·(3×10⁻⁶)²/(0.20²) = 9×10⁹·9×10⁻¹²/0.04 = 0.081/0.04 = 2.0 N (attractive)."},
  {"i":"phys-b2-0148","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A 12 V battery with internal resistance 0.5 Ω is connected to a 5.5 Ω external resistor. What is the terminal voltage of the battery?","o":["11 V","12 V","1 V","6 V"],"c":0,"e":"I = ε/(R+r) = 12/6 = 2 A. Terminal voltage V = ε − Ir = 12 − 2·0.5 = 11 V."},
  {"i":"phys-b2-0149","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Three resistors of 6 Ω, 3 Ω and 4 Ω: the 6 Ω and 3 Ω are in parallel, and that combination is in series with the 4 Ω. What is the total resistance?","o":["6 Ω","13 Ω","2 Ω","5.2 Ω"],"c":0,"e":"Parallel: (6·3)/(6+3) = 18/9 = 2 Ω. Series with 4 Ω: 2 + 4 = 6 Ω."},
  {"i":"phys-b2-0150","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"How much heat is needed to convert 0.2 kg of ice at 0 °C completely to water at 0 °C? (Latent heat of fusion of ice = 3.34×10⁵ J/kg)","o":["6.68×10⁴ J","3.34×10⁵ J","6.68×10⁵ J","1.67×10⁴ J"],"c":0,"e":"Q = mL = 0.2 × 3.34×10⁵ = 6.68×10⁴ J. No temperature change occurs during melting."},
  {"i":"phys-b2-0151","g":11,"u":"Nuclear Physics","d":"hard","t":"calculation","q":"A radioactive isotope has a half-life of 8 days. What fraction of an initial sample remains after 24 days?","o":["1/8","1/3","1/16","1/24"],"c":0,"e":"Number of half-lives n = 24/8 = 3. Fraction remaining = (½)³ = 1/8."},
  {"i":"phys-b2-0152","g":11,"u":"Motion in One and Two Dimensions","d":"impossible","t":"calculation","q":"From the edge of a cliff a stone is thrown so that exactly at the top of its trajectory its speed equals half its launch speed. If the maximum height reached above the launch point is 15.0 m, what was the launch speed (take g = 9.8 m/s²)?","o":["≈ 19.8 m/s","≈ 17.1 m/s","≈ 9.9 m/s","≈ 34.3 m/s"],"c":0,"e":"At the top vₓ = v₀cosθ = v₀/2, so cosθ = 1/2 (θ = 60°). Max height H = (v₀sinθ)²/(2g) ⇒ v₀sin60° = √(2gH) = √(2·9.8·15) = 17.15 m/s, so v₀ = 17.15/sin60° = 17.15/0.866 ≈ 19.8 m/s."},
  {"i":"phys-b2-0153","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"Twelve identical 6.0 Ω resistors are soldered along the edges of a cube. A battery is connected across one body diagonal of the cube (between two opposite corners). What is the equivalent resistance the battery sees?","o":["5.0 Ω","6.0 Ω","10.0 Ω","2.5 Ω"],"c":0,"e":"By symmetry the body-diagonal resistance of a cube of edge resistors R is (5/6)R: current splits into 3 parallel, then 6 parallel, then 3 parallel paths giving R(1/3 + 1/6 + 1/3) = 5R/6 = (5/6)(6) = 5.0 Ω."},
  {"i":"phys-b2-0154","g":11,"u":"Heat Conduction & Calorimetry","d":"impossible","t":"calculation","q":"A compound rod is made of a copper section (k = 400 W/m·K, length 0.10 m) joined end-to-end to a steel section (k = 50 W/m·K, length 0.10 m); both have the same cross-section. The free copper end is held at 100 °C and the free steel end at 0 °C, with sides insulated. In steady state, what is the temperature at the copper–steel junction?","o":["11.1 °C","88.9 °C","50.0 °C","20.0 °C"],"c":1,"e":"Steady-state heat flow is equal through both: k_Cu(100−T)/L = k_St(T−0)/L ⇒ 400(100−T) = 50T ⇒ 40000 = 450T ⇒ T ≈ 88.9 °C (the better conductor drops little temperature, so the junction stays hot)."},
  {"i":"phys-b2-0155","g":11,"u":"Nuclear Physics","d":"impossible","t":"calculation","q":"A radioactive sample contains two independent isotopes with equal initial activity. Isotope A has half-life 2.0 days and isotope B has half-life 6.0 days. After 6.0 days, what is the ratio of the total activity to the initial total activity (A_total / A₀,total)?","o":["0.3125","0.5000","0.1875","0.2500"],"c":0,"e":"Each isotope starts at A₀/2. After 6 days: A undergoes 3 half-lives → (1/8); B undergoes 1 half-life → (1/2). Total = (A₀/2)(1/8) + (A₀/2)(1/2) = A₀(1/16 + 1/4) = (5/16)A₀ = 0.3125 A₀."},
  {"i":"phys-b2-0156","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A stone is thrown horizontally from a cliff with a speed of 5 m/s. After 2 s, what is its vertical velocity component? (g = 9.8 m/s²)","o":["5 m/s","9.8 m/s","19.6 m/s","24.6 m/s"],"c":2,"e":"The vertical velocity in projectile motion is v_y = g·t = 9.8 × 2 = 19.6 m/s. The horizontal component (5 m/s) stays constant and is not asked."},
  {"i":"phys-b2-0157","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A ball is projected at 20 m/s at an angle of 30° above the horizontal. What is its horizontal velocity component? (cos30° ≈ 0.87)","o":["10 m/s","17.4 m/s","20 m/s","11.5 m/s"],"c":1,"e":"The horizontal component is vₓ = v·cosθ = 20 × cos30° = 20 × 0.87 = 17.4 m/s."},
  {"i":"phys-b2-0158","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"conceptual","q":"For a projectile launched at an angle (neglecting air resistance), which quantity remains constant throughout the flight?","o":["Vertical velocity component","Horizontal velocity component","Total speed","Vertical acceleration changes sign"],"c":1,"e":"With no air resistance, the only force is gravity acting vertically, so the horizontal velocity component is unchanged while the vertical component changes due to g."},
  {"i":"phys-b2-0159","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"An object moves in a circle of radius 2 m at a constant speed of 4 m/s. What is its centripetal acceleration?","o":["2 m/s²","4 m/s²","8 m/s²","16 m/s²"],"c":2,"e":"Centripetal acceleration a = v²/r = (4)²/2 = 16/2 = 8 m/s²."},
  {"i":"phys-b2-0160","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 2 kg object on a frictionless surface is pushed with a net force of 10 N. What is its acceleration? (Newton's second law)","o":["2 m/s²","5 m/s²","10 m/s²","20 m/s²"],"c":1,"e":"By Newton's second law, a = F/m = 10/2 = 5 m/s²."},
  {"i":"phys-b2-0161","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 3 kg cart moving at 4 m/s collides and sticks to a 1 kg cart at rest. What is their common velocity after collision? (conservation of momentum)","o":["2 m/s","3 m/s","4 m/s","1 m/s"],"c":1,"e":"Conservation of momentum: (3×4 + 1×0) = (3+1)·v, so 12 = 4v, giving v = 3 m/s."},
  {"i":"phys-b2-0162","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A wheel rotating at constant angular velocity turns through 4 rad in 2 s. What is its angular velocity?","o":["0.5 rad/s","2 rad/s","4 rad/s","8 rad/s"],"c":1,"e":"Angular velocity ω = θ/t = 4/2 = 2 rad/s."},
  {"i":"phys-b2-0163","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A force of 20 N is applied at a perpendicular distance of 0.5 m from a pivot. What is the torque?","o":["10 N·m","20 N·m","40 N·m","5 N·m"],"c":0,"e":"Torque τ = F·d = 20 × 0.5 = 10 N·m, since the force is perpendicular to the lever arm."},
  {"i":"phys-b2-0164","g":12,"u":"Application of Physics","d":"easy","t":"definition","q":"Newton's law of universal gravitation states that the gravitational force between two masses is inversely proportional to:","o":["The distance between them","The square of the distance between them","The sum of the masses","The product of the masses"],"c":1,"e":"F = G·m₁m₂/r²; the force is inversely proportional to the square of the separation r, and directly proportional to the product of the masses."},
  {"i":"phys-b2-0165","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"A liquid of density 1000 kg/m³ fills a column to a depth of 2 m. What is the gauge pressure at the bottom? (g = 9.8 m/s²)","o":["1960 Pa","9800 Pa","19600 Pa","2000 Pa"],"c":2,"e":"Gauge pressure P = ρgh = 1000 × 9.8 × 2 = 19600 Pa."},
  {"i":"phys-b2-0166","g":12,"u":"Fluid Mechanics","d":"easy","t":"definition","q":"Archimedes' principle states that the buoyant force on a submerged object equals the:","o":["Weight of the object","Weight of the fluid displaced","Volume of the object","Density of the fluid"],"c":1,"e":"Archimedes' principle: the upward buoyant force equals the weight of the fluid displaced by the object."},
  {"i":"phys-b2-0167","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A resistor of 4 Ω carries a current of 3 A. What is the voltage across it? (Ohm's law)","o":["0.75 V","7 V","12 V","1.33 V"],"c":2,"e":"By Ohm's law, V = I·R = 3 × 4 = 12 V."},
  {"i":"phys-b2-0168","g":12,"u":"Electronics","d":"easy","t":"definition","q":"In a semiconductor diode, current flows easily in which condition?","o":["Reverse bias only","Forward bias only","Both biases equally","Neither bias"],"c":1,"e":"A diode conducts readily under forward bias (p-side at higher potential) and blocks current under reverse bias, allowing one-way current flow."},
  {"i":"phys-b2-0169","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A footballer in Addis Ababa kicks a ball at 20 m/s at 30° above the horizontal. Taking g = 9.8 m/s², what is the maximum height the ball reaches?","o":["5.1 m","10.2 m","2.6 m","20.4 m"],"c":0,"e":"H = (v²sin²θ)/(2g) = (20²·(0.5)²)/(2·9.8) = 100/19.6 ≈ 5.1 m."},
  {"i":"phys-b2-0170","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A projectile is launched at 40 m/s at 45° on level ground. Using g = 9.8 m/s², what is its horizontal range?","o":["163 m","82 m","116 m","326 m"],"c":0,"e":"R = (v²sin2θ)/g = (1600·sin90°)/9.8 = 1600/9.8 ≈ 163 m."},
  {"i":"phys-b2-0171","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A stone is thrown horizontally at 15 m/s from a cliff and lands after 2 s. Taking g = 9.8 m/s², what is the horizontal distance traveled?","o":["30 m","19.6 m","49 m","60 m"],"c":0,"e":"Horizontal motion is uniform: x = v·t = 15·2 = 30 m; gravity affects only the vertical component."},
  {"i":"phys-b2-0172","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A car of mass 1000 kg rounds a flat curve of radius 50 m at 10 m/s. What centripetal force is required?","o":["2000 N","200 N","20000 N","1000 N"],"c":0,"e":"F = mv²/r = 1000·100/50 = 2000 N."},
  {"i":"phys-b2-0173","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 2 kg block is pushed across a floor with a 12 N horizontal force against a friction force of 4 N. What is its acceleration?","o":["4 m/s²","6 m/s²","8 m/s²","2 m/s²"],"c":0,"e":"Net force = 12 − 4 = 8 N; a = F/m = 8/2 = 4 m/s²."},
  {"i":"phys-b2-0174","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 0.5 kg ball moving at 6 m/s is struck and rebounds straight back at 4 m/s. What is the magnitude of the impulse on the ball?","o":["5 N·s","1 N·s","3 N·s","2 N·s"],"c":0,"e":"Taking rebound as opposite direction: Δp = m(v_f − v_i) = 0.5·(−4 − 6) = −5 N·s; magnitude 5 N·s."},
  {"i":"phys-b2-0175","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 3 kg cart at 4 m/s collides and sticks to a stationary 1 kg cart. What is their common velocity after collision?","o":["3 m/s","4 m/s","2 m/s","1 m/s"],"c":0,"e":"Conservation of momentum: 3·4 = (3+1)v → 12 = 4v → v = 3 m/s."},
  {"i":"phys-b2-0176","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A force of 20 N is applied tangentially at the rim of a disc of radius 0.25 m. What torque does it produce?","o":["5 N·m","80 N·m","0.0125 N·m","4 N·m"],"c":0,"e":"τ = F·r = 20·0.25 = 5 N·m (force perpendicular to radius)."},
  {"i":"phys-b2-0177","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"Two 6 kg masses are separated by 2 m. Using G = 6.67×10⁻¹¹ N·m²/kg², what is the gravitational force between them?","o":["6.0×10⁻¹⁰ N","2.4×10⁻⁹ N","1.2×10⁻⁹ N","6.0×10⁻¹¹ N"],"c":0,"e":"F = Gm₁m₂/r² = 6.67×10⁻¹¹·36/4 = 6.0×10⁻¹⁰ N."},
  {"i":"phys-b2-0178","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A water tank is open at the top. At a depth of 5 m below the surface, what is the gauge pressure? (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["49000 Pa","5000 Pa","9800 Pa","98000 Pa"],"c":0,"e":"Gauge pressure P = ρgh = 1000·9.8·5 = 49000 Pa."},
  {"i":"phys-b2-0179","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"An object of volume 2×10⁻³ m³ is fully submerged in water (ρ = 1000 kg/m³). What buoyant force does it experience? (g = 9.8 m/s²)","o":["19.6 N","2.0 N","1960 N","9.8 N"],"c":0,"e":"F_b = ρ_fluid·V·g = 1000·2×10⁻³·9.8 = 19.6 N (Archimedes' principle)."},
  {"i":"phys-b2-0180","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A 12 V battery is connected across a 4 Ω resistor. What current flows through the resistor?","o":["3 A","48 A","0.33 A","8 A"],"c":0,"e":"Ohm's law: I = V/R = 12/4 = 3 A."},
  {"i":"phys-b2-0181","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A proton moves at 2×10⁶ m/s perpendicular to a 0.5 T magnetic field. The charge is 1.6×10⁻¹⁹ C. What is the magnetic force on it?","o":["1.6×10⁻¹³ N","8.0×10⁻¹⁴ N","3.2×10⁻¹³ N","1.6×10⁻¹⁹ N"],"c":0,"e":"F = qvB = 1.6×10⁻¹⁹·2×10⁶·0.5 = 1.6×10⁻¹³ N (velocity perpendicular to B)."},
  {"i":"phys-b2-0182","g":12,"u":"Electronics","d":"medium","t":"conceptual","q":"In a forward-biased silicon p–n junction diode, what happens to the depletion region and current flow?","o":["The depletion region narrows and current flows easily","The depletion region widens and blocks current","The depletion region stays fixed and no current flows","The diode acts as an open switch in both directions"],"c":0,"e":"Forward bias lowers the potential barrier, narrowing the depletion region so majority carriers cross and current flows readily."},
  {"i":"phys-b2-0183","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 0.50 kg ball moving at 8.0 m/s strikes a wall perpendicularly and rebounds at 6.0 m/s. If the contact lasts 0.020 s, what is the average force the wall exerts on the ball?","o":["50 N","100 N","350 N","700 N"],"c":2,"e":"Δp = m(v_f - v_i) = 0.50(-6.0 - 8.0) = -7.0 kg·m/s. F = Δp/Δt = 7.0/0.020 = 350 N in magnitude."},
  {"i":"phys-b2-0184","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A solid uniform sphere (I = (2/5)mr²) of mass 2.0 kg and radius 0.10 m rolls without slipping down an incline, starting from rest and descending a vertical height of 1.4 m. What is its speed at the bottom? (g = 9.8 m/s²)","o":["3.7 m/s","4.4 m/s","5.2 m/s","6.6 m/s"],"c":1,"e":"Energy: mgh = ½mv² + ½Iω² = ½mv² + ½(2/5)mv² = (7/10)mv². So v = √(10gh/7) = √(10·9.8·1.4/7) = √19.6 = 4.4 m/s."},
  {"i":"phys-b2-0185","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"Two masses, 3.0 kg and 5.0 kg, hang from a light string over a frictionless pulley (Atwood machine). What is the magnitude of the acceleration of the system? (g = 9.8 m/s²)","o":["1.96 m/s²","2.45 m/s²","3.92 m/s²","4.90 m/s²"],"c":1,"e":"a = (m₂ - m₁)g/(m₁ + m₂) = (5.0 - 3.0)·9.8/(8.0) = 19.6/8.0 = 2.45 m/s²."},
  {"i":"phys-b2-0186","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A satellite orbits Earth in a circular orbit of radius 4R, where R is Earth's radius. If the gravitational acceleration at Earth's surface is g, what is the orbital speed of the satellite? (Use g = 9.8 m/s², R = 6.4×10⁶ m)","o":["2.0×10³ m/s","4.0×10³ m/s","5.6×10³ m/s","7.9×10³ m/s"],"c":1,"e":"Orbital v = √(GM/r) = √(gR²/r) = √(gR²/4R) = √(gR/4) = √(9.8·6.4×10⁶/4) = √(1.568×10⁷) ≈ 3.96×10³ ≈ 4.0×10³ m/s."},
  {"i":"phys-b2-0187","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A solid block floats in water with 80% of its volume submerged. When placed in an unknown liquid, only 60% of its volume is submerged. What is the density of the unknown liquid? (ρ_water = 1000 kg/m³)","o":["750 kg/m³","1000 kg/m³","1200 kg/m³","1333 kg/m³"],"c":3,"e":"Floating: ρ_block = 0.80·ρ_water = 800 kg/m³. In the liquid: ρ_block = 0.60·ρ_liquid, so ρ_liquid = 800/0.60 = 1333 kg/m³."},
  {"i":"phys-b2-0188","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A proton (q = 1.6×10⁻¹⁹ C) moves at 2.0×10⁵ m/s perpendicular to a uniform magnetic field of 0.50 T. What is the radius of its circular path? (m_proton = 1.67×10⁻²⁷ kg)","o":["2.1×10⁻³ m","4.2×10⁻³ m","8.4×10⁻³ m","1.7×10⁻² m"],"c":1,"e":"r = mv/(qB) = (1.67×10⁻²⁷·2.0×10⁵)/(1.6×10⁻¹⁹·0.50) = (3.34×10⁻²²)/(8.0×10⁻²⁰) = 4.2×10⁻³ m."},
  {"i":"phys-b2-0189","g":12,"u":"Electronics","d":"hard","t":"calculation","q":"In a series RC circuit, a 12 V battery charges a 100 μF capacitor through a 2.0 kΩ resistor. What is the charge on the capacitor after one time constant? (Use 1 - e⁻¹ ≈ 0.632)","o":["4.6×10⁻⁴ C","7.6×10⁻⁴ C","1.2×10⁻³ C","1.9×10⁻³ C"],"c":1,"e":"Final charge Q = CV = 100×10⁻⁶·12 = 1.2×10⁻³ C. After one time constant: q = Q(1-e⁻¹) = 1.2×10⁻³·0.632 = 7.6×10⁻⁴ C."},
  {"i":"phys-b2-0190","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"On the road to Adama, a boy kicks a ball at exactly 45° above the horizontal. The ball must just graze the top of a fence 15 m high located 40 m away horizontally (measured from the launch point). Taking g = 9.8 m/s² and neglecting air resistance, what is the launch speed?","o":["About 19.8 m/s","About 22.1 m/s","About 25.0 m/s","About 17.7 m/s"],"c":2,"e":"The trajectory at 45° is y = x − gx²/v². Setting y = 15 m at x = 40 m gives v² = gd²/(d−h) = 9.8·40²/(40−15) = 627.2, so v ≈ 25.0 m/s."},
  {"i":"phys-b2-0191","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"In a mass spectrometer, protons first pass undeflected through a velocity selector with crossed fields E = 3.0×10⁵ V/m and B₁ = 0.20 T. They then enter a region of uniform field B₂ = 0.50 T (perpendicular to the velocity) and move in a circle. Using mₚ = 1.67×10⁻²⁷ kg and e = 1.6×10⁻¹⁹ C, what is the radius of the circular path?","o":["About 3.1 cm","About 7.8 cm","About 1.7×10⁻⁵ cm","About 12.5 cm"],"c":0,"e":"The selector passes v = E/B₁ = 3.0×10⁵/0.20 = 1.5×10⁶ m/s. Then r = mₚv/(eB₂) = (1.67×10⁻²⁷·1.5×10⁶)/(1.6×10⁻¹⁹·0.50) ≈ 0.031 m = 3.1 cm."},
  {"i":"phys-b2-0192","g":12,"u":"Fluid Mechanics","d":"impossible","t":"calculation","q":"A large cylindrical water tank of cross-sectional area 0.50 m² has a small hole of area 1.0×10⁻³ m² at its base. The water is initially 1.6 m deep. Treating the flow as ideal (Torricelli's law) and the surface speed as negligible, how long does it take for the tank to drain completely?","o":["About 50 s","About 286 s","About 143 s","About 100 s"],"c":1,"e":"With dH/dt set by continuity and v = √(2gH), integration gives t = (A/a)√(2H/g) = (0.50/1.0×10⁻³)·√(2·1.6/9.8) ≈ 500·0.571 ≈ 286 s."},
  {"i":"phys-b2-0193","g":12,"u":"Electronics","d":"impossible","t":"calculation","q":"An npn transistor in a common-emitter circuit operates in the active region with current gain β = 100 and base current I_B = 40 μA. The collector is supplied by V_CC = 12 V through a collector resistor R_C = 2.0 kΩ. What is the collector–emitter voltage V_CE?","o":["8.0 V","4.0 V","12 V","2.0 V"],"c":1,"e":"Collector current I_C = βI_B = 100·40 μA = 4.0 mA. Then V_CE = V_CC − I_C R_C = 12 − (4.0×10⁻³)(2000) = 12 − 8 = 4.0 V."},
  {"i":"phys-b3-0001","g":9,"u":"Physics & Human Society","d":"easy","t":"definition","q":"Physics is best described as the branch of natural science that studies","o":["the chemical composition of substances","matter, energy, and their interactions","the classification of living organisms","the formation of rocks and minerals"],"c":1,"e":"Physics is the science concerned with matter, energy, and how they interact, including motion, force, heat, sound, light, electricity and magnetism."},
  {"i":"phys-b3-0002","g":9,"u":"Physical Quantities","d":"easy","t":"definition","q":"Which of the following is a base (fundamental) SI unit?","o":["newton","kilogram","joule","watt"],"c":1,"e":"The kilogram is a base SI unit (for mass). The newton, joule and watt are derived units."},
  {"i":"phys-b3-0003","g":9,"u":"Physical Quantities","d":"easy","t":"conceptual","q":"Which set lists only vector quantities?","o":["mass, time, distance","speed, energy, temperature","velocity, force, displacement","work, power, density"],"c":2,"e":"Vectors have both magnitude and direction. Velocity, force and displacement are all vectors; the others listed are scalars."},
  {"i":"phys-b3-0004","g":9,"u":"Motion in a Straight Line","d":"easy","t":"calculation","q":"A bus on the Addis Ababa–Adama road travels 150 km in 3 hours. What is its average speed?","o":["30 km/h","45 km/h","50 km/h","60 km/h"],"c":2,"e":"Average speed = distance ÷ time = 150 km ÷ 3 h = 50 km/h."},
  {"i":"phys-b3-0005","g":9,"u":"Motion in a Straight Line","d":"easy","t":"calculation","q":"A car starting from rest accelerates uniformly at 2 m/s² for 5 s. What is its final velocity?","o":["7 m/s","10 m/s","2.5 m/s","20 m/s"],"c":1,"e":"Using v = u + at with u = 0: v = 0 + (2)(5) = 10 m/s."},
  {"i":"phys-b3-0006","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"calculation","q":"What is the weight of a 5 kg bag of teff on Earth? (g = 9.8 m/s²)","o":["5 N","9.8 N","49 N","98 N"],"c":2,"e":"Weight = mass × g = 5 kg × 9.8 m/s² = 49 N."},
  {"i":"phys-b3-0007","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"application","q":"Newton's first law of motion states that a body remains at rest or in uniform motion unless acted upon by","o":["a balanced set of forces","a net (unbalanced) external force","gravity only","its own internal energy"],"c":1,"e":"Newton's first law (inertia) says motion changes only when a net unbalanced external force acts on the body."},
  {"i":"phys-b3-0008","g":9,"u":"Force, Work, Energy & Power","d":"easy","t":"calculation","q":"A worker pushes a crate with a force of 40 N and moves it 6 m in the direction of the force. How much work is done?","o":["6.7 J","46 J","240 J","120 J"],"c":2,"e":"Work = force × distance = 40 N × 6 m = 240 J."},
  {"i":"phys-b3-0009","g":9,"u":"Simple Machines","d":"easy","t":"calculation","q":"A lever has an effort arm of 2 m and a load arm of 0.5 m. What is its mechanical advantage?","o":["0.25","1.5","2.5","4"],"c":3,"e":"For a lever, MA = effort arm ÷ load arm = 2 m ÷ 0.5 m = 4."},
  {"i":"phys-b3-0010","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"easy","t":"calculation","q":"A pendulum completes one full swing in 0.5 s. What is its frequency?","o":["0.5 Hz","1 Hz","2 Hz","4 Hz"],"c":2,"e":"Frequency = 1 ÷ period = 1 ÷ 0.5 s = 2 Hz."},
  {"i":"phys-b3-0011","g":9,"u":"Temperature & Thermometer","d":"easy","t":"calculation","q":"The boiling point of water is 100 °C. What is this temperature on the Kelvin scale?","o":["100 K","173 K","273 K","373 K"],"c":3,"e":"Kelvin = Celsius + 273, so 100 °C + 273 = 373 K."},
  {"i":"phys-b3-0012","g":9,"u":"Physics & Human Society","d":"medium","t":"conceptual","q":"A team studying soil erosion along the Blue Nile gorge first proposes that vegetation cover slows runoff, then collects rainfall and runoff measurements to check it. In the scientific method, the proposed explanation tested by these measurements is best called the:","o":["Hypothesis","Conclusion","Law","Theory"],"c":0,"e":"A hypothesis is a testable proposed explanation formulated before data collection; the runoff measurements are the test of it. A conclusion comes after, and laws/theories are well-established generalizations."},
  {"i":"phys-b3-0013","g":9,"u":"Physical Quantities","d":"medium","t":"calculation","q":"A water tank used in a Hawassa farm has a volume of 2.5 m³. Expressed in litres (1 m³ = 1000 L), this volume is:","o":["25 L","250 L","2500 L","25000 L"],"c":2,"e":"1 m³ = 1000 L, so 2.5 m³ × 1000 L/m³ = 2500 L."},
  {"i":"phys-b3-0014","g":9,"u":"Physical Quantities","d":"medium","t":"application","q":"A student measures the period of a pendulum five times and gets values clustered tightly around 1.98 s, but the true period is 2.20 s. These measurements are best described as:","o":["Precise but not accurate","Accurate but not precise","Both accurate and precise","Neither accurate nor precise"],"c":0,"e":"Tightly clustered readings indicate high precision, but a consistent offset from the true value (1.98 s vs 2.20 s) means low accuracy."},
  {"i":"phys-b3-0015","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A bus leaving Adama accelerates uniformly from rest to 20 m/s in 8 s. The distance it covers during this time is:","o":["80 m","100 m","160 m","320 m"],"c":0,"e":"With u = 0, average speed = (0+20)/2 = 10 m/s, so s = 10 × 8 = 80 m (equivalently s = ½at² with a = 2.5 m/s²)."},
  {"i":"phys-b3-0016","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A stone is dropped from rest off a bridge over the Awash River and takes 2.0 s to reach the water (g = 9.8 m/s²). Its speed just before impact is:","o":["9.8 m/s","19.6 m/s","39.2 m/s","4.9 m/s"],"c":1,"e":"Starting from rest, v = gt = 9.8 × 2.0 = 19.6 m/s."},
  {"i":"phys-b3-0017","g":9,"u":"Motion in a Straight Line","d":"medium","t":"calculation","q":"A car travelling at 25 m/s brakes and stops after covering 50 m. Assuming uniform deceleration, the magnitude of its acceleration is:","o":["3.125 m/s²","6.25 m/s²","12.5 m/s²","0.5 m/s²"],"c":1,"e":"Using v² = u² + 2as with v = 0: 0 = 25² + 2a(50), so a = -625/100 = -6.25 m/s²; magnitude 6.25 m/s²."},
  {"i":"phys-b3-0018","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A 3.0 kg crate on a frictionless floor is pushed by a net horizontal force of 12 N. Its acceleration is:","o":["2.0 m/s²","4.0 m/s²","9.0 m/s²","36 m/s²"],"c":1,"e":"By Newton's second law, a = F/m = 12 N / 3.0 kg = 4.0 m/s²."},
  {"i":"phys-b3-0019","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A porter at Merkato lifts a 15 kg sack vertically to a shelf 1.6 m high in 4.0 s (g = 9.8 m/s²). The average power he develops is:","o":["6.0 W","58.8 W","235 W","94 W"],"c":1,"e":"Work = mgh = 15 × 9.8 × 1.6 = 235.2 J; power = W/t = 235.2/4.0 = 58.8 W."},
  {"i":"phys-b3-0020","g":9,"u":"Force, Work, Energy & Power","d":"medium","t":"calculation","q":"A 0.50 kg football is kicked and leaves the foot at 8.0 m/s. The change in its momentum from rest is:","o":["2.0 kg·m/s","4.0 kg·m/s","8.0 kg·m/s","16 kg·m/s"],"c":1,"e":"Δp = mΔv = 0.50 kg × (8.0 − 0) m/s = 4.0 kg·m/s."},
  {"i":"phys-b3-0021","g":9,"u":"Simple Machines","d":"medium","t":"calculation","q":"A worker uses a lever to lift a 600 N load by applying 150 N at the end of the effort arm. The mechanical advantage of this lever is:","o":["2","4","0.25","450"],"c":1,"e":"Mechanical advantage = load/effort = 600 N / 150 N = 4."},
  {"i":"phys-b3-0022","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"medium","t":"calculation","q":"A sound wave in air travels at 340 m/s with a frequency of 680 Hz. Its wavelength is:","o":["0.5 m","2.0 m","2 m·s","0.2 m"],"c":0,"e":"From v = fλ, λ = v/f = 340 / 680 = 0.50 m."},
  {"i":"phys-b3-0023","g":9,"u":"Temperature & Thermometer","d":"medium","t":"calculation","q":"On a hot afternoon in Dire Dawa a thermometer reads 35 °C. Converted to the Kelvin scale, this temperature is:","o":["238 K","308 K","298 K","35 K"],"c":1,"e":"T(K) = T(°C) + 273 = 35 + 273 = 308 K."},
  {"i":"phys-b3-0024","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"calculation","q":"A 1200 kg minibus moving at 15 m/s along a level Addis Ababa road collides head-on with a stationary 800 kg car and the two lock together. Assuming momentum is conserved, what is their common speed just after impact?","o":["9 m/s","6 m/s","12 m/s","18 m/s"],"c":0,"e":"Conserving momentum: (1200×15)+0 = (1200+800)v, so v = 18000/2000 = 9 m/s."},
  {"i":"phys-b3-0025","g":9,"u":"Motion in a Straight Line","d":"hard","t":"calculation","q":"A stone is thrown horizontally at 20 m/s from the top of a 19.6 m vertical cliff. Taking g = 9.8 m/s², how far from the base of the cliff does it land?","o":["40 m","20 m","80 m","28 m"],"c":0,"e":"Time of fall: t = √(2h/g) = √(2×19.6/9.8) = 2 s. Horizontal range = 20×2 = 40 m."},
  {"i":"phys-b3-0026","g":9,"u":"Simple Machines","d":"hard","t":"calculation","q":"A loader pushes a 600 N drum up a 5 m long ramp that rises to a height of 2 m, using an effort of 280 N parallel to the ramp. What is the efficiency of this inclined plane?","o":["About 86%","About 100%","About 75%","About 47%"],"c":0,"e":"MA = 600/280 = 2.14; VR = 5/2 = 2.5; efficiency = MA/VR = 2.14/2.5 ≈ 0.857 = 86%."},
  {"i":"phys-b3-0027","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"calculation","q":"A 10 kg crate on a floor is pulled by a horizontal force of 40 N while a constant friction force of 15 N opposes the motion. What is the crate's acceleration?","o":["2.5 m/s²","4.0 m/s²","1.5 m/s²","5.5 m/s²"],"c":0,"e":"Net force = 40 − 15 = 25 N; by Newton's second law a = F/m = 25/10 = 2.5 m/s²."},
  {"i":"phys-b3-0028","g":9,"u":"Motion in a Straight Line","d":"hard","t":"calculation","q":"A car traveling at 25 m/s brakes uniformly and slows to 10 m/s over a distance of 70 m. What is its acceleration?","o":["−3.75 m/s²","−2.5 m/s²","−7.5 m/s²","−1.88 m/s²"],"c":0,"e":"Using v² = u² + 2as: a = (10² − 25²)/(2×70) = (100 − 625)/140 = −525/140 = −3.75 m/s²."},
  {"i":"phys-b3-0029","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"hard","t":"calculation","q":"A simple pendulum has a length of 0.90 m. Taking g = 9.8 m/s², what is its period of oscillation (to two decimal places)?","o":["1.90 s","0.53 s","3.80 s","0.95 s"],"c":0,"e":"T = 2π√(L/g) = 2π√(0.90/9.8) = 2π×0.303 ≈ 1.90 s."},
  {"i":"phys-b3-0030","g":9,"u":"Force, Work, Energy & Power","d":"hard","t":"calculation","q":"A water pump lifts 300 kg of water through a vertical height of 12 m in 40 s. Taking g = 9.8 m/s², what is the useful power output of the pump?","o":["882 W","90 W","35 280 W","441 W"],"c":0,"e":"Useful work = mgh = 300×9.8×12 = 35 280 J; power = work/time = 35 280/40 = 882 W."},
  {"i":"phys-b3-0031","g":9,"u":"Temperature & Thermometer","d":"hard","t":"calculation","q":"On an unmarked thermometer the mercury sits at 20 mm in melting ice and at 170 mm in steam. If, while measuring a patient, the mercury rests at 95 mm, what Celsius temperature does this correspond to?","o":["50 °C","63 °C","56 °C","75 °C"],"c":0,"e":"Linear scale: T = (95 − 20)/(170 − 20) × 100 = 75/150 × 100 = 50 °C."},
  {"i":"phys-b3-0032","g":9,"u":"Physical Quantities","d":"hard","t":"calculation","q":"An astronaut weighs 588 N on Earth (g = 9.8 m/s²). On a planet where g = 3.7 m/s², what would the same astronaut weigh?","o":["222 N","60 N","588 N","1557 N"],"c":0,"e":"Mass = 588/9.8 = 60 kg (unchanged); weight on the planet = 60×3.7 = 222 N."},
  {"i":"phys-b3-0033","g":9,"u":"Motion in a Straight Line","d":"impossible","t":"calculation","q":"From the top of a 14.7 m tower in Bahir Dar, a stone is thrown vertically upward with speed 19.6 m/s. Taking g = 9.8 m/s², how long after release does it strike the ground at the tower's base?","o":["3.0 s","4.0 s","4.65 s","5.3 s"],"c":2,"e":"Taking up positive with displacement −14.7 m: −14.7 = 19.6t − 4.9t², giving t² − 4t − 3 = 0, so t = (4 + √28)/2 ≈ 4.65 s (the positive root)."},
  {"i":"phys-b3-0034","g":9,"u":"Force, Work, Energy & Power","d":"impossible","t":"calculation","q":"A 3 kg block on a frictionless 30° incline is connected by a light cord over a frictionless pulley to a 2 kg block hanging vertically. With g = 9.8 m/s², what is the magnitude of the system's acceleration?","o":["0.98 m/s²","1.96 m/s²","2.94 m/s²","3.92 m/s²"],"c":0,"e":"The 2 kg weight (19.6 N) pulls against the incline component of the 3 kg block (3·9.8·sin30° = 14.7 N). a = (19.6 − 14.7)/(3+2) = 4.9/5 = 0.98 m/s²."},
  {"i":"phys-b3-0035","g":9,"u":"Simple Machines","d":"impossible","t":"application","q":"A first-class lever lifts a 600 N load placed 0.20 m from the fulcrum, with the effort applied 1.0 m from the fulcrum on the other side. If the lever's mechanical efficiency is 80%, what effort force is actually required?","o":["96 N","120 N","150 N","240 N"],"c":2,"e":"Ideal effort balances torques: E·1.0 = 600·0.20, so E_ideal = 120 N. At 80% efficiency the real effort is 120/0.80 = 150 N."},
  {"i":"phys-b3-0036","g":9,"u":"Mechanical Oscillation & Sound Wave","d":"impossible","t":"calculation","q":"A glass tube closed at one end resonates at its fundamental (first) frequency when the air column is 0.17 m long. If the speed of sound in the air is 340 m/s, what is that fundamental frequency?","o":["250 Hz","500 Hz","1000 Hz","2000 Hz"],"c":1,"e":"A pipe closed at one end has fundamental wavelength λ = 4L = 0.68 m. Thus f = v/λ = 340/0.68 = 500 Hz."},
  {"i":"phys-b3-0037","g":10,"u":"Vector Quantities","d":"easy","t":"conceptual","q":"Two forces of 6 N and 8 N act on a body at right angles to each other. What is the magnitude of their resultant?","o":["2 N","10 N","14 N","48 N"],"c":1,"e":"For perpendicular vectors R = √(6² + 8²) = √(36 + 64) = √100 = 10 N."},
  {"i":"phys-b3-0038","g":10,"u":"Vector Quantities","d":"easy","t":"definition","q":"The single vector that has the same effect as two or more vectors combined is called the:","o":["Component","Resultant","Unit vector","Scalar"],"c":1,"e":"The resultant is the single vector whose effect equals the combined effect of the original vectors."},
  {"i":"phys-b3-0039","g":10,"u":"Vector Quantities","d":"easy","t":"calculation","q":"Two displacements of 5 m east and 5 m west are added. What is the magnitude of the resultant displacement?","o":["0 m","5 m","10 m","25 m"],"c":0,"e":"Opposite vectors cancel: 5 m east + 5 m west = 5 − 5 = 0 m."},
  {"i":"phys-b3-0040","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"An object is dropped from rest. Taking g = 9.8 m/s², what is its speed after 2 s?","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"Free fall from rest: v = gt = 9.8 × 2 = 19.6 m/s."},
  {"i":"phys-b3-0041","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A bus moving at 20 m/s brakes to a stop in 4 s. What is its acceleration?","o":["−4 m/s²","−5 m/s²","−16 m/s²","−80 m/s²"],"c":1,"e":"a = (v − u)/t = (0 − 20)/4 = −5 m/s²."},
  {"i":"phys-b3-0042","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A body travels 100 m in 10 s at constant velocity. What is its speed?","o":["1 m/s","5 m/s","10 m/s","100 m/s"],"c":2,"e":"Speed = distance/time = 100/10 = 10 m/s."},
  {"i":"phys-b3-0043","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"conceptual","q":"By Newton's second law, the net force on a 5 kg body accelerating at 3 m/s² is:","o":["1.7 N","8 N","15 N","45 N"],"c":2,"e":"F = ma = 5 × 3 = 15 N."},
  {"i":"phys-b3-0044","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A 2 kg ball moves at 4 m/s. What is its linear momentum?","o":["2 kg·m/s","6 kg·m/s","8 kg·m/s","16 kg·m/s"],"c":2,"e":"Momentum p = mv = 2 × 4 = 8 kg·m/s."},
  {"i":"phys-b3-0045","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"On the moon, the gravitational acceleration is about 1.6 m/s². What is the weight of a 10 kg mass there?","o":["1.6 N","16 N","10 N","98 N"],"c":1,"e":"Weight W = mg = 10 × 1.6 = 16 N."},
  {"i":"phys-b3-0046","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"calculation","q":"A force of 20 N acts at a perpendicular distance of 0.5 m from a pivot. What is the moment of the force?","o":["4 N·m","10 N·m","20 N·m","40 N·m"],"c":1,"e":"Moment = force × perpendicular distance = 20 × 0.5 = 10 N·m."},
  {"i":"phys-b3-0047","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"conceptual","q":"According to Hooke's law, within the elastic limit the extension of a spring is directly proportional to the:","o":["Mass of the spring","Applied force","Length of the wire","Temperature"],"c":1,"e":"Hooke's law: extension is directly proportional to the applied force within the elastic limit."},
  {"i":"phys-b3-0048","g":10,"u":"Static & Current Electricity","d":"easy","t":"calculation","q":"A current of 3 A flows through a resistor of 4 Ω. By Ohm's law, what is the voltage across it?","o":["0.75 V","7 V","12 V","1.33 V"],"c":2,"e":"Ohm's law: V = IR = 3 × 4 = 12 V."},
  {"i":"phys-b3-0049","g":10,"u":"Static & Current Electricity","d":"easy","t":"calculation","q":"A charge of 10 C passes a point in 5 s. What is the electric current?","o":["0.5 A","2 A","15 A","50 A"],"c":1,"e":"Current I = Q/t = 10/5 = 2 A."},
  {"i":"phys-b3-0050","g":10,"u":"Magnetism","d":"easy","t":"conceptual","q":"Like magnetic poles placed near each other will:","o":["Attract","Repel","Neither attract nor repel","Lose magnetism"],"c":1,"e":"Like poles (N–N or S–S) repel each other, while unlike poles attract."},
  {"i":"phys-b3-0051","g":10,"u":"Magnetism","d":"easy","t":"definition","q":"A region around a magnet where its magnetic force can be detected is called the:","o":["Electric field","Magnetic field","Gravitational field","Neutral point"],"c":1,"e":"The magnetic field is the region around a magnet where magnetic force acts."},
  {"i":"phys-b3-0052","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"easy","t":"definition","q":"During reflection of light from a plane mirror, the angle of incidence is always equal to the angle of:","o":["Refraction","Reflection","Deviation","Incidence's double"],"c":1,"e":"The law of reflection states the angle of incidence equals the angle of reflection."},
  {"i":"phys-b3-0053","g":10,"u":"Vector Quantities","d":"easy","t":"conceptual","q":"A displacement vector makes an angle of 60° with the horizontal and has magnitude 20 m. What is its horizontal component?","o":["10 m","17.3 m","20 m","40 m"],"c":0,"e":"The horizontal component is A·cos60° = 20 × 0.5 = 10 m."},
  {"i":"phys-b3-0054","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A car starts from rest and accelerates uniformly at 3 m/s². What is its speed after 5 s?","o":["8 m/s","15 m/s","0.6 m/s","18 m/s"],"c":1,"e":"Using v = u + at with u = 0: v = 0 + 3 × 5 = 15 m/s."},
  {"i":"phys-b3-0055","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A stone is dropped from rest. Taking g = 9.8 m/s², what is its speed after 2 s of free fall?","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"In free fall v = gt = 9.8 × 2 = 19.6 m/s."},
  {"i":"phys-b3-0056","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A bus moving at 20 m/s decelerates uniformly and stops in 4 s. What is the magnitude of its acceleration?","o":["5 m/s²","80 m/s²","4 m/s²","16 m/s²"],"c":0,"e":"a = (v − u)/t = (0 − 20)/4 = −5 m/s²; the magnitude is 5 m/s²."},
  {"i":"phys-b3-0057","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A body travels with uniform acceleration from rest, covering distance using s = ½at². If a = 4 m/s², how far does it travel in 3 s?","o":["12 m","18 m","36 m","6 m"],"c":1,"e":"s = ½ × 4 × 3² = ½ × 4 × 9 = 18 m."},
  {"i":"phys-b3-0058","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"application","q":"A football is kicked vertically upward at 14 m/s (g = 9.8 m/s²). How long does it take to reach its highest point?","o":["1.43 s","0.7 s","2.8 s","14 s"],"c":0,"e":"At the top v = 0, so t = u/g = 14/9.8 ≈ 1.43 s."},
  {"i":"phys-b3-0059","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"Newton's second law gives the force on a 5 kg object accelerating at 2 m/s² as:","o":["2.5 N","10 N","7 N","3 N"],"c":1,"e":"F = ma = 5 × 2 = 10 N."},
  {"i":"phys-b3-0060","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"calculation","q":"A 2 kg ball moving at 6 m/s has linear momentum of:","o":["3 kg·m/s","12 kg·m/s","8 kg·m/s","4 kg·m/s"],"c":1,"e":"Momentum p = mv = 2 × 6 = 12 kg·m/s."},
  {"i":"phys-b3-0061","g":10,"u":"Uniformly Accelerated Motion","d":"easy","t":"definition","q":"Two bodies of mass m are separated by distance r. According to Newton's law of gravitation, if r is doubled, the gravitational force becomes:","o":["Half","One quarter","Double","Four times"],"c":1,"e":"Gravitational force varies as 1/r². Doubling r gives 1/2² = 1/4 of the original force."},
  {"i":"phys-b3-0062","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"calculation","q":"A force of 20 N is applied at the end of a spanner 0.3 m from the bolt, perpendicular to the handle. What is the torque?","o":["6 N·m","60 N·m","0.015 N·m","20.3 N·m"],"c":0,"e":"Torque τ = F × d = 20 × 0.3 = 6 N·m."},
  {"i":"phys-b3-0063","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"easy","t":"application","q":"A spring obeys Hooke's law with spring constant 200 N/m. What force stretches it by 0.05 m?","o":["10 N","4000 N","0.25 N","100 N"],"c":0,"e":"By Hooke's law F = kx = 200 × 0.05 = 10 N."},
  {"i":"phys-b3-0064","g":10,"u":"Static & Current Electricity","d":"easy","t":"calculation","q":"A resistor carries a current of 2 A when connected to a 12 V supply. What is its resistance?","o":["24 Ω","6 Ω","14 Ω","0.17 Ω"],"c":1,"e":"By Ohm's law R = V/I = 12/2 = 6 Ω."},
  {"i":"phys-b3-0065","g":10,"u":"Static & Current Electricity","d":"easy","t":"calculation","q":"If a charge of 30 C flows through a wire in 6 s, what is the current?","o":["180 A","5 A","0.2 A","36 A"],"c":1,"e":"Current I = Q/t = 30/6 = 5 A."},
  {"i":"phys-b3-0066","g":10,"u":"Magnetism","d":"easy","t":"definition","q":"Like magnetic poles brought close together will:","o":["Attract each other","Repel each other","Neither attract nor repel","Lose their magnetism"],"c":1,"e":"Like poles (N–N or S–S) repel, while unlike poles attract."},
  {"i":"phys-b3-0067","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"easy","t":"definition","q":"When light passes from air into water, it bends because its speed changes. This bending is called:","o":["Reflection","Refraction","Dispersion","Diffraction"],"c":1,"e":"Refraction is the bending of light as it changes speed crossing the boundary between two media of different optical density."},
  {"i":"phys-b3-0068","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"A boat in Lake Tana heads due north at 4.0 m/s while the current pushes it due east at 3.0 m/s. What is the magnitude of the boat's resultant velocity relative to the shore?","o":["5.0 m/s","7.0 m/s","1.0 m/s","3.5 m/s"],"c":0,"e":"Perpendicular vectors add by Pythagoras: √(4.0² + 3.0²) = √25 = 5.0 m/s."},
  {"i":"phys-b3-0069","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"Two forces act on a crate at the same point: 6.0 N east and 8.0 N north. What is the magnitude of the single resultant force?","o":["14 N","10 N","2.0 N","48 N"],"c":1,"e":"For perpendicular forces, R = √(6.0² + 8.0²) = √100 = 10 N."},
  {"i":"phys-b3-0070","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"A displacement vector has magnitude 20 m directed at 30° above the horizontal. What is its horizontal (x) component? (cos30° ≈ 0.87)","o":["10 m","17 m","20 m","12 m"],"c":1,"e":"x-component = 20 cos30° = 20 × 0.87 ≈ 17 m."},
  {"i":"phys-b3-0071","g":10,"u":"Vector Quantities","d":"medium","t":"conceptual","q":"A student walks 3 km east, then 4 km west. Which statement correctly compares the distance travelled and the magnitude of the displacement?","o":["Distance 7 km, displacement 1 km","Distance 1 km, displacement 7 km","Distance 7 km, displacement 7 km","Distance 1 km, displacement 1 km"],"c":0,"e":"Distance is the total path = 3 + 4 = 7 km; displacement is the net vector = 4 − 3 = 1 km west."},
  {"i":"phys-b3-0072","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A taxi on a straight road in Addis accelerates uniformly from 5.0 m/s to 15 m/s in 4.0 s. What is its acceleration?","o":["2.5 m/s²","5.0 m/s²","10 m/s²","0.4 m/s²"],"c":0,"e":"a = (v − u)/t = (15 − 5.0)/4.0 = 10/4.0 = 2.5 m/s²."},
  {"i":"phys-b3-0073","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A stone is dropped from rest off a bridge and hits the river 2.0 s later. Using g = 9.8 m/s², how far did it fall?","o":["9.8 m","19.6 m","39.2 m","4.9 m"],"c":1,"e":"h = ½gt² = ½ × 9.8 × (2.0)² = ½ × 9.8 × 4.0 = 19.6 m."},
  {"i":"phys-b3-0074","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A car moving at 20 m/s brakes with a uniform deceleration of 5.0 m/s². How far does it travel before stopping?","o":["80 m","40 m","4.0 m","100 m"],"c":1,"e":"Using v² = u² − 2as with v = 0: s = u²/(2a) = 400/(2×5.0) = 40 m."},
  {"i":"phys-b3-0075","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A ball is thrown straight up at 14.7 m/s. Using g = 9.8 m/s², what maximum height does it reach?","o":["11.0 m","22.1 m","14.7 m","7.4 m"],"c":0,"e":"At the top v = 0, so h = u²/(2g) = (14.7)²/(2×9.8) = 216.09/19.6 ≈ 11.0 m."},
  {"i":"phys-b3-0076","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"application","q":"A horizontal force gives a 2.0 kg block on a frictionless table an acceleration of 3.0 m/s². If the same force acts on a 6.0 kg block, what is its acceleration?","o":["1.0 m/s²","3.0 m/s²","9.0 m/s²","2.0 m/s²"],"c":0,"e":"Force F = ma = 2.0 × 3.0 = 6.0 N. For the 6.0 kg block, a = F/m = 6.0/6.0 = 1.0 m/s²."},
  {"i":"phys-b3-0077","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A 1500 kg minibus experiences a net forward force of 3000 N. What is its acceleration?","o":["0.5 m/s²","2.0 m/s²","4.5 m/s²","1.5 m/s²"],"c":1,"e":"By Newton's second law, a = F/m = 3000/1500 = 2.0 m/s²."},
  {"i":"phys-b3-0078","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A 0.50 kg ball moving at 8.0 m/s is struck and rebounds straight back at 6.0 m/s. What is the magnitude of the change in its momentum?","o":["1.0 kg·m/s","7.0 kg·m/s","3.5 kg·m/s","14 kg·m/s"],"c":1,"e":"Taking the rebound direction as negative: Δp = m(v − u) = 0.50(−6.0 − 8.0) = −7.0 kg·m/s, magnitude 7.0 kg·m/s."},
  {"i":"phys-b3-0079","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"application","q":"A 2.0 kg cart moving at 3.0 m/s collides and sticks to a stationary 1.0 kg cart. What is their common velocity after the collision?","o":["2.0 m/s","1.0 m/s","3.0 m/s","1.5 m/s"],"c":0,"e":"Momentum conservation: (2.0×3.0) = (2.0+1.0)v, so v = 6.0/3.0 = 2.0 m/s."},
  {"i":"phys-b3-0080","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A satellite orbits Earth where g = 8.0 m/s² at radius 7.0×10⁶ m. What speed keeps it in a circular orbit? (use v = √(gr))","o":["7.5×10³ m/s","5.6×10⁷ m/s","2.8×10³ m/s","1.1×10⁴ m/s"],"c":0,"e":"For circular orbit gravity provides centripetal force: v = √(gr) = √(8.0×7.0×10⁶) = √(5.6×10⁷) ≈ 7.5×10³ m/s."},
  {"i":"phys-b3-0081","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A 0.20 kg mass on a string moves in a horizontal circle of radius 0.50 m at 2.0 m/s. What is the centripetal force?","o":["0.80 N","1.6 N","0.40 N","2.0 N"],"c":1,"e":"F = mv²/r = 0.20 × (2.0)²/0.50 = 0.20 × 4.0/0.50 = 1.6 N."},
  {"i":"phys-b3-0082","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A spring obeying Hooke's law stretches 0.040 m when a 12 N force is applied. What is its spring constant?","o":["300 N/m","0.48 N/m","48 N/m","0.0033 N/m"],"c":0,"e":"k = F/x = 12/0.040 = 300 N/m."},
  {"i":"phys-b3-0083","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"application","q":"A uniform 4.0 m plank is balanced on a single pivot at its centre. A 30 N weight sits 1.0 m left of the pivot. Where must a 15 N weight be placed to balance it?","o":["1.0 m to the right","2.0 m to the right","0.5 m to the right","4.0 m to the right"],"c":1,"e":"Balancing torques: 30×1.0 = 15×d, so d = 30/15 = 2.0 m on the opposite side."},
  {"i":"phys-b3-0084","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A force of 20 N is applied at the end of a wrench 0.25 m long, perpendicular to the handle. What torque does it produce about the bolt?","o":["80 N·m","5.0 N·m","0.0125 N·m","45 N·m"],"c":1,"e":"τ = F × r = 20 × 0.25 = 5.0 N·m (force perpendicular to lever arm)."},
  {"i":"phys-b3-0085","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"A resistor carries a current of 0.50 A when connected across a 6.0 V battery. What is its resistance?","o":["3.0 Ω","12 Ω","0.083 Ω","6.5 Ω"],"c":1,"e":"By Ohm's law, R = V/I = 6.0/0.50 = 12 Ω."},
  {"i":"phys-b3-0086","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"Two resistors of 4.0 Ω and 6.0 Ω are connected in parallel. What is their combined resistance?","o":["10 Ω","2.4 Ω","2.0 Ω","24 Ω"],"c":1,"e":"1/R = 1/4.0 + 1/6.0 = 3/12 + 2/12 = 5/12, so R = 12/5 = 2.4 Ω."},
  {"i":"phys-b3-0087","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"An electric stove draws 8.0 A from the 220 V mains. What is its power consumption?","o":["27.5 W","1760 W","228 W","880 W"],"c":1,"e":"P = VI = 220 × 8.0 = 1760 W."},
  {"i":"phys-b3-0088","g":10,"u":"Magnetism","d":"medium","t":"calculation","q":"A straight wire 0.40 m long carries 5.0 A perpendicular to a magnetic field of 0.20 T. What force acts on the wire?","o":["0.40 N","2.5 N","0.10 N","4.0 N"],"c":0,"e":"F = BIL = 0.20 × 5.0 × 0.40 = 0.40 N (current perpendicular to field)."},
  {"i":"phys-b3-0089","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"medium","t":"calculation","q":"Light travels from air into glass of refractive index 1.5. If the angle of incidence is such that sin(i) = 0.60, what is sin(r) in the glass?","o":["0.90","0.40","0.60","0.15"],"c":1,"e":"By Snell's law n₁sin i = n₂sin r: (1.0)(0.60) = (1.5)sin r, so sin r = 0.60/1.5 = 0.40."},
  {"i":"phys-b3-0090","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"A boy in Bahir Dar walks 3 km due east, then 4 km due north. What is the magnitude of his resultant displacement?","o":["7 km","5 km","1 km","12 km"],"c":1,"e":"Perpendicular vectors add by Pythagoras: √(3² + 4²) = √25 = 5 km. The 7 km answer wrongly adds them as scalars."},
  {"i":"phys-b3-0091","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"A force of 20 N acts at 30° above the horizontal. What is its horizontal component? (cos30° = 0.87)","o":["10 N","20 N","17.4 N","11.5 N"],"c":2,"e":"Horizontal component = F cos30° = 20 × 0.87 = 17.4 N. The 10 N answer mistakenly uses sin30°."},
  {"i":"phys-b3-0092","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A car starting from rest accelerates uniformly at 2 m/s² for 5 s. What distance does it cover?","o":["10 m","25 m","50 m","20 m"],"c":1,"e":"s = ut + ½at² = 0 + ½(2)(5²) = ½(2)(25) = 25 m."},
  {"i":"phys-b3-0093","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A stone is dropped from rest from a cliff and hits the ground after 3 s. Taking g = 9.8 m/s², what is its speed just before impact?","o":["29.4 m/s","9.8 m/s","44.1 m/s","3.3 m/s"],"c":0,"e":"v = u + gt = 0 + 9.8 × 3 = 29.4 m/s."},
  {"i":"phys-b3-0094","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A bus moving at 20 m/s brakes uniformly and stops in 50 m. What is the magnitude of its acceleration?","o":["2 m/s²","8 m/s²","4 m/s²","0.4 m/s²"],"c":2,"e":"v² = u² + 2as → 0 = 20² + 2a(50) → a = −400/100 = −4 m/s². Magnitude is 4 m/s²."},
  {"i":"phys-b3-0095","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A ball is thrown vertically upward at 19.6 m/s. Using g = 9.8 m/s², what maximum height does it reach?","o":["19.6 m","39.2 m","9.8 m","4.9 m"],"c":0,"e":"At the top v = 0: v² = u² − 2gh → 0 = 19.6² − 2(9.8)h → h = 384.16/19.6 = 19.6 m."},
  {"i":"phys-b3-0096","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"application","q":"A 2 kg block on a frictionless surface is pushed by a constant 10 N force. What is its acceleration?","o":["20 m/s²","0.2 m/s²","5 m/s²","12 m/s²"],"c":2,"e":"By Newton's second law a = F/m = 10/2 = 5 m/s²."},
  {"i":"phys-b3-0097","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A 0.5 kg ball moving at 4 m/s is brought to rest in 0.2 s by a wall. What average force does the wall exert?","o":["2 N","10 N","0.4 N","20 N"],"c":1,"e":"F = Δp/Δt = m(v−u)/t = 0.5(0−4)/0.2 = −2/0.2 = −10 N. Magnitude 10 N."},
  {"i":"phys-b3-0098","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A 3 kg trolley moving at 4 m/s collides and sticks to a 1 kg stationary trolley. What is their common velocity after collision?","o":["3 m/s","4 m/s","1 m/s","2 m/s"],"c":0,"e":"Momentum conserved: (3)(4) = (3+1)v → 12 = 4v → v = 3 m/s."},
  {"i":"phys-b3-0099","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"application","q":"A 60 kg student climbs a staircase of vertical height 5 m in 10 s. Using g = 9.8 m/s², what is the power developed?","o":["30 W","294 W","2940 W","147 W"],"c":1,"e":"P = mgh/t = (60 × 9.8 × 5)/10 = 2940/10 = 294 W."},
  {"i":"phys-b3-0100","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A 0.2 kg stone is whirled in a horizontal circle of radius 0.5 m at a constant speed of 4 m/s. What is the centripetal force?","o":["1.6 N","3.2 N","6.4 N","0.4 N"],"c":2,"e":"F = mv²/r = 0.2 × 4²/0.5 = 0.2 × 16/0.5 = 3.2/0.5 = 6.4 N."},
  {"i":"phys-b3-0101","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"application","q":"The acceleration due to gravity on the Moon is about 1.6 m/s². What is the weight of a 50 kg sack of teff on the Moon?","o":["490 N","80 N","50 N","31 N"],"c":1,"e":"Weight W = mg = 50 × 1.6 = 80 N."},
  {"i":"phys-b3-0102","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A wire stretches 2 mm under a 40 N load within its elastic limit. How much will it stretch under a 100 N load?","o":["5 mm","2.5 mm","4 mm","8 mm"],"c":0,"e":"By Hooke's law extension is proportional to load: e = 2 mm × (100/40) = 5 mm."},
  {"i":"phys-b3-0103","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A uniform beam is in equilibrium on a pivot. A 30 N weight sits 0.4 m left of the pivot. At what distance right of the pivot must a 20 N weight be placed to balance it?","o":["0.6 m","0.4 m","0.3 m","1.2 m"],"c":0,"e":"Balancing moments: 30 × 0.4 = 20 × d → 12 = 20d → d = 0.6 m."},
  {"i":"phys-b3-0104","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A force of 50 N is applied at the end of a spanner 0.25 m long, perpendicular to it. What turning moment is produced about the bolt?","o":["200 N·m","12.5 N·m","25 N·m","2 N·m"],"c":1,"e":"Moment = force × perpendicular distance = 50 × 0.25 = 12.5 N·m."},
  {"i":"phys-b3-0105","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"A resistor carries a current of 2 A when connected across a 12 V supply. What is its resistance?","o":["24 Ω","6 Ω","10 Ω","0.17 Ω"],"c":1,"e":"By Ohm's law R = V/I = 12/2 = 6 Ω."},
  {"i":"phys-b3-0106","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"Two resistors of 4 Ω and 6 Ω are connected in series across a 20 V battery. What current flows in the circuit?","o":["5 A","2 A","8 A","0.5 A"],"c":1,"e":"Series total R = 4 + 6 = 10 Ω; I = V/R = 20/10 = 2 A."},
  {"i":"phys-b3-0107","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"An electric mitad (stove) rated 1100 W operates on a 220 V mains supply. What current does it draw?","o":["5 A","0.2 A","2.42 A","10 A"],"c":0,"e":"P = VI → I = P/V = 1100/220 = 5 A."},
  {"i":"phys-b3-0108","g":10,"u":"Magnetism","d":"medium","t":"calculation","q":"A wire of length 0.5 m carrying a current of 4 A lies perpendicular to a magnetic field of 0.2 T. What force acts on the wire?","o":["0.4 N","0.1 N","2.5 N","1.6 N"],"c":0,"e":"F = BIL = 0.2 × 4 × 0.5 = 0.4 N (wire perpendicular to field, so sinθ = 1)."},
  {"i":"phys-b3-0109","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"medium","t":"calculation","q":"A ray of light passes from air into glass of refractive index 1.5, striking the surface at an angle of incidence of 30°. What is the sine of the angle of refraction? (sin30° = 0.5)","o":["0.75","0.33","0.50","0.66"],"c":1,"e":"By Snell's law n = sin i / sin r → sin r = sin30°/1.5 = 0.5/1.5 = 0.33."},
  {"i":"phys-b3-0110","g":10,"u":"Uniformly Accelerated Motion","d":"medium","t":"calculation","q":"A bus leaving Meskel Square accelerates uniformly from rest and reaches 18 m/s after travelling 54 m. What is the magnitude of its acceleration?","o":["3.0 m/s²","6.0 m/s²","2.0 m/s²","9.0 m/s²"],"c":0,"e":"Using v² = u² + 2as with u = 0: a = v²/(2s) = 18²/(2×54) = 324/108 = 3.0 m/s²."},
  {"i":"phys-b3-0111","g":10,"u":"Vector Quantities","d":"medium","t":"calculation","q":"A farmer pulls a load with two ropes in the same horizontal plane: one exerts 30 N due east, the other 40 N due north. What is the magnitude of the resultant force?","o":["35 N","70 N","50 N","10 N"],"c":2,"e":"The forces are perpendicular, so the resultant is √(30² + 40²) = √(900 + 1600) = √2500 = 50 N."},
  {"i":"phys-b3-0112","g":10,"u":"Static & Current Electricity","d":"medium","t":"calculation","q":"A resistor in a torch circuit carries a current of 0.50 A when connected across a 1.5 V cell. How much charge flows through it in 2.0 minutes, and what is its resistance?","o":["60 C and 3.0 Ω","30 C and 0.75 Ω","60 C and 0.75 Ω","15 C and 3.0 Ω"],"c":0,"e":"Charge Q = It = 0.50 × (2.0×60) = 60 C; resistance R = V/I = 1.5/0.50 = 3.0 Ω."},
  {"i":"phys-b3-0113","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"medium","t":"calculation","q":"A uniform 4.0 m plank weighing 200 N rests on two supports, one at each end. A 300 N sack sits 1.0 m from the left support. What is the upward force on the left support?","o":["325 N","275 N","250 N","175 N"],"c":0,"e":"Taking moments about the right support: F_left×4.0 = 200×2.0 + 300×3.0 = 400 + 900 = 1300, so F_left = 1300/4.0 = 325 N."},
  {"i":"phys-b3-0114","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"A delivery drone over Addis flies 30 m east, then 40 m north, then 30 m west. What is the magnitude of its total displacement from the start?","o":["40 m","50 m","100 m","70 m"],"c":0,"e":"East and west cancel (30−30=0), leaving 40 m north, so displacement = 40 m."},
  {"i":"phys-b3-0115","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"Two forces of 12 N and 16 N act on a body at a point with a 90° angle between them. What single force balances them (equilibrant)?","o":["20 N opposite the resultant","28 N along the resultant","4 N opposite the resultant","20 N along the resultant"],"c":0,"e":"Resultant = √(12²+16²) = √400 = 20 N; the equilibrant equals 20 N but acts opposite to the resultant."},
  {"i":"phys-b3-0116","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"A vector of magnitude 25 N makes 53° with the x-axis (sin53°=0.8, cos53°=0.6). What are its x and y components?","o":["x=15 N, y=20 N","x=20 N, y=15 N","x=12.5 N, y=21.65 N","x=25 N, y=0 N"],"c":0,"e":"Fx = 25cos53° = 25(0.6) = 15 N; Fy = 25sin53° = 25(0.8) = 20 N."},
  {"i":"phys-b3-0117","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"Two displacement vectors, 10 m and 10 m, give a resultant of magnitude 10 m. What is the angle between them?","o":["120°","60°","90°","45°"],"c":0,"e":"R² = A²+B²+2AB cosθ → 100 = 100+100+200cosθ → cosθ = −0.5 → θ = 120°."},
  {"i":"phys-b3-0118","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A car on the Addis–Adama road accelerates uniformly from 10 m/s to 30 m/s over 200 m. What is its acceleration?","o":["2 m/s²","4 m/s²","1 m/s²","20 m/s²"],"c":0,"e":"v² = u²+2as → 900 = 100+2a(200) → 800 = 400a → a = 2 m/s²."},
  {"i":"phys-b3-0119","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A stone is thrown straight up at 19.6 m/s (g=9.8 m/s²). What total time elapses before it returns to the throwing height?","o":["4 s","2 s","8 s","3 s"],"c":0,"e":"Time up = u/g = 19.6/9.8 = 2 s; total time = 2 × 2 = 4 s."},
  {"i":"phys-b3-0120","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A ball is projected horizontally at 15 m/s from a 19.6 m high cliff (g=9.8 m/s²). How far horizontally does it land from the base?","o":["30 m","15 m","45 m","20 m"],"c":0,"e":"Fall time: 19.6 = ½(9.8)t² → t² = 4 → t = 2 s; range = 15 × 2 = 30 m."},
  {"i":"phys-b3-0121","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A 2 kg block is pulled along a rough floor by a 20 N horizontal force; friction is 8 N. What is the block's acceleration?","o":["6 m/s²","10 m/s²","14 m/s²","4 m/s²"],"c":0,"e":"Net force = 20 − 8 = 12 N; a = F/m = 12/2 = 6 m/s²."},
  {"i":"phys-b3-0122","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A 0.5 kg ball moving at 8 m/s is struck and rebounds at 6 m/s in the opposite direction. What is the magnitude of the impulse on it?","o":["7 kg·m/s","1 kg·m/s","4 kg·m/s","14 kg·m/s"],"c":0,"e":"Impulse = Δp = m(v−u) = 0.5(−6 − 8) = −7 kg·m/s; magnitude 7 kg·m/s."},
  {"i":"phys-b3-0123","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A 3 kg trolley moving at 4 m/s collides and sticks to a stationary 1 kg trolley. What is their common velocity after impact?","o":["3 m/s","4 m/s","1 m/s","2 m/s"],"c":0,"e":"Conservation of momentum: 3(4)+0 = (3+1)v → 12 = 4v → v = 3 m/s."},
  {"i":"phys-b3-0124","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A satellite orbits at radius r with speed v. If it moves to radius 4r around the same planet, its orbital speed becomes:","o":["v/2","2v","v/4","4v"],"c":0,"e":"v = √(GM/r), so v ∝ 1/√r; at 4r, speed = v/√4 = v/2."},
  {"i":"phys-b3-0125","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A 0.2 kg ball is whirled in a horizontal circle of radius 0.5 m at 4 m/s. What centripetal force is needed?","o":["6.4 N","3.2 N","1.6 N","12.8 N"],"c":0,"e":"F = mv²/r = 0.2(16)/0.5 = 3.2/0.5 = 6.4 N."},
  {"i":"phys-b3-0126","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A wheel starting from rest reaches 12 rad/s in 4 s with constant angular acceleration. Through what angle does it turn in that time?","o":["24 rad","48 rad","12 rad","6 rad"],"c":0,"e":"α = 12/4 = 3 rad/s²; θ = ½αt² = ½(3)(16) = 24 rad."},
  {"i":"phys-b3-0127","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A uniform 4 m beam weighing 200 N rests on two supports at its ends. A 100 N load sits 1 m from the left support. What force does the left support exert?","o":["175 N","125 N","100 N","150 N"],"c":0,"e":"Taking torques about right support: R_L(4) = 200(2) + 100(3) = 700 → R_L = 175 N."},
  {"i":"phys-b3-0128","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A wire of original length 2 m and cross-sectional area 1×10⁻⁶ m² stretches 1 mm under a 100 N load. What is its Young's modulus?","o":["2×10¹¹ Pa","1×10¹¹ Pa","5×10¹⁰ Pa","4×10¹¹ Pa"],"c":0,"e":"Y = (F/A)/(ΔL/L) = (100/1e−6)/(0.001/2) = 1e8 / 5e−4 = 2×10¹¹ Pa."},
  {"i":"phys-b3-0129","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A spring obeying Hooke's law stretches 4 cm under 20 N. How much elastic potential energy is stored at this stretch?","o":["0.4 J","0.8 J","0.04 J","8 J"],"c":0,"e":"k = F/x = 20/0.04 = 500 N/m; E = ½kx² = ½(500)(0.04²) = ½(500)(0.0016) = 0.4 J."},
  {"i":"phys-b3-0130","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"Two point charges of +4 μC and +9 μC are 5 cm apart in air (k=9×10⁹). What is the force between them?","o":["129.6 N","64.8 N","259.2 N","12.96 N"],"c":0,"e":"F = kq₁q₂/r² = 9e9(4e−6)(9e−6)/(0.05²) = 9e9(36e−12)/0.0025 = 0.324/0.0025 = 129.6 N."},
  {"i":"phys-b3-0131","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"Three resistors, 6 Ω and 3 Ω in parallel, then in series with 4 Ω, connect across 12 V. What is the total current?","o":["2 A","1 A","3 A","0.5 A"],"c":0,"e":"Parallel: (6×3)/(6+3) = 2 Ω; total = 2+4 = 6 Ω; I = 12/6 = 2 A."},
  {"i":"phys-b3-0132","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"A 60 W bulb operates on a 220 V supply for 5 hours. How much electrical energy does it use, in kWh?","o":["0.3 kWh","0.6 kWh","3 kWh","0.06 kWh"],"c":0,"e":"Energy = power × time = 0.060 kW × 5 h = 0.3 kWh."},
  {"i":"phys-b3-0133","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"A battery of emf 12 V and internal resistance 0.5 Ω drives a 5.5 Ω external resistor. What is the terminal voltage?","o":["11 V","12 V","1 V","6 V"],"c":0,"e":"I = 12/(5.5+0.5) = 2 A; terminal V = emf − Ir = 12 − 2(0.5) = 11 V."},
  {"i":"phys-b3-0134","g":10,"u":"Magnetism","d":"hard","t":"calculation","q":"A 0.4 m wire carrying 5 A lies perpendicular to a 0.2 T magnetic field. What force acts on the wire?","o":["0.4 N","2 N","0.04 N","4 N"],"c":0,"e":"F = BIL = 0.2 × 5 × 0.4 = 0.4 N (sin90° = 1)."},
  {"i":"phys-b3-0135","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"hard","t":"calculation","q":"Light travels from air into a medium of refractive index 1.5, striking the surface at 30° to the normal. What is the angle of refraction (sin30°=0.5)?","o":["≈19.5°","30°","45°","≈48.6°"],"c":0,"e":"n₁sinθ₁ = n₂sinθ₂ → sinθ₂ = (1×0.5)/1.5 = 0.333 → θ₂ ≈ 19.5°."},
  {"i":"phys-b3-0136","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"A boat heads straight across the Abay (Blue Nile) pointing due north at 3.0 m/s relative to the water, while the current flows due east at 4.0 m/s. What is the boat's speed relative to the bank and the angle of its actual path measured from the north (upstream-to-bank) direction?","o":["5.0 m/s, 37 deg east of north","5.0 m/s, 53 deg east of north","7.0 m/s, 37 deg east of north","1.0 m/s, 53 deg east of north"],"c":1,"e":"Resultant speed = sqrt(3.0^2 + 4.0^2) = 5.0 m/s. The angle from north satisfies tan(theta) = 4.0/3.0, so theta = 53 deg east of north."},
  {"i":"phys-b3-0137","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A minibus on the Addis Ababa ring road is moving at 25 m/s when the driver brakes uniformly, stopping in exactly 50 m. How long does the minibus take to stop?","o":["2.0 s","4.0 s","5.0 s","8.0 s"],"c":1,"e":"From v^2 = u^2 + 2as: 0 = 25^2 + 2a(50), so a = -6.25 m/s^2. Then t = (0 - 25)/(-6.25) = 4.0 s."},
  {"i":"phys-b3-0138","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A stone is dropped from rest off a bridge over the Awash River. Taking g = 9.8 m/s^2, what distance does it fall during the 3rd second of its motion alone (not the total in 3 s)?","o":["14.7 m","19.6 m","24.5 m","44.1 m"],"c":2,"e":"Distance in the nth second = (g/2)(2n - 1) = (9.8/2)(2x3 - 1) = 4.9 x 5 = 24.5 m."},
  {"i":"phys-b3-0139","g":10,"u":"Uniformly Accelerated Motion","d":"hard","t":"calculation","q":"A ball is kicked from the ground at 19.6 m/s at 30 deg above the horizontal on a flat field. Using g = 9.8 m/s^2, what are its time of flight and horizontal range?","o":["1.0 s and 17 m","2.0 s and 34 m","2.0 s and 17 m","4.0 s and 68 m"],"c":1,"e":"v_y = 19.6 sin30 = 9.8 m/s, so T = 2v_y/g = 2.0 s. v_x = 19.6 cos30 = 16.97 m/s, giving range = 16.97 x 2.0 = 34 m."},
  {"i":"phys-b3-0140","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"A 5.0 kg crate slides down a ramp inclined at 30 deg to the horizontal. The coefficient of kinetic friction between crate and ramp is 0.20. Using g = 9.8 m/s^2, what is the crate's acceleration down the ramp?","o":["1.7 m/s^2","3.2 m/s^2","4.9 m/s^2","6.6 m/s^2"],"c":1,"e":"a = g(sin30 - mu cos30) = 9.8(0.500 - 0.20 x 0.866) = 9.8 x 0.327 = 3.2 m/s^2. Mass cancels out."},
  {"i":"phys-b3-0141","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"A 1200 kg car moving at 20 m/s strikes a stationary 800 kg car and they lock together. What is their common velocity just after the perfectly inelastic collision?","o":["8.0 m/s","10 m/s","12 m/s","16 m/s"],"c":2,"e":"Momentum is conserved: v = (1200 x 20 + 800 x 0)/(1200 + 800) = 24000/2000 = 12 m/s."},
  {"i":"phys-b3-0142","g":10,"u":"Vector Quantities","d":"hard","t":"calculation","q":"A 1000 kg car rounds a flat, unbanked curve of radius 50 m where the coefficient of static friction with the road is 0.40. Taking g = 9.8 m/s^2, what is the maximum speed at which it can take the curve without skidding?","o":["7.0 m/s","10 m/s","14 m/s","20 m/s"],"c":2,"e":"Friction supplies the centripetal force: mu mg = mv^2/r, so v = sqrt(mu g r) = sqrt(0.40 x 9.8 x 50) = sqrt(196) = 14 m/s."},
  {"i":"phys-b3-0143","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A uniform horizontal beam 4.0 m long weighs 200 N and rests on two supports, one at each end. A 300 N sack of teff is placed 3.0 m from the left support. What is the upward force exerted by the right support?","o":["225 N","275 N","325 N","400 N"],"c":2,"e":"Take torques about the left support: R x 4.0 = 200 x 2.0 + 300 x 3.0 = 1300, so R = 325 N."},
  {"i":"phys-b3-0144","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"hard","t":"calculation","q":"A steel wire of original length 2.0 m and cross-sectional area 1.0 x 10^-6 m^2 has Young's modulus 2.0 x 10^11 Pa. By how much does it stretch when a load producing 100 N of tension is hung from it?","o":["0.5 mm","1.0 mm","2.0 mm","4.0 mm"],"c":1,"e":"Extension = FL/(AY) = (100 x 2.0)/(1.0e-6 x 2.0e11) = 200/2.0e5 = 1.0 x 10^-3 m = 1.0 mm."},
  {"i":"phys-b3-0145","g":10,"u":"Static & Current Electricity","d":"hard","t":"calculation","q":"A 6.0 ohm and a 3.0 ohm resistor are connected in parallel, and this combination is in series with a 4.0 ohm resistor across a 12 V battery of negligible internal resistance. What is the current through the 3.0 ohm resistor?","o":["0.67 A","1.3 A","2.0 A","3.0 A"],"c":1,"e":"Parallel pair = (6x3)/(6+3) = 2.0 ohm; total = 6.0 ohm; total current = 12/6 = 2.0 A. Voltage across the pair = 2.0 x 2.0 = 4.0 V, so current in the 3.0 ohm = 4.0/3.0 = 1.3 A."},
  {"i":"phys-b3-0146","g":10,"u":"Static & Current Electricity","d":"hard","t":"application","q":"A household electric mitad (injera stove) rated 2000 W is used for 3 hours each day for 5 days. If the EEU tariff is 0.50 birr per kilowatt-hour, what is the total cost of the energy used?","o":["7.50 birr","15.0 birr","30.0 birr","150 birr"],"c":1,"e":"Energy = 2.0 kW x 3 h x 5 = 30 kWh. Cost = 30 x 0.50 = 15.0 birr."},
  {"i":"phys-b3-0147","g":10,"u":"Magnetism","d":"hard","t":"calculation","q":"A straight wire of length 0.20 m carries a current of 4.0 A and lies in a uniform magnetic field of 0.50 T, with the wire making a 30 deg angle to the field direction. What is the magnitude of the magnetic force on the wire?","o":["0.20 N","0.40 N","0.69 N","0.80 N"],"c":0,"e":"F = BIL sin(theta) = 0.50 x 4.0 x 0.20 x sin30 = 0.40 x 0.50 = 0.20 N."},
  {"i":"phys-b3-0148","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"hard","t":"calculation","q":"An object is placed 20 cm in front of a concave mirror of focal length 15 cm. What is the image distance and the magnification?","o":["60 cm, magnification 3 (inverted)","60 cm, magnification 0.33 (upright)","8.6 cm, magnification 0.43 (upright)","12 cm, magnification 0.6 (inverted)"],"c":0,"e":"1/v = 1/f - 1/u = 1/15 - 1/20 = 1/60, so v = 60 cm. Magnification = v/u = 60/20 = 3, image inverted and real."},
  {"i":"phys-b3-0149","g":10,"u":"Vector Quantities","d":"impossible","t":"calculation","q":"A drone over Bahir Dar flies 60 m on bearing 030°, then 80 m on bearing 120°, then 50 m on bearing 270° (due west). What is the magnitude of its net displacement from the start?","o":["50.7 m","61.0 m","100.0 m","42.3 m"],"c":0,"e":"With east = sin(bearing), north = cos(bearing): E = 60sin30 + 80sin120 + 50sin270 = 30 + 69.28 − 50 = 49.28; N = 60cos30 + 80cos120 + 50cos270 = 51.96 − 40 + 0 = 11.96. Magnitude = √(49.28² + 11.96²) = √2571.5 ≈ 50.7 m."},
  {"i":"phys-b3-0150","g":10,"u":"Vector Quantities","d":"impossible","t":"calculation","q":"Two forces act at a point in Adama: 12 N at 50° and 18 N at 140° (measured from the +x axis). The single force needed to hold the point in equilibrium has magnitude closest to:","o":["21.6 N","30.0 N","6.0 N","15.0 N"],"c":0,"e":"Rx = 12cos50 + 18cos140 = 7.71 − 13.79 = −6.08; Ry = 12sin50 + 18sin140 = 9.19 + 11.57 = 20.76. |R| = √(6.08²+20.76²) = √467.9 ≈ 21.6 N; the equilibrant has the same magnitude, opposite direction."},
  {"i":"phys-b3-0151","g":10,"u":"Uniformly Accelerated Motion","d":"impossible","t":"calculation","q":"A ball is thrown vertically up at 24.5 m/s from a 19.6 m cliff edge in Gondar (g = 9.8 m/s²). How long after launch does it strike the ground at the cliff base?","o":["5.70 s","4.00 s","6.00 s","2.50 s"],"c":0,"e":"Up positive, ground at −19.6 m: −19.6 = 24.5t − 4.9t² → t² − 5t − 4 = 0 → t = (5 + √41)/2 = (5 + 6.403)/2 = 5.70 s."},
  {"i":"phys-b3-0152","g":10,"u":"Uniformly Accelerated Motion","d":"impossible","t":"calculation","q":"Two stones are dropped down a deep well from the same point, the second released 1.0 s after the first. At the instant the first has been falling for 3.0 s, what is the separation between them? (g = 9.8 m/s²)","o":["24.5 m","44.1 m","19.6 m","29.4 m"],"c":0,"e":"First (3.0 s): y₁ = ½·9.8·9 = 44.1 m. Second (2.0 s): y₂ = ½·9.8·4 = 19.6 m. Separation = 44.1 − 19.6 = 24.5 m."},
  {"i":"phys-b3-0153","g":10,"u":"Uniformly Accelerated Motion","d":"impossible","t":"calculation","q":"A car on the Addis–Adama expressway accelerates uniformly from rest and covers 24 m during the 4th second of its motion. What is its acceleration?","o":["6.86 m/s²","3.00 m/s²","6.00 m/s²","12.0 m/s²"],"c":0,"e":"Distance in the nth second = a(2n−1)/2. For n = 4: 24 = a(7)/2 = 3.5a → a = 24/3.5 = 6.86 m/s²."},
  {"i":"phys-b3-0154","g":10,"u":"Uniformly Accelerated Motion","d":"impossible","t":"application","q":"A 0.50 kg ball moving at 8.0 m/s strikes a wall in Hawassa and rebounds at 6.0 m/s along the same line; contact lasts 0.020 s. What is the average force the wall exerts on the ball?","o":["350 N","50 N","100 N","700 N"],"c":0,"e":"Taking the incoming direction positive: Δp = 0.50(−6.0 − 8.0) = −7.0 kg·m/s. F = Δp/Δt = 7.0/0.020 = 350 N, directed away from the wall."},
  {"i":"phys-b3-0155","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"impossible","t":"calculation","q":"A uniform 40 N beam of length 4.0 m rests on two supports: one at the left end (x = 0) and one at x = 3.0 m. A 60 N load hangs at x = 3.5 m. What upward force does the right support (at x = 3.0 m) exert?","o":["96.7 N","53.3 N","70.0 N","40.0 N"],"c":0,"e":"Torques about the left end: N_right·3.0 = 40·2.0 (weight at the 2.0 m centre) + 60·3.5 = 80 + 210 = 290 → N_right = 290/3.0 = 96.7 N."},
  {"i":"phys-b3-0156","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"impossible","t":"calculation","q":"A steel wire 2.0 m long with cross-sectional area 1.0 mm² stretches by 1.0 mm under a 100 N load. What is Young's modulus of the steel?","o":["2.0 × 10¹¹ Pa","1.0 × 10¹¹ Pa","2.0 × 10⁹ Pa","5.0 × 10¹⁰ Pa"],"c":0,"e":"Y = (F·L)/(A·ΔL) = (100·2.0)/(1.0×10⁻⁶·1.0×10⁻³) = 200/(1.0×10⁻⁹) = 2.0×10¹¹ Pa."},
  {"i":"phys-b3-0157","g":10,"u":"Elasticity & Static Equilibrium of Rigid Body","d":"impossible","t":"conceptual","q":"A uniform ladder leans against a frictionless wall on a rough floor (coefficient μ) at angle θ to the floor. The minimum angle at which it will not slip satisfies:","o":["tan θ = 1/(2μ)","tan θ = 2μ","tan θ = μ","tan θ = 1/μ"],"c":0,"e":"Vertical: N_floor = W. Wall is frictionless, so horizontal: f = N_wall. Torque about the base: N_wall = W/(2 tan θ). No-slip needs f ≤ μN_floor → W/(2 tan θ) ≤ μW → tan θ ≥ 1/(2μ); minimum angle satisfies tan θ = 1/(2μ)."},
  {"i":"phys-b3-0158","g":10,"u":"Static & Current Electricity","d":"impossible","t":"calculation","q":"A 6 Ω and a 3 Ω resistor are in parallel; that combination is in series with a 2 Ω resistor, across a 12 V battery of internal resistance 0.5 Ω. What current flows from the battery?","o":["2.67 A","3.00 A","2.00 A","1.33 A"],"c":0,"e":"Parallel: (6·3)/(6+3) = 2 Ω. Total = 2 + 2 + 0.5 = 4.5 Ω. I = 12/4.5 = 2.67 A."},
  {"i":"phys-b3-0159","g":10,"u":"Static & Current Electricity","d":"impossible","t":"calculation","q":"Point charges +4 μC and −1 μC are fixed 30 cm apart. At what point on the line through them is the net electric field zero?","o":["30 cm beyond the −1 μC charge (on the side away from +4 μC)","Midway between the charges","20 cm from the +4 μC charge, between them","10 cm from the −1 μC charge, between them"],"c":0,"e":"A null can only lie beyond the smaller (negative) charge. Let d be the distance from the −1 μC charge: k·4/(d+0.30)² = k·1/d² → 2d = d + 0.30 → d = 0.30 m, i.e. 30 cm beyond the −1 μC charge."},
  {"i":"phys-b3-0160","g":10,"u":"Magnetism","d":"impossible","t":"calculation","q":"A proton enters a uniform 0.20 T field perpendicular to it at 3.0 × 10⁶ m/s (m = 1.67 × 10⁻²⁷ kg, q = 1.6 × 10⁻¹⁹ C). What is the radius of its circular path?","o":["0.157 m","0.31 m","0.078 m","1.57 m"],"c":0,"e":"r = mv/(qB) = (1.67×10⁻²⁷·3.0×10⁶)/(1.6×10⁻¹⁹·0.20) = (5.01×10⁻²¹)/(3.2×10⁻²⁰) = 0.157 m."},
  {"i":"phys-b3-0161","g":10,"u":"Magnetism","d":"impossible","t":"application","q":"A straight 0.40 m conductor carrying 5.0 A lies at 30° to a uniform 0.50 T magnetic field. What is the magnitude of the force on the conductor?","o":["0.50 N","1.0 N","0.87 N","0.25 N"],"c":0,"e":"F = BIL sinθ = 0.50·5.0·0.40·sin30° = 1.0·0.5 = 0.50 N."},
  {"i":"phys-b3-0162","g":10,"u":"Electromagnetic Waves & Geometrical Optics","d":"impossible","t":"calculation","q":"For light travelling from a layer of oil into water (n_water = 1.33), the critical angle for total internal reflection at the oil–water boundary is 65°. What is the refractive index of the oil?","o":["1.47","1.21","1.33","1.10"],"c":0,"e":"At the critical angle from the denser medium (oil): n_oil sinθc = n_water sin90° → n_oil = 1.33/sin65° = 1.33/0.9063 = 1.47."},
  {"i":"phys-b3-0163","g":11,"u":"Physics & Human Society","d":"easy","t":"definition","q":"Physics is best described as the branch of science that studies","o":["the chemical reactions of living cells","matter, energy, and their interactions","the classification of living organisms","the composition of rocks and minerals"],"c":1,"e":"Physics is the study of matter, energy, and the interactions between them."},
  {"i":"phys-b3-0164","g":11,"u":"Physics & Human Society","d":"easy","t":"conceptual","q":"Which of the following is a direct application of physics in modern medical diagnosis?","o":["Blood-type testing","X-ray imaging","DNA sequencing","Soil fertility testing"],"c":1,"e":"X-ray imaging uses electromagnetic radiation, a physics principle, to view internal structures of the body."},
  {"i":"phys-b3-0165","g":11,"u":"Vectors","d":"easy","t":"definition","q":"A quantity that has both magnitude and direction is called a","o":["scalar quantity","vector quantity","base quantity","derived unit"],"c":1,"e":"A vector quantity has both magnitude and direction; a scalar has magnitude only."},
  {"i":"phys-b3-0166","g":11,"u":"Vectors","d":"easy","t":"calculation","q":"Two perpendicular forces of 3 N and 4 N act on a point. The magnitude of their resultant is","o":["5 N","7 N","1 N","12 N"],"c":0,"e":"For perpendicular vectors R = √(3² + 4²) = √25 = 5 N."},
  {"i":"phys-b3-0167","g":11,"u":"Vectors","d":"easy","t":"conceptual","q":"Which of the following is a scalar quantity?","o":["Velocity","Displacement","Mass","Acceleration"],"c":2,"e":"Mass has only magnitude, so it is a scalar; the others have direction and are vectors."},
  {"i":"phys-b3-0168","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A car moving in a straight line covers 150 m in 10 s at constant speed. Its speed is","o":["15 m/s","1500 m/s","10 m/s","0.067 m/s"],"c":0,"e":"Speed = distance/time = 150/10 = 15 m/s."},
  {"i":"phys-b3-0169","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A body starts from rest and accelerates uniformly at 2 m/s². Its velocity after 5 s is","o":["10 m/s","7 m/s","2.5 m/s","0.4 m/s"],"c":0,"e":"v = u + at = 0 + 2 × 5 = 10 m/s."},
  {"i":"phys-b3-0170","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"application","q":"An object is dropped from rest near the Earth's surface. After 2 s its speed is (g = 9.8 m/s²)","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"v = gt = 9.8 × 2 = 19.6 m/s."},
  {"i":"phys-b3-0171","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A runner accelerates uniformly from 4 m/s to 10 m/s in 3 s. The acceleration is","o":["2 m/s²","6 m/s²","18 m/s²","0.5 m/s²"],"c":0,"e":"a = (v − u)/t = (10 − 4)/3 = 6/3 = 2 m/s²."},
  {"i":"phys-b3-0172","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A net force of 20 N acts on a 4 kg object. Its acceleration is","o":["5 m/s²","80 m/s²","0.2 m/s²","16 m/s²"],"c":0,"e":"By Newton's second law a = F/m = 20/4 = 5 m/s²."},
  {"i":"phys-b3-0173","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"The weight of a 6 kg bag of teff on Earth is (g = 9.8 m/s²)","o":["6 N","58.8 N","0.61 N","16 N"],"c":1,"e":"Weight W = mg = 6 × 9.8 = 58.8 N."},
  {"i":"phys-b3-0174","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A 2 kg ball moving at 5 m/s has a linear momentum of","o":["10 kg·m/s","2.5 kg·m/s","7 kg·m/s","25 kg·m/s"],"c":0,"e":"Momentum p = mv = 2 × 5 = 10 kg·m/s."},
  {"i":"phys-b3-0175","g":11,"u":"Dynamics","d":"easy","t":"conceptual","q":"Newton's third law states that for every action there is","o":["a larger reaction","an equal and opposite reaction","no reaction","a delayed reaction"],"c":1,"e":"Forces occur in pairs that are equal in magnitude and opposite in direction."},
  {"i":"phys-b3-0176","g":11,"u":"Dynamics","d":"easy","t":"application","q":"The universal law of gravitation states that the gravitational force between two masses is inversely proportional to","o":["the sum of the masses","the distance between them","the square of the distance between them","the product of the masses"],"c":2,"e":"F = Gm₁m₂/r², so the force is inversely proportional to the square of the separation r."},
  {"i":"phys-b3-0177","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"definition","q":"The transfer of heat through a solid metal rod without the metal itself moving is called","o":["convection","radiation","conduction","evaporation"],"c":2,"e":"Conduction is heat transfer through a material by particle vibration without bulk movement of the material."},
  {"i":"phys-b3-0178","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"A resistor of 10 Ω carries a current of 2 A. The voltage across it is","o":["5 V","12 V","20 V","0.2 V"],"c":2,"e":"By Ohm's law V = IR = 2 × 10 = 20 V."},
  {"i":"phys-b3-0179","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"definition","q":"Like electric charges","o":["attract each other","repel each other","have no force between them","always neutralize"],"c":1,"e":"Like charges repel and unlike charges attract."},
  {"i":"phys-b3-0180","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"Two resistors of 4 Ω and 6 Ω are connected in series. The total resistance is","o":["2.4 Ω","10 Ω","24 Ω","5 Ω"],"c":1,"e":"In series, resistances add: R = 4 + 6 = 10 Ω."},
  {"i":"phys-b3-0181","g":11,"u":"Nuclear Physics","d":"easy","t":"definition","q":"The particles found inside the nucleus of an atom are","o":["protons and electrons","protons and neutrons","neutrons and electrons","electrons only"],"c":1,"e":"The nucleus contains protons and neutrons (collectively called nucleons)."},
  {"i":"phys-b3-0182","g":11,"u":"Physics & Human Society","d":"easy","t":"definition","q":"Which branch of physics deals with the study of heat, temperature, and the transfer of thermal energy?","o":["Optics","Thermodynamics","Acoustics","Electromagnetism"],"c":1,"e":"Thermodynamics is the branch of physics concerned with heat, temperature, and the conversion and transfer of thermal energy."},
  {"i":"phys-b3-0183","g":11,"u":"Vectors","d":"easy","t":"calculation","q":"Two perpendicular forces of 3 N and 4 N act on a body at a point. The magnitude of their resultant is:","o":["1 N","5 N","7 N","12 N"],"c":1,"e":"For perpendicular vectors R = √(3² + 4²) = √(9 + 16) = √25 = 5 N."},
  {"i":"phys-b3-0184","g":11,"u":"Vectors","d":"easy","t":"calculation","q":"A vector of magnitude 10 N makes an angle of 60° with the horizontal. Its horizontal component is:","o":["5 N","8.7 N","10 N","17.3 N"],"c":0,"e":"Horizontal component = 10 cos60° = 10 × 0.5 = 5 N."},
  {"i":"phys-b3-0185","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A car accelerates uniformly from rest at 2 m/s² for 5 s. Its final speed is:","o":["2.5 m/s","7 m/s","10 m/s","25 m/s"],"c":2,"e":"Using v = u + at = 0 + (2)(5) = 10 m/s."},
  {"i":"phys-b3-0186","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A stone is dropped from rest. After 2 s of free fall (g = 9.8 m/s²), its speed is:","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"v = gt = 9.8 × 2 = 19.6 m/s."},
  {"i":"phys-b3-0187","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A body moving at 20 m/s decelerates uniformly at 4 m/s². The time to come to rest is:","o":["2 s","5 s","16 s","80 s"],"c":1,"e":"Using v = u + at, 0 = 20 + (−4)t, so t = 20/4 = 5 s."},
  {"i":"phys-b3-0188","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A projectile is launched horizontally from a cliff. Ignoring air resistance, its horizontal velocity during flight:","o":["Increases steadily","Decreases steadily","Remains constant","Becomes zero at the top"],"c":2,"e":"With no horizontal force (air resistance ignored), horizontal velocity stays constant throughout the flight."},
  {"i":"phys-b3-0189","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A net force of 12 N acts on a 3 kg object. Its acceleration is:","o":["0.25 m/s²","4 m/s²","9 m/s²","36 m/s²"],"c":1,"e":"By Newton's second law a = F/m = 12/3 = 4 m/s²."},
  {"i":"phys-b3-0190","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"The weight of a 5 kg mass on Earth (g = 9.8 m/s²) is:","o":["5 N","9.8 N","49 N","98 N"],"c":2,"e":"Weight W = mg = 5 × 9.8 = 49 N."},
  {"i":"phys-b3-0191","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A 2 kg trolley moving at 6 m/s has a linear momentum of:","o":["3 kg·m/s","8 kg·m/s","12 kg·m/s","36 kg·m/s"],"c":2,"e":"Momentum p = mv = 2 × 6 = 12 kg·m/s."},
  {"i":"phys-b3-0192","g":11,"u":"Dynamics","d":"easy","t":"conceptual","q":"For an object moving in a circle at constant speed, the centripetal acceleration is directed:","o":["Along the velocity","Away from the centre","Toward the centre","Vertically downward"],"c":2,"e":"Centripetal acceleration always points toward the centre of the circular path."},
  {"i":"phys-b3-0193","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"The gravitational force between two masses is F. If the distance between them is doubled, the new force is:","o":["F/4","F/2","2F","4F"],"c":0,"e":"By the inverse-square law F ∝ 1/r²; doubling r reduces the force to F/4."},
  {"i":"phys-b3-0194","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A torque is produced by a 10 N force applied perpendicularly at 0.5 m from a pivot. The torque is:","o":["0.05 N·m","2 N·m","5 N·m","20 N·m"],"c":2,"e":"Torque τ = F × r = 10 × 0.5 = 5 N·m."},
  {"i":"phys-b3-0195","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"definition","q":"The transfer of heat through a solid metal rod without the movement of the material itself is called:","o":["Convection","Conduction","Radiation","Evaporation"],"c":1,"e":"Conduction transfers heat through a material by particle vibration without bulk movement of the material."},
  {"i":"phys-b3-0196","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"A resistor carries a current of 2 A under a potential difference of 12 V. Its resistance is:","o":["0.17 Ω","6 Ω","14 Ω","24 Ω"],"c":1,"e":"By Ohm's law R = V/I = 12/2 = 6 Ω."},
  {"i":"phys-b3-0197","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"Two resistors of 4 Ω and 6 Ω are connected in series. Their total resistance is:","o":["2.4 Ω","5 Ω","10 Ω","24 Ω"],"c":2,"e":"In series, resistances add: R = 4 + 6 = 10 Ω."},
  {"i":"phys-b3-0198","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"An electrical device draws 3 A at 220 V. The power it consumes is:","o":["73.3 W","223 W","440 W","660 W"],"c":3,"e":"Power P = VI = 220 × 3 = 660 W."},
  {"i":"phys-b3-0199","g":11,"u":"Nuclear Physics","d":"easy","t":"definition","q":"Atoms of the same element having the same number of protons but different numbers of neutrons are called:","o":["Ions","Isotopes","Isobars","Allotropes"],"c":1,"e":"Isotopes share the same proton number (same element) but differ in neutron number, giving different mass numbers."},
  {"i":"phys-b3-0200","g":11,"u":"Physics & Human Society","d":"easy","t":"definition","q":"Which branch of physics deals with the study of heat, temperature, and the conversion of energy between heat and other forms?","o":["Optics","Thermodynamics","Acoustics","Electromagnetism"],"c":1,"e":"Thermodynamics is the branch of physics concerned with heat, temperature, and energy transfer between heat and other forms."},
  {"i":"phys-b3-0201","g":11,"u":"Physics & Human Society","d":"easy","t":"conceptual","q":"The SI base unit used to measure the amount of electric current is the:","o":["volt","watt","ampere","coulomb"],"c":2,"e":"The ampere (A) is the SI base unit of electric current; the coulomb measures charge and the volt measures potential difference."},
  {"i":"phys-b3-0202","g":11,"u":"Physics & Human Society","d":"easy","t":"definition","q":"A quantity that has only magnitude and no direction is called a:","o":["vector quantity","scalar quantity","tensor quantity","unit vector"],"c":1,"e":"A scalar quantity is fully described by magnitude alone, such as mass or temperature, while a vector also needs direction."},
  {"i":"phys-b3-0203","g":11,"u":"Vectors","d":"easy","t":"conceptual","q":"Two forces of equal magnitude act on a body. The resultant is maximum when the angle between them is:","o":["0°","90°","120°","180°"],"c":0,"e":"The resultant of two vectors is maximum when they point in the same direction, i.e. the angle between them is 0°."},
  {"i":"phys-b3-0204","g":11,"u":"Vectors","d":"easy","t":"calculation","q":"A displacement vector has components 6 m east and 8 m north. Its magnitude is:","o":["10 m","14 m","2 m","48 m"],"c":0,"e":"Magnitude = √(6² + 8²) = √(36 + 64) = √100 = 10 m."},
  {"i":"phys-b3-0205","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A bus on the Addis–Adama road travels 120 km in 2 hours. Its average speed is:","o":["240 km/h","60 km/h","30 km/h","122 km/h"],"c":1,"e":"Average speed = distance ÷ time = 120 km ÷ 2 h = 60 km/h."},
  {"i":"phys-b3-0206","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A car accelerates uniformly from rest at 2 m/s² for 5 s. Its final velocity is:","o":["2.5 m/s","7 m/s","10 m/s","20 m/s"],"c":2,"e":"Using v = u + at = 0 + (2)(5) = 10 m/s."},
  {"i":"phys-b3-0207","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A stone is dropped from rest. Taking g = 9.8 m/s², its speed after 2 s is:","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"v = gt = 9.8 × 2 = 19.6 m/s for a freely falling object starting from rest."},
  {"i":"phys-b3-0208","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"conceptual","q":"For a projectile launched at an angle (neglecting air resistance), the horizontal component of velocity:","o":["increases steadily","remains constant","decreases to zero at the top","reverses direction at the top"],"c":1,"e":"With no air resistance there is no horizontal force, so the horizontal velocity component stays constant throughout the flight."},
  {"i":"phys-b3-0209","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A 2 kg ball moves at 3 m/s. Its linear momentum is:","o":["1.5 kg·m/s","5 kg·m/s","6 kg·m/s","9 kg·m/s"],"c":2,"e":"Momentum p = mv = 2 kg × 3 m/s = 6 kg·m/s."},
  {"i":"phys-b3-0210","g":11,"u":"Dynamics","d":"easy","t":"conceptual","q":"When you push against a wall, the wall pushes back on you with an equal and opposite force. This illustrates Newton's:","o":["first law","second law","third law","law of gravitation"],"c":2,"e":"Newton's third law states that for every action there is an equal and opposite reaction force."},
  {"i":"phys-b3-0211","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A wheel rotates through an angle of 6 rad in 3 s at constant rate. Its angular velocity is:","o":["0.5 rad/s","2 rad/s","9 rad/s","18 rad/s"],"c":1,"e":"Angular velocity ω = θ/t = 6 rad ÷ 3 s = 2 rad/s."},
  {"i":"phys-b3-0212","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"definition","q":"The quantity of heat needed to raise the temperature of 1 kg of a substance by 1 K is its:","o":["latent heat","specific heat capacity","thermal conductivity","heat of fusion"],"c":1,"e":"Specific heat capacity is the heat required to raise the temperature of unit mass (1 kg) by 1 K (or 1 °C)."},
  {"i":"phys-b3-0213","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"calculation","q":"How much heat is needed to raise 2 kg of water (c = 4200 J/kg·K) by 5 K?","o":["8400 J","21000 J","42000 J","4200 J"],"c":2,"e":"Q = mcΔT = 2 × 4200 × 5 = 42000 J."},
  {"i":"phys-b3-0214","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"conceptual","q":"The transfer of heat through a solid metal rod from the hot end to the cold end occurs mainly by:","o":["convection","radiation","conduction","evaporation"],"c":2,"e":"In solids heat transfers by conduction, as vibrating particles pass energy to neighbouring particles without bulk movement."},
  {"i":"phys-b3-0215","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"A resistor of 4 Ω carries a current of 3 A. The potential difference across it is:","o":["0.75 V","7 V","12 V","1.33 V"],"c":2,"e":"By Ohm's law V = IR = 3 A × 4 Ω = 12 V."},
  {"i":"phys-b3-0216","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"conceptual","q":"Two like electric charges placed near each other will:","o":["attract each other","repel each other","exert no force","neutralize each other"],"c":1,"e":"Like charges repel and unlike charges attract; two positive (or two negative) charges therefore repel."},
  {"i":"phys-b3-0217","g":11,"u":"Motion in One and Two Dimensions","d":"easy","t":"calculation","q":"A bus leaving Addis Ababa starts from rest and accelerates uniformly at 2 m/s². What is its speed after 6 s?","o":["6 m/s","12 m/s","3 m/s","8 m/s"],"c":1,"e":"Using v = u + at with u = 0, v = 0 + (2)(6) = 12 m/s."},
  {"i":"phys-b3-0218","g":11,"u":"Dynamics","d":"easy","t":"calculation","q":"A net force of 20 N acts on a 4 kg crate on a frictionless floor. What is the crate's acceleration?","o":["80 m/s²","5 m/s²","0.2 m/s²","16 m/s²"],"c":1,"e":"By Newton's second law a = F/m = 20/4 = 5 m/s²."},
  {"i":"phys-b3-0219","g":11,"u":"Electrostatics & Electric Circuit","d":"easy","t":"calculation","q":"A resistor carries a current of 3 A when connected across a 12 V battery. What is its resistance?","o":["36 Ω","0.25 Ω","4 Ω","9 Ω"],"c":2,"e":"By Ohm's law R = V/I = 12/3 = 4 Ω."},
  {"i":"phys-b3-0220","g":11,"u":"Heat Conduction & Calorimetry","d":"easy","t":"definition","q":"Which quantity is defined as the amount of heat required to raise the temperature of 1 kg of a substance by 1 K?","o":["Specific heat capacity","Latent heat","Thermal conductivity","Heat capacity"],"c":0,"e":"Specific heat capacity is the heat per unit mass per unit temperature rise, in J/(kg·K)."},
  {"i":"phys-b3-0221","g":11,"u":"Nuclear Physics","d":"easy","t":"conceptual","q":"Which type of nuclear radiation is a positively charged helium nucleus?","o":["Gamma radiation","Beta radiation","Alpha radiation","X-ray radiation"],"c":2,"e":"An alpha particle consists of 2 protons and 2 neutrons, identical to a helium-4 nucleus, so it carries a +2 charge."},
  {"i":"phys-b3-0222","g":11,"u":"Physics & Human Society","d":"medium","t":"conceptual","q":"A student measures a table's length as 1.20 m using a ruler marked in millimetres. Which statement best describes why the measurement is reported as 1.200 m rather than 1.2 m?","o":["The extra zeros change the value of the length","The number of significant figures reflects the precision of the instrument","Adding zeros is required by SI rules for all lengths","The zeros indicate the measurement is an estimate only"],"c":1,"e":"Trailing zeros after the decimal point are significant; writing 1.200 m communicates that the millimetre ruler resolves to ±0.001 m, conveying the instrument's precision."},
  {"i":"phys-b3-0223","g":11,"u":"Physics & Human Society","d":"medium","t":"application","q":"A physical quantity has the unit kg·m/s². Which derived SI quantity has exactly this unit?","o":["Energy","Power","Force","Momentum"],"c":2,"e":"Force = mass × acceleration, so its unit is kg·m/s² (the newton). Momentum is kg·m/s and energy is kg·m²/s²."},
  {"i":"phys-b3-0224","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Two forces of 6 N (east) and 8 N (north) act on a point. What is the magnitude of their resultant?","o":["10 N","14 N","2 N","7 N"],"c":0,"e":"Perpendicular vectors add by Pythagoras: √(6² + 8²) = √(36 + 64) = √100 = 10 N."},
  {"i":"phys-b3-0225","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"A vector of magnitude 20 m points at 30° above the horizontal. What is its vertical component? (sin 30° = 0.5)","o":["17.3 m","10 m","20 m","15 m"],"c":1,"e":"Vertical component = 20 × sin 30° = 20 × 0.5 = 10 m."},
  {"i":"phys-b3-0226","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A car accelerates uniformly from rest to 24 m/s in 8 s. How far does it travel during this time?","o":["192 m","96 m","48 m","24 m"],"c":1,"e":"With average velocity (0 + 24)/2 = 12 m/s over 8 s, distance = 12 × 8 = 96 m."},
  {"i":"phys-b3-0227","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A ball is thrown vertically upward at 19.6 m/s. Using g = 9.8 m/s², how long until it returns to the thrower's hand?","o":["2 s","4 s","1 s","8 s"],"c":1,"e":"Time up = v/g = 19.6/9.8 = 2 s; total flight time is twice this = 4 s."},
  {"i":"phys-b3-0228","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A stone is dropped from a cliff and hits the ground after 3 s. Using g = 9.8 m/s², what is the cliff's height?","o":["29.4 m","44.1 m","88.2 m","14.7 m"],"c":1,"e":"h = ½gt² = ½ × 9.8 × 3² = ½ × 9.8 × 9 = 44.1 m."},
  {"i":"phys-b3-0229","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A projectile is launched horizontally from a 19.6 m high platform at 15 m/s. How far horizontally does it land? (g = 9.8 m/s²)","o":["30 m","15 m","45 m","20 m"],"c":0,"e":"Fall time: t = √(2h/g) = √(2×19.6/9.8) = √4 = 2 s; range = 15 × 2 = 30 m."},
  {"i":"phys-b3-0230","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 5 kg block on a frictionless surface is pushed by a 20 N horizontal force. What is its acceleration?","o":["4 m/s²","100 m/s²","0.25 m/s²","25 m/s²"],"c":0,"e":"By Newton's second law, a = F/m = 20/5 = 4 m/s²."},
  {"i":"phys-b3-0231","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 2 kg object moving at 10 m/s is brought to rest by a constant force in 4 s. What is the magnitude of the force?","o":["5 N","20 N","2.5 N","8 N"],"c":0,"e":"Deceleration a = (10−0)/4 = 2.5 m/s²; F = ma = 2 × 2.5 = 5 N."},
  {"i":"phys-b3-0232","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 0.5 kg ball moving at 8 m/s strikes a wall and rebounds at 6 m/s in the opposite direction. What is the magnitude of the change in its momentum?","o":["1 kg·m/s","7 kg·m/s","14 kg·m/s","4 kg·m/s"],"c":1,"e":"Taking initial as +, Δp = m(v_f − v_i) = 0.5(−6 − 8) = −7 kg·m/s; magnitude 7 kg·m/s."},
  {"i":"phys-b3-0233","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"Two masses, 3 kg and 1 kg, move toward each other at 2 m/s each and stick together on collision. What is their common speed afterward?","o":["1 m/s","2 m/s","0.5 m/s","1.5 m/s"],"c":0,"e":"Momentum: (3×2) + (1×−2) = 4 kg·m/s; total mass 4 kg, so v = 4/4 = 1 m/s in the heavier mass's direction."},
  {"i":"phys-b3-0234","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A satellite orbits Earth at radius r. If the orbital radius is doubled, the gravitational force on it becomes what fraction of the original?","o":["1/2","1/4","1/8","2"],"c":1,"e":"Gravitation follows an inverse-square law: F ∝ 1/r², so doubling r gives F × (1/2²) = 1/4 of the original."},
  {"i":"phys-b3-0235","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A wheel rotating at 4 rad/s undergoes a constant angular acceleration of 2 rad/s² for 3 s. What is its final angular velocity?","o":["6 rad/s","10 rad/s","12 rad/s","8 rad/s"],"c":1,"e":"ω = ω₀ + αt = 4 + 2 × 3 = 10 rad/s."},
  {"i":"phys-b3-0236","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 0.2 kg stone is whirled in a horizontal circle of radius 0.5 m at 4 m/s. What centripetal force is required?","o":["6.4 N","3.2 N","1.6 N","12.8 N"],"c":0,"e":"F = mv²/r = 0.2 × 4²/0.5 = 0.2 × 16/0.5 = 3.2/0.5 = 6.4 N."},
  {"i":"phys-b3-0237","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"How much heat is needed to raise the temperature of 0.5 kg of water by 20°C? (specific heat of water = 4200 J/kg·°C)","o":["42000 J","4200 J","21000 J","84000 J"],"c":0,"e":"Q = mcΔT = 0.5 × 4200 × 20 = 42000 J."},
  {"i":"phys-b3-0238","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"A metal rod conducts heat at 60 W. If its cross-sectional area is doubled while all else stays constant, what is the new rate of heat conduction?","o":["120 W","30 W","60 W","240 W"],"c":0,"e":"Conduction rate Q/t = kAΔT/L is proportional to area A, so doubling A doubles the rate to 120 W."},
  {"i":"phys-b3-0239","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two point charges of +2 μC and +3 μC are 0.1 m apart. Using k = 9×10⁹ N·m²/C², what is the magnitude of the force between them?","o":["5.4 N","54 N","0.54 N","27 N"],"c":0,"e":"F = kq₁q₂/r² = 9×10⁹ × (2×10⁻⁶)(3×10⁻⁶)/(0.1²) = 9×10⁹ × 6×10⁻¹²/0.01 = 5.4 N."},
  {"i":"phys-b3-0240","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Three resistors of 2 Ω, 3 Ω and 6 Ω are connected in parallel. What is their equivalent resistance?","o":["1 Ω","11 Ω","0.5 Ω","3.67 Ω"],"c":0,"e":"1/R = 1/2 + 1/3 + 1/6 = 3/6 + 2/6 + 1/6 = 6/6 = 1, so R = 1 Ω."},
  {"i":"phys-b3-0241","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"A 12 V battery drives a current of 3 A through a resistor. What electrical power is dissipated?","o":["36 W","4 W","15 W","9 W"],"c":0,"e":"P = VI = 12 × 3 = 36 W."},
  {"i":"phys-b3-0242","g":11,"u":"Nuclear Physics","d":"medium","t":"calculation","q":"A radioactive isotope has a half-life of 8 days. What fraction of an initial sample remains undecayed after 24 days?","o":["1/8","1/3","1/16","1/4"],"c":0,"e":"24 days is 3 half-lives (24/8 = 3), so the remaining fraction is (1/2)³ = 1/8."},
  {"i":"phys-b3-0243","g":11,"u":"Physics & Human Society","d":"medium","t":"conceptual","q":"A research team in Ethiopia wants to measure the period of a pendulum to determine g. Which statement best reflects the role of repeated measurement in physics?","o":["A single measurement is always exact and needs no repetition","Repeating the measurement and averaging reduces the effect of random errors","Repetition removes systematic errors caused by a miscalibrated ruler","More repetitions change the true value of g being measured"],"c":1,"e":"Averaging many trials reduces random scatter; it does not fix systematic errors nor alter the true value."},
  {"i":"phys-b3-0244","g":11,"u":"Physics & Human Society","d":"medium","t":"definition","q":"A physical quantity is expressed as 4.50 × 10³ kg/m³. How many significant figures does this value carry?","o":["2","3","4","5"],"c":1,"e":"In 4.50 × 10³ the mantissa 4.50 has three significant figures; the power of ten does not count."},
  {"i":"phys-b3-0245","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Two forces act on a body at the same point: 6 N directed east and 8 N directed north. What is the magnitude of their resultant?","o":["7 N","10 N","14 N","2 N"],"c":1,"e":"Perpendicular vectors add as √(6² + 8²) = √(36+64) = √100 = 10 N."},
  {"i":"phys-b3-0246","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"A displacement vector has components Ax = -3 m and Ay = 4 m. What angle does it make with the positive x-axis (measured anticlockwise)?","o":["53° below the x-axis","127° from the positive x-axis","37° from the positive x-axis","143° from the positive x-axis"],"c":1,"e":"The vector is in the second quadrant; reference angle = tan⁻¹(4/3) = 53°, so angle = 180° − 53° = 127°."},
  {"i":"phys-b3-0247","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Given vectors A = 2i + 3j and B = 4i − j, what is the scalar (dot) product A·B?","o":["5","8","11","−5"],"c":0,"e":"A·B = (2)(4) + (3)(−1) = 8 − 3 = 5."},
  {"i":"phys-b3-0248","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A car accelerates uniformly from rest and reaches 20 m/s in 8 s on a road near Adama. What distance does it cover during this time?","o":["80 m","160 m","40 m","320 m"],"c":0,"e":"With average velocity (0+20)/2 = 10 m/s over 8 s, distance = 10 × 8 = 80 m."},
  {"i":"phys-b3-0249","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A stone is thrown vertically upward at 14 m/s (g = 9.8 m/s²). What maximum height does it reach above the launch point?","o":["10 m","14 m","20 m","28 m"],"c":0,"e":"h = v²/(2g) = 14²/(2×9.8) = 196/19.6 = 10 m."},
  {"i":"phys-b3-0250","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A ball is projected horizontally at 15 m/s from a 20 m high cliff (g = 9.8 m/s²). How far from the base does it land?","o":["about 30 m","about 45 m","about 20 m","about 60 m"],"c":0,"e":"Fall time t = √(2×20/9.8) ≈ 2.02 s; horizontal range = 15 × 2.02 ≈ 30 m."},
  {"i":"phys-b3-0251","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A projectile is launched at 30 m/s at 30° above the horizontal (g = 9.8 m/s²). What is its time of flight on level ground?","o":["3.06 s","1.53 s","5.30 s","6.12 s"],"c":0,"e":"T = 2v·sinθ/g = 2(30)(0.5)/9.8 = 30/9.8 ≈ 3.06 s."},
  {"i":"phys-b3-0252","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"An object moving at 25 m/s decelerates uniformly at 5 m/s². How far does it travel before stopping?","o":["62.5 m","50 m","125 m","31.25 m"],"c":0,"e":"v² = u² − 2as → 0 = 625 − 2(5)s → s = 625/10 = 62.5 m."},
  {"i":"phys-b3-0253","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 4 kg block on a frictionless surface is pushed by a horizontal 12 N force. What is its acceleration?","o":["3 m/s²","48 m/s²","0.33 m/s²","8 m/s²"],"c":0,"e":"a = F/m = 12/4 = 3 m/s²."},
  {"i":"phys-b3-0254","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 2 kg ball moving at 6 m/s strikes a wall and rebounds at 4 m/s in the opposite direction. What is the magnitude of the impulse on the ball?","o":["4 N·s","20 N·s","12 N·s","8 N·s"],"c":1,"e":"Impulse = Δp = m(v_f − v_i) = 2(−4 − 6) = −20 N·s; magnitude 20 N·s."},
  {"i":"phys-b3-0255","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 1500 kg car rounds a flat curve of radius 50 m at 10 m/s. What centripetal force is required?","o":["3000 N","300 N","30000 N","1500 N"],"c":0,"e":"F = mv²/r = 1500 × 100/50 = 3000 N."},
  {"i":"phys-b3-0256","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 5 kg box is pulled along a rough floor by a 30 N horizontal force at constant velocity. What is the coefficient of kinetic friction (g = 9.8 m/s²)?","o":["0.61","0.51","0.30","0.16"],"c":0,"e":"Constant velocity means friction = applied force = 30 N; μ = 30/(5×9.8) = 30/49 ≈ 0.61."},
  {"i":"phys-b3-0257","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"Two masses, 3 kg and 5 kg, hang from a frictionless pulley (Atwood machine, g = 9.8 m/s²). What is the acceleration of the system?","o":["2.45 m/s²","1.22 m/s²","4.90 m/s²","9.80 m/s²"],"c":0,"e":"a = (m₂−m₁)g/(m₁+m₂) = (2)(9.8)/8 = 19.6/8 = 2.45 m/s²."},
  {"i":"phys-b3-0258","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A solid disc of radius 0.2 m experiences a tangential force of 10 N at its rim. What torque acts about its centre?","o":["2 N·m","50 N·m","0.02 N·m","10 N·m"],"c":0,"e":"τ = F × r = 10 × 0.2 = 2 N·m."},
  {"i":"phys-b3-0259","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A satellite orbits Earth where g at that altitude is 8.0 m/s² and the orbital radius is 8.0 × 10⁶ m. What is its orbital speed?","o":["8.0 × 10³ m/s","6.4 × 10⁷ m/s","1.0 × 10³ m/s","8.0 × 10⁶ m/s"],"c":0,"e":"For orbit, g = v²/r → v = √(g·r) = √(8.0 × 8.0×10⁶) = √(6.4×10⁷) ≈ 8.0×10³ m/s."},
  {"i":"phys-b3-0260","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"How much heat is needed to raise the temperature of 0.5 kg of water by 20 °C (specific heat 4200 J/kg·°C)?","o":["42000 J","4200 J","84000 J","2100 J"],"c":0,"e":"Q = mcΔT = 0.5 × 4200 × 20 = 42000 J."},
  {"i":"phys-b3-0261","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"A metal rod 2 m long with cross-section 0.01 m² and thermal conductivity 200 W/m·°C has ends at 100 °C and 20 °C. What is the rate of heat conduction?","o":["80 W","160 W","8 W","800 W"],"c":0,"e":"Q/t = kAΔT/L = 200 × 0.01 × 80 / 2 = 160/2 = 80 W."},
  {"i":"phys-b3-0262","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two point charges of +3 μC and +2 μC are placed 0.30 m apart in air (k = 9×10⁹ N·m²/C²). What is the force between them?","o":["0.60 N","0.20 N","1.80 N","6.00 N"],"c":0,"e":"F = kq₁q₂/r² = 9×10⁹ × (3×10⁻⁶)(2×10⁻⁶)/0.09 = 0.054/0.09 = 0.60 N."},
  {"i":"phys-b3-0263","g":11,"u":"Physics & Human Society","d":"medium","t":"conceptual","q":"A research team in Bishoftu wants to predict the trajectory of a thrown stone. Which feature of physics makes such prediction possible, distinguishing it from a non-scientific claim?","o":["Its laws give testable, repeatable quantitative predictions","It relies on the authority of famous physicists","It avoids the use of mathematics","Its conclusions can never be revised"],"c":0,"e":"Physics is predictive and falsifiable: its laws yield quantitative results that can be tested and repeated, unlike claims based on authority alone."},
  {"i":"phys-b3-0264","g":11,"u":"Physics & Human Society","d":"medium","t":"application","q":"Ethiopia plans large-scale solar farms in the Afar region. Which branch of physics most directly governs the conversion of sunlight into electrical energy in a photovoltaic cell?","o":["Quantum/solid-state physics (the photoelectric effect)","Classical thermodynamics only","Fluid mechanics","Acoustics"],"c":0,"e":"Photovoltaic conversion relies on the photoelectric effect, a quantum/solid-state phenomenon where photons free charge carriers in a semiconductor."},
  {"i":"phys-b3-0265","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Two forces act on a crate at a single point: 6.0 N due east and 8.0 N due north. What is the magnitude of their resultant?","o":["10.0 N","14.0 N","2.0 N","48.0 N"],"c":0,"e":"Perpendicular vectors add by Pythagoras: R = √(6.0² + 8.0²) = √(36 + 64) = √100 = 10.0 N."},
  {"i":"phys-b3-0266","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"A displacement vector has magnitude 20 m directed 30° above the horizontal. What is its horizontal component?","o":["17.3 m","10.0 m","20.0 m","11.5 m"],"c":0,"e":"The horizontal component is A·cos30° = 20 × 0.866 = 17.3 m."},
  {"i":"phys-b3-0267","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Vector A = (3, 4) and vector B = (-1, 2), in metres. What is the magnitude of A + B?","o":["6.3 m","8.0 m","2.0 m","10.0 m"],"c":0,"e":"A + B = (3−1, 4+2) = (2, 6); magnitude = √(2² + 6²) = √40 ≈ 6.3 m."},
  {"i":"phys-b3-0268","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A bus leaving Addis Ababa accelerates uniformly from rest to 20 m/s in 8.0 s. How far does it travel during this time?","o":["80 m","160 m","40 m","20 m"],"c":0,"e":"With average velocity (0+20)/2 = 10 m/s over 8.0 s, distance = 10 × 8.0 = 80 m."},
  {"i":"phys-b3-0269","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A stone is dropped from rest off a bridge and hits the river 2.0 s later. Using g = 9.8 m/s², what is its speed just before impact?","o":["19.6 m/s","9.8 m/s","4.9 m/s","39.2 m/s"],"c":0,"e":"v = gt = 9.8 × 2.0 = 19.6 m/s (initial speed zero)."},
  {"i":"phys-b3-0270","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A ball is kicked horizontally at 15 m/s from a 4.9 m high platform. Using g = 9.8 m/s², how far horizontally does it land from the base?","o":["15 m","30 m","7.5 m","22 m"],"c":0,"e":"Fall time: 4.9 = ½(9.8)t² → t² = 1.0 → t = 1.0 s. Range = 15 × 1.0 = 15 m."},
  {"i":"phys-b3-0271","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A projectile is launched at 40 m/s at 30° above the horizontal. Using g = 9.8 m/s², what is its maximum height?","o":["20.4 m","40.8 m","10.2 m","81.6 m"],"c":0,"e":"v_y = 40·sin30° = 20 m/s; H = v_y²/(2g) = 400/19.6 = 20.4 m."},
  {"i":"phys-b3-0272","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A net force of 12 N acts on a 3.0 kg block on a frictionless surface. What is the block's acceleration?","o":["4.0 m/s²","36 m/s²","0.25 m/s²","9.0 m/s²"],"c":0,"e":"By Newton's second law, a = F/m = 12/3.0 = 4.0 m/s²."},
  {"i":"phys-b3-0273","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 1500 kg car moving at 20 m/s is brought to rest in 5.0 s. What average braking force acts on it?","o":["6000 N","3000 N","7500 N","1500 N"],"c":0,"e":"a = (0−20)/5.0 = −4.0 m/s²; F = ma = 1500 × 4.0 = 6000 N (magnitude)."},
  {"i":"phys-b3-0274","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 5.0 kg crate is pulled along a floor by a 30 N horizontal force against a friction force of 10 N. What is its acceleration?","o":["4.0 m/s²","6.0 m/s²","8.0 m/s²","2.0 m/s²"],"c":0,"e":"Net force = 30 − 10 = 20 N; a = 20/5.0 = 4.0 m/s²."},
  {"i":"phys-b3-0275","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 0.50 kg ball moving at 8.0 m/s strikes a wall and rebounds at 6.0 m/s in the opposite direction. What is the magnitude of the impulse on the ball?","o":["7.0 N·s","1.0 N·s","3.0 N·s","14 N·s"],"c":0,"e":"Impulse = Δp = m(v_f − v_i) = 0.50(−6.0 − 8.0) = −7.0 N·s; magnitude 7.0 N·s."},
  {"i":"phys-b3-0276","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 2.0 kg trolley moving at 3.0 m/s collides and sticks to a stationary 4.0 kg trolley. What is their common velocity after collision?","o":["1.0 m/s","1.5 m/s","2.0 m/s","0.5 m/s"],"c":0,"e":"Momentum conservation: (2.0×3.0)/(2.0+4.0) = 6.0/6.0 = 1.0 m/s."},
  {"i":"phys-b3-0277","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A wheel rotates from rest with constant angular acceleration 2.0 rad/s². What is its angular velocity after 5.0 s?","o":["10 rad/s","2.5 rad/s","7.0 rad/s","20 rad/s"],"c":0,"e":"ω = ω₀ + αt = 0 + 2.0 × 5.0 = 10 rad/s."},
  {"i":"phys-b3-0278","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A satellite orbits Earth where gravitational acceleration is 8.0 m/s² at radius 7.0×10⁶ m. What is its orbital speed? (v = √(g·r))","o":["7.5×10³ m/s","5.6×10⁷ m/s","1.1×10³ m/s","2.4×10⁴ m/s"],"c":0,"e":"v = √(g·r) = √(8.0 × 7.0×10⁶) = √(5.6×10⁷) ≈ 7.5×10³ m/s."},
  {"i":"phys-b3-0279","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 0.20 kg ball on a string moves in a horizontal circle of radius 0.50 m at 3.0 m/s. What is the centripetal force?","o":["3.6 N","1.2 N","1.8 N","0.90 N"],"c":0,"e":"F = mv²/r = 0.20 × 9.0 / 0.50 = 1.8/0.50 = 3.6 N."},
  {"i":"phys-b3-0280","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"How much heat is needed to raise the temperature of 0.50 kg of water by 20 °C? (c = 4200 J/kg·°C)","o":["42000 J","4200 J","21000 J","84000 J"],"c":0,"e":"Q = mcΔT = 0.50 × 4200 × 20 = 42000 J."},
  {"i":"phys-b3-0281","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"A metal rod 0.20 m long, area 4.0×10⁻⁴ m², thermal conductivity 200 W/m·K, has ends at 100 °C and 20 °C. What is the rate of heat conduction?","o":["32 W","16 W","64 W","8.0 W"],"c":0,"e":"Q/t = kAΔT/L = 200 × 4.0×10⁻⁴ × 80 / 0.20 = 6.4/0.20 = 32 W."},
  {"i":"phys-b3-0282","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two point charges of +3.0 μC and +2.0 μC are 0.30 m apart. What is the magnitude of the electrostatic force between them? (k = 9.0×10⁹ N·m²/C²)","o":["0.60 N","6.0 N","0.18 N","1.8 N"],"c":0,"e":"F = kq₁q₂/r² = 9.0×10⁹ × 6.0×10⁻¹² / 0.09 = 5.4×10⁻²/0.09 = 0.60 N."},
  {"i":"phys-b3-0283","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Three resistors of 2.0 Ω, 3.0 Ω and 6.0 Ω are connected in parallel across a battery. What is their equivalent resistance?","o":["1.0 Ω","11 Ω","3.7 Ω","0.5 Ω"],"c":0,"e":"1/R = 1/2 + 1/3 + 1/6 = 3/6 + 2/6 + 1/6 = 1 → R = 1.0 Ω."},
  {"i":"phys-b3-0284","g":11,"u":"Nuclear Physics","d":"medium","t":"calculation","q":"A radioactive isotope has a half-life of 6.0 hours. Starting from 80 mg, how much remains after 18 hours?","o":["10 mg","20 mg","40 mg","5.0 mg"],"c":0,"e":"18 h = 3 half-lives; remaining = 80 × (½)³ = 80/8 = 10 mg."},
  {"i":"phys-b3-0285","g":11,"u":"Physics & Human Society","d":"medium","t":"conceptual","q":"A research team in Addis Ababa reports a measured value of the gravitational acceleration as g = 9.81 ± 0.02 m/s². In this statement, the '± 0.02 m/s²' primarily expresses the result's:","o":["accuracy compared to the true value","uncertainty in the measurement","systematic error only","random fluctuation of g itself"],"c":1,"e":"The ± term states the uncertainty (the range within which the true value is expected to lie); it does not by itself confirm accuracy nor mean g physically changes."},
  {"i":"phys-b3-0286","g":11,"u":"Physics & Human Society","d":"medium","t":"application","q":"A student measures a wire's length as 24.0 cm and its diameter as 0.50 mm to compute its volume. To how many significant figures should the final volume be reported?","o":["1","2","3","4"],"c":1,"e":"In multiplication the result keeps the fewest significant figures of the inputs; 0.50 mm has 2 sig figs, so the volume is reported to 2 significant figures."},
  {"i":"phys-b3-0287","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"Two forces act on a crate at a port in Djibouti: 6 N directed east and 8 N directed north. What is the magnitude of their resultant?","o":["10 N","14 N","2 N","48 N"],"c":0,"e":"The forces are perpendicular, so the resultant is √(6² + 8²) = √(36 + 64) = √100 = 10 N."},
  {"i":"phys-b3-0288","g":11,"u":"Vectors","d":"medium","t":"calculation","q":"A displacement vector of magnitude 20 m points 30° above the horizontal. What is its horizontal component?","o":["10 m","17.3 m","20 m","11.5 m"],"c":1,"e":"The horizontal component is 20·cos30° = 20·0.866 = 17.3 m."},
  {"i":"phys-b3-0289","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A minibus on the Addis Ababa ring road accelerates uniformly from 10 m/s to 25 m/s in 5.0 s. What distance does it cover during this interval?","o":["75 m","87.5 m","125 m","62.5 m"],"c":1,"e":"Using distance = average velocity × time = ((10 + 25)/2)·5.0 = 17.5·5.0 = 87.5 m."},
  {"i":"phys-b3-0290","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A ball is kicked horizontally from a 4.9 m high wall with a speed of 6.0 m/s. How far from the base of the wall does it land? (g = 9.8 m/s²)","o":["6.0 m","3.0 m","12 m","9.8 m"],"c":0,"e":"Time to fall: t = √(2h/g) = √(2·4.9/9.8) = √1 = 1.0 s; range = 6.0·1.0 = 6.0 m."},
  {"i":"phys-b3-0291","g":11,"u":"Motion in One and Two Dimensions","d":"medium","t":"calculation","q":"A stone is thrown vertically upward at 14.7 m/s. What is the maximum height it reaches? (g = 9.8 m/s²)","o":["11.0 m","22.0 m","14.7 m","7.5 m"],"c":0,"e":"At the top v = 0, so h = v²/(2g) = (14.7²)/(2·9.8) = 216.09/19.6 = 11.0 m."},
  {"i":"phys-b3-0292","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 1200 kg car traveling at 20 m/s is brought to rest in 4.0 s by braking. What is the magnitude of the average braking force?","o":["6000 N","4800 N","24000 N","3000 N"],"c":0,"e":"Acceleration = (0 − 20)/4.0 = −5.0 m/s²; force = m·a = 1200·5.0 = 6000 N."},
  {"i":"phys-b3-0293","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A 2.0 kg object moving at 3.0 m/s collides and sticks to a stationary 4.0 kg object. What is the common velocity after the collision?","o":["1.0 m/s","1.5 m/s","2.0 m/s","0.5 m/s"],"c":0,"e":"By momentum conservation: (2.0·3.0 + 0)/(2.0 + 4.0) = 6.0/6.0 = 1.0 m/s."},
  {"i":"phys-b3-0294","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A satellite orbits a planet at radius r. If it is moved to a new orbit at radius 2r, the gravitational force on it becomes what fraction of the original?","o":["1/2","1/4","1/8","2"],"c":1,"e":"Gravitational force varies as 1/r²; doubling r gives 1/(2²) = 1/4 of the original force."},
  {"i":"phys-b3-0295","g":11,"u":"Dynamics","d":"medium","t":"calculation","q":"A wheel starting from rest reaches an angular velocity of 12 rad/s in 4.0 s under constant angular acceleration. What is its angular acceleration?","o":["3.0 rad/s²","48 rad/s²","0.33 rad/s²","6.0 rad/s²"],"c":0,"e":"Angular acceleration = (ω − ω₀)/t = (12 − 0)/4.0 = 3.0 rad/s²."},
  {"i":"phys-b3-0296","g":11,"u":"Dynamics","d":"medium","t":"application","q":"A 5.0 kg block is pulled along a horizontal surface by a 30 N horizontal force against a friction force of 10 N. What is the block's acceleration?","o":["4.0 m/s²","6.0 m/s²","8.0 m/s²","2.0 m/s²"],"c":0,"e":"Net force = 30 − 10 = 20 N; acceleration = 20/5.0 = 4.0 m/s²."},
  {"i":"phys-b3-0297","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"How much heat is required to raise the temperature of 0.50 kg of water by 20 °C? (specific heat of water = 4200 J/kg·°C)","o":["42000 J","4200 J","21000 J","84000 J"],"c":0,"e":"Q = mcΔT = 0.50·4200·20 = 42000 J."},
  {"i":"phys-b3-0298","g":11,"u":"Heat Conduction & Calorimetry","d":"medium","t":"calculation","q":"A metal rod of length 0.40 m and cross-sectional area 2.0×10⁻⁴ m² has a temperature difference of 50 °C across its ends. If its thermal conductivity is 400 W/m·°C, what is the rate of heat conduction?","o":["10 W","20 W","5.0 W","40 W"],"c":0,"e":"Rate = kAΔT/L = (400·2.0×10⁻⁴·50)/0.40 = 4.0/0.40 = 10 W."},
  {"i":"phys-b3-0299","g":11,"u":"Electrostatics & Electric Circuit","d":"medium","t":"calculation","q":"Two resistors of 6.0 Ω and 3.0 Ω are connected in parallel across a 12 V battery. What total current is drawn from the battery?","o":["6.0 A","2.0 A","4.0 A","18 A"],"c":0,"e":"Parallel resistance = (6·3)/(6+3) = 2.0 Ω; current = V/R = 12/2.0 = 6.0 A."},
  {"i":"phys-b3-0300","g":11,"u":"Physics & Human Society","d":"hard","t":"conceptual","q":"A researcher claims a new local solar cooker boils 1 L of water 30% faster than the standard model. Which step best reflects the scientific method before accepting this claim?","o":["Publish the claim immediately because it benefits the community","Repeat the boiling test under controlled, identical conditions and compare measured times","Accept it if the inventor is a respected community elder","Assume it is true because solar energy is free"],"c":1,"e":"The scientific method requires controlled, repeatable experiments with measured data before a claim is accepted; authority or convenience is not evidence."},
  {"i":"phys-b3-0301","g":11,"u":"Physics & Human Society","d":"hard","t":"application","q":"A measurement of a steel rod's length gives 2.000 m with an absolute uncertainty of 0.004 m. A second rod measures 0.500 m with the same absolute uncertainty 0.004 m. Which rod's measurement is more precise (smaller relative uncertainty)?","o":["The 0.500 m rod, since 0.8% > 0.2%","The 2.000 m rod, since its relative uncertainty 0.2% is smaller","Both equal, since absolute uncertainties are equal","Cannot be compared without the instrument type"],"c":1,"e":"Relative uncertainty = absolute/value: 0.004/2.000 = 0.2% vs 0.004/0.500 = 0.8%. Smaller relative uncertainty (0.2%) means the longer rod is measured more precisely."},
  {"i":"phys-b3-0302","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"Two forces act at a point: 6 N due east and 8 N at 60° north of east. The magnitude of their resultant is closest to:","o":["12.2 N","10.0 N","14.0 N","9.2 N"],"c":0,"e":"Components: Fx = 6 + 8cos60° = 6 + 4 = 10 N; Fy = 8sin60° = 6.93 N. Resultant = √(10² + 6.93²) = √(100 + 48) = √148 ≈ 12.2 N."},
  {"i":"phys-b3-0303","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"Given A = 3i + 4j and B = -2i + 6j, the angle between vectors A and B is closest to:","o":["55°","44°","30°","72°"],"c":0,"e":"A·B = (3)(-2)+(4)(6) = 18; |A| = 5, |B| = √40 = 6.32. cosθ = 18/(5×6.32) = 0.569, so θ = cos⁻¹(0.569) ≈ 55°."},
  {"i":"phys-b3-0304","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"A boat heads straight across a river at 4.0 m/s relative to the water. The river current flows downstream at 3.0 m/s. The boat's speed relative to the riverbank is:","o":["7.0 m/s","1.0 m/s","5.0 m/s","2.6 m/s"],"c":2,"e":"The crossing and current velocities are perpendicular: resultant = √(4.0² + 3.0²) = √(16+9) = √25 = 5.0 m/s."},
  {"i":"phys-b3-0305","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A stone is thrown vertically upward at 24.5 m/s. The total time it spends above a height of 19.6 m is (g = 9.8 m/s²):","o":["3.0 s","2.0 s","1.0 s","2.5 s"],"c":0,"e":"Solve 19.6 = 24.5t − 4.9t²: t² − 5t + 4 = 0, giving t = 1 s and t = 4 s. Time above 19.6 m = 4 − 1 = 3.0 s."},
  {"i":"phys-b3-0306","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A ball is projected horizontally from a 44.1 m high cliff and lands 30 m from the base. Its initial horizontal speed was (g = 9.8 m/s²):","o":["10.0 m/s","15.0 m/s","7.5 m/s","12.0 m/s"],"c":0,"e":"Fall time: 44.1 = ½(9.8)t², t² = 9, t = 3 s. Horizontal: v = 30/3 = 10.0 m/s."},
  {"i":"phys-b3-0307","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A projectile is launched at 39.2 m/s at 30° above horizontal. Its maximum height is (g = 9.8 m/s²):","o":["19.6 m","39.2 m","9.8 m","78.4 m"],"c":0,"e":"vy = 39.2 sin30° = 19.6 m/s. H = vy²/(2g) = 19.6²/(2×9.8) = 384.16/19.6 = 19.6 m."},
  {"i":"phys-b3-0308","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A car accelerates uniformly from rest, covering 24 m in the 3rd second of motion. Its acceleration is:","o":["9.6 m/s²","8.0 m/s²","4.8 m/s²","16 m/s²"],"c":0,"e":"Distance in nth second = u + a(2n−1)/2 = a(2×3−1)/2 = 2.5a. So 2.5a = 24, a = 9.6 m/s²."},
  {"i":"phys-b3-0309","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 5.0 kg block on a rough horizontal floor (μk = 0.30) is pulled by a 30 N force at 37° above horizontal. Its acceleration is (g = 9.8 m/s², cos37°=0.8, sin37°=0.6):","o":["2.9 m/s²","4.8 m/s²","1.8 m/s²","3.6 m/s²"],"c":0,"e":"N = mg − Fsinθ = 49 − 30(0.6) = 31 N. Friction = 0.30×31 = 9.3 N. Net = 30(0.8) − 9.3 = 24 − 9.3 = 14.7 N. a = 14.7/5 = 2.94 ≈ 2.9 m/s²."},
  {"i":"phys-b3-0310","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"Two blocks of 3 kg and 2 kg connected by a light string hang over a frictionless pulley (Atwood machine). The acceleration of the system is (g = 9.8 m/s²):","o":["1.96 m/s²","3.92 m/s²","9.8 m/s²","0.98 m/s²"],"c":0,"e":"a = (m1−m2)g/(m1+m2) = (3−2)(9.8)/(3+2) = 9.8/5 = 1.96 m/s²."},
  {"i":"phys-b3-0311","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 1500 kg car rounds an unbanked curve of radius 50 m at 15 m/s. The minimum coefficient of friction needed to prevent skidding is (g = 9.8 m/s²):","o":["0.46","0.30","0.61","0.23"],"c":0,"e":"Required centripetal force = friction: μ = v²/(rg) = 15²/(50×9.8) = 225/490 = 0.459 ≈ 0.46."},
  {"i":"phys-b3-0312","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 0.20 kg ball moving at 8.0 m/s strikes a wall and rebounds at 6.0 m/s along the same line. If contact lasts 0.05 s, the average force on the ball is:","o":["56 N","8 N","40 N","24 N"],"c":0,"e":"Δp = m(v_f − v_i) = 0.20(−6 − 8) = −2.8 kg·m/s. F = |Δp|/Δt = 2.8/0.05 = 56 N."},
  {"i":"phys-b3-0313","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A solid disk of mass 4.0 kg and radius 0.50 m (I = ½MR²) has a net torque of 5.0 N·m applied about its center. Its angular acceleration is:","o":["10 rad/s²","5 rad/s²","20 rad/s²","2.5 rad/s²"],"c":0,"e":"I = ½(4.0)(0.50²) = 0.5 kg·m². α = τ/I = 5.0/0.5 = 10 rad/s²."},
  {"i":"phys-b3-0314","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"Two satellites orbit Earth, one at radius R and another at radius 4R. The ratio of the orbital period of the outer to the inner (T₄ₐ/T_R) is:","o":["8","4","2","16"],"c":0,"e":"By Kepler's third law T² ∝ r³, so T ∝ r^(3/2). Ratio = 4^(3/2) = 8."},
  {"i":"phys-b3-0315","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 2.0 kg object moving at 3.0 m/s collides head-on and sticks to a stationary 4.0 kg object. The kinetic energy lost in the collision is:","o":["6.0 J","3.0 J","9.0 J","2.0 J"],"c":0,"e":"By momentum: v = (2×3)/6 = 1.0 m/s. KE_i = ½(2)(9) = 9 J; KE_f = ½(6)(1) = 3 J. Lost = 6.0 J."},
  {"i":"phys-b3-0316","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"A 0.40 kg aluminium cup (c = 900 J/kg·K) contains 0.30 kg of water (c = 4200 J/kg·K) at 20°C. A 0.10 kg iron block (c = 450 J/kg·K) at 200°C is dropped in. The final equilibrium temperature is closest to (ignore losses):","o":["24.9°C","30.0°C","22.0°C","40.0°C"],"c":0,"e":"Heat lost by iron = heat gained: 0.1×450×(200−T) = (0.4×900 + 0.3×4200)(T−20). 45(200−T) = 1620(T−20); 9000 − 45T = 1620T − 32400; 41400 = 1665T; T ≈ 24.9°C."},
  {"i":"phys-b3-0317","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"A metal rod 2.0 m long with cross-section 4.0×10⁻⁴ m² has thermal conductivity 200 W/m·K. Its ends are kept at 100°C and 20°C. The rate of heat conduction is:","o":["3.2 W","6.4 W","1.6 W","8.0 W"],"c":0,"e":"Q/t = kAΔT/L = 200×4.0×10⁻⁴×80/2.0 = 3.2 W."},
  {"i":"phys-b3-0318","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Two point charges +4 μC and −1 μC are placed 30 cm apart in air. At what point on the line through them is the net electric field zero?","o":["30 cm beyond the −1 μC charge (on the side away from +4 μC)","15 cm beyond the −1 μC charge","30 cm beyond the +4 μC charge","at the midpoint between them"],"c":0,"e":"The null point lies beyond the smaller (−1 μC) charge. With x = distance from −1 μC: 4/(0.30+x)² = 1/x² gives 2x = 0.30+x, x = 0.30 m = 30 cm beyond the −1 μC charge."},
  {"i":"phys-b3-0319","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A battery of emf 12 V and internal resistance 0.5 Ω is connected to two resistors, 4 Ω and 6 Ω, in parallel. The current drawn from the battery is:","o":["4.14 A","1.2 A","2.0 A","5.0 A"],"c":0,"e":"Parallel R = (4×6)/(4+6) = 2.4 Ω. Total = 2.4 + 0.5 = 2.9 Ω. I = 12/2.9 = 4.14 A."},
  {"i":"phys-b3-0320","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Two capacitors, 3 μF and 6 μF, are connected in series across a 12 V source. The charge on each capacitor is:","o":["24 μC","36 μC","72 μC","12 μC"],"c":0,"e":"Series C = (3×6)/(3+6) = 2 μF. Q = CV = 2×12 = 24 μC, and capacitors in series carry equal charge of 24 μC each."},
  {"i":"phys-b3-0321","g":11,"u":"Nuclear Physics","d":"hard","t":"calculation","q":"A radioactive isotope has a half-life of 8 days. A sample's activity drops to 12.5% of its initial value after:","o":["24 days","16 days","32 days","12 days"],"c":0,"e":"12.5% = 1/8 = (1/2)³, so 3 half-lives elapsed: 3 × 8 = 24 days."},
  {"i":"phys-b3-0322","g":11,"u":"Physics & Human Society","d":"hard","t":"conceptual","q":"A research team in Bishoftu builds a model that predicts rainfall from past data. After it fails to predict an unusual flood, they refine the model with the new data. Which feature of the scientific method does this revision best illustrate?","o":["Science accepts a hypothesis permanently once it is published","Models are tentative and revised when new evidence contradicts predictions","A single failed prediction proves the entire theory is useless","Empirical data is less reliable than theoretical reasoning"],"c":1,"e":"The scientific method is self-correcting: hypotheses and models are provisional and refined as new evidence arises, which is exactly what the team did."},
  {"i":"phys-b3-0323","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"A drone flies 60 m on a bearing of N30°E, then 80 m due East. What is the magnitude of its total displacement from the start?","o":["About 121 m","About 140 m","About 100 m","About 92 m"],"c":0,"e":"N30°E gives east 60·sin30°=30, north 60·cos30°=51.96. Total east=30+80=110, north=51.96. Magnitude=√(110²+51.96²)=√14800≈121.7 m."},
  {"i":"phys-b3-0324","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"Two forces of 12 N and 5 N act on a point. If their resultant has magnitude 13 N, what is the angle between the two forces?","o":["90°","60°","120°","45°"],"c":0,"e":"R²=A²+B²+2AB·cosθ: 169=144+25+120cosθ → 169=169+120cosθ → cosθ=0, so θ=90°."},
  {"i":"phys-b3-0325","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A ball is thrown straight up from the edge of a 25 m cliff in Lalibela at 15 m/s. Using g=9.8 m/s², how long after launch does it hit the ground at the cliff base?","o":["About 4.27 s","About 3.06 s","About 1.53 s","About 2.14 s"],"c":0,"e":"Taking up positive: -25=15t-4.9t² → 4.9t²-15t-25=0 → t=(15+√(225+490))/9.8=(15+26.74)/9.8≈4.26 s."},
  {"i":"phys-b3-0326","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A projectile is launched at 40 m/s at 53° above the horizontal. Using g=9.8 m/s², what is its height above the launch point when it has travelled a horizontal distance of 60 m?","o":["About 49.2 m","About 45.0 m","About 35.2 m","About 60.0 m"],"c":0,"e":"vₓ=40cos53°=24.07, so t=60/24.07=2.493 s. v_y=40sin53°=31.95. y=31.95·2.493−4.9·2.493²=79.66−30.45≈49.2 m."},
  {"i":"phys-b3-0327","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A car accelerates uniformly from rest, covering 24 m in the 3rd second of its motion. What is its acceleration?","o":["About 9.6 m/s²","About 8.0 m/s²","About 4.8 m/s²","About 12.0 m/s²"],"c":0,"e":"Distance in the nth second = a(2n−1)/2. For n=3: 24=a(5)/2 → a=48/5=9.6 m/s²."},
  {"i":"phys-b3-0328","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 4 kg block on a horizontal surface (μ_k=0.25) is pulled by a 20 N force at 30° above the horizontal. Using g=9.8 m/s², what is its acceleration?","o":["About 2.51 m/s²","About 4.33 m/s²","About 1.90 m/s²","About 3.50 m/s²"],"c":0,"e":"N=mg−Fsin30°=39.2−10=29.2 N. Friction=0.25·29.2=7.3 N. Net=Fcos30°−f=17.32−7.3=10.02 N. a=10.02/4≈2.51 m/s²."},
  {"i":"phys-b3-0329","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"Two masses 3 kg and 5 kg are connected by a string over a frictionless pulley (Atwood machine). Using g=9.8 m/s², what is the tension in the string?","o":["About 36.75 N","About 49.0 N","About 24.5 N","About 19.6 N"],"c":0,"e":"a=(5−3)g/(5+3)=2(9.8)/8=2.45 m/s². T=m₁(g+a)=3(9.8+2.45)=3(12.25)=36.75 N."},
  {"i":"phys-b3-0330","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 1200 kg car rounds an unbanked curve of radius 50 m. If the coefficient of static friction is 0.40 and g=9.8 m/s², what is the maximum speed without skidding?","o":["About 14.0 m/s","About 19.6 m/s","About 10.0 m/s","About 22.1 m/s"],"c":0,"e":"Max friction provides centripetal force: μmg=mv²/r → v=√(μgr)=√(0.40·9.8·50)=√196=14.0 m/s."},
  {"i":"phys-b3-0331","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 0.15 kg ball moving at 12 m/s strikes a wall and rebounds at 8 m/s in the opposite direction. If contact lasts 0.02 s, what is the average force on the ball?","o":["150 N","30 N","60 N","75 N"],"c":0,"e":"Δp=m(v_f−v_i)=0.15(−8−12)=−3 kg·m/s. F=Δp/Δt=3/0.02=150 N in magnitude."},
  {"i":"phys-b3-0332","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 2 kg object moving at 6 m/s collides head-on and sticks to a stationary 4 kg object. How much kinetic energy is lost in this collision?","o":["24 J","12 J","36 J","8 J"],"c":0,"e":"Common velocity v=(2·6)/6=2 m/s. KE_i=½·2·36=36 J. KE_f=½·6·4=12 J. Lost=36−12=24 J."},
  {"i":"phys-b3-0333","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A solid disc of radius 0.2 m and moment of inertia 0.5 kg·m² is acted on by a tangential force of 10 N at its rim. What is its angular acceleration?","o":["4 rad/s²","2 rad/s²","10 rad/s²","20 rad/s²"],"c":0,"e":"Torque τ=F·r=10·0.2=2 N·m. α=τ/I=2/0.5=4 rad/s²."},
  {"i":"phys-b3-0334","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A satellite orbits Earth at radius r with period T. If it is moved to a new circular orbit of radius 4r, by what factor does its orbital period change?","o":["8 times longer","4 times longer","2 times longer","16 times longer"],"c":0,"e":"By Kepler's third law T²∝r³, so T_new/T=4^(3/2)=8. The period becomes 8 times longer."},
  {"i":"phys-b3-0335","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"The acceleration due to gravity at Earth's surface is 9.8 m/s². At what altitude (in Earth radii R above the surface) is g reduced to 1/9 of its surface value?","o":["2R","3R","8R","9R"],"c":0,"e":"g∝1/d² measured from the center. 1/9 means d=3R from the center, so altitude=3R−R=2R above the surface."},
  {"i":"phys-b3-0336","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 60 kg athlete in Addis runs up a 5 m high staircase in 4 s. Using g=9.8 m/s², what is the average power output against gravity?","o":["735 W","588 W","2940 W","1470 W"],"c":0,"e":"Work=mgh=60·9.8·5=2940 J. Power=2940/4=735 W."},
  {"i":"phys-b3-0337","g":11,"u":"Dynamics","d":"hard","t":"conceptual","q":"A uniform ladder leans against a frictionless wall, with friction only at the floor. As a person climbs higher up the ladder, what happens to the friction force the floor must provide to keep it from slipping?","o":["It increases","It decreases","It stays constant","It first decreases then increases"],"c":0,"e":"Torque balance shows the wall's normal force, equal to the required floor friction, grows as the load moves up, so the needed friction increases."},
  {"i":"phys-b3-0338","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"A copper rod 0.5 m long with cross-section 4×10⁻⁴ m² conducts heat between ends at 100°C and 20°C. With thermal conductivity 400 W/m·K, what is the rate of heat flow?","o":["25.6 W","12.8 W","51.2 W","6.4 W"],"c":0,"e":"Q/t=kAΔT/L=(400·4×10⁻⁴·80)/0.5=12.8/0.5=25.6 W."},
  {"i":"phys-b3-0339","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"How much heat is needed to convert 0.2 kg of ice at 0°C completely to water at 20°C? (L_f=3.34×10⁵ J/kg, c_water=4186 J/kg·°C)","o":["About 83,544 J","About 66,800 J","About 16,744 J","About 100,288 J"],"c":0,"e":"Melt: 0.2·3.34×10⁵=66,800 J. Warm: 0.2·4186·20=16,744 J. Total=66,800+16,744=83,544 J."},
  {"i":"phys-b3-0340","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Two point charges +3 μC and −5 μC are 0.3 m apart in air (k=9×10⁹ N·m²/C²). What is the magnitude of the force between them?","o":["1.5 N","0.5 N","3.0 N","15 N"],"c":0,"e":"F=k·q₁q₂/r²=9×10⁹·(3×10⁻⁶·5×10⁻⁶)/0.09=0.135/0.09=1.5 N."},
  {"i":"phys-b3-0341","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"A 12 V battery with internal resistance 0.5 Ω is connected to two resistors, 4 Ω and 6 Ω, in parallel. What current is drawn from the battery?","o":["About 4.14 A","About 3.0 A","About 2.0 A","About 1.20 A"],"c":0,"e":"Parallel: (4·6)/(4+6)=2.4 Ω. Total=2.4+0.5=2.9 Ω. I=12/2.9≈4.14 A."},
  {"i":"phys-b3-0342","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"In a circuit a 6 Ω and a 3 Ω resistor are in parallel, and this combination is in series with a 4 Ω resistor across a 12 V source of negligible internal resistance. What power is dissipated in the 4 Ω resistor?","o":["16 W","8 W","4 W","2 W"],"c":0,"e":"Parallel: (6·3)/9=2 Ω. Total=2+4=6 Ω. I=12/6=2 A. P₄=I²R=4·4=16 W."},
  {"i":"phys-b3-0343","g":11,"u":"Nuclear Physics","d":"hard","t":"calculation","q":"A radioactive isotope has a half-life of 8 days. A sample starts with 4.0×10²⁰ nuclei. How many remain undecayed after 24 days?","o":["5.0×10¹⁹","1.0×10²⁰","2.0×10²⁰","2.5×10¹⁹"],"c":0,"e":"24 days = 3 half-lives. Remaining = 4.0×10²⁰·(1/2)³ = 4.0×10²⁰/8 = 5.0×10¹⁹ nuclei."},
  {"i":"phys-b3-0344","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A stone is thrown horizontally at 15 m/s from the top of a cliff near Sodere and lands 45 m horizontally from the base. Using g = 9.8 m/s², what is the height of the cliff?","o":["44.1 m","22.1 m","30.0 m","88.2 m"],"c":0,"e":"Time of flight: t = 45/15 = 3 s. Height h = ½gt² = ½(9.8)(9) = 44.1 m."},
  {"i":"phys-b3-0345","g":11,"u":"Motion in One and Two Dimensions","d":"hard","t":"calculation","q":"A projectile is launched at 40 m/s at 30° above the horizontal. What is the maximum height it reaches? (g = 9.8 m/s²)","o":["20.4 m","40.8 m","10.2 m","61.2 m"],"c":0,"e":"Vertical component v_y = 40 sin30° = 20 m/s. H = v_y²/(2g) = 400/19.6 = 20.4 m."},
  {"i":"phys-b3-0346","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 10 kg block on a horizontal surface (μ_k = 0.25) is pulled by a 50 N horizontal force. What is its acceleration? (g = 9.8 m/s²)","o":["2.55 m/s²","5.00 m/s²","2.45 m/s²","3.05 m/s²"],"c":0,"e":"Friction = μ_k m g = 0.25(10)(9.8) = 24.5 N. a = (50 − 24.5)/10 = 25.5/10 = 2.55 m/s²."},
  {"i":"phys-b3-0347","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"Two masses, 3 kg and 5 kg, are connected by a light string over a frictionless pulley (Atwood machine). What is the magnitude of the acceleration of the system? (g = 9.8 m/s²)","o":["2.45 m/s²","4.90 m/s²","1.96 m/s²","9.80 m/s²"],"c":0,"e":"a = (m₂ − m₁)g/(m₁ + m₂) = (5 − 3)(9.8)/8 = 19.6/8 = 2.45 m/s²."},
  {"i":"phys-b3-0348","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 1200 kg car traveling at 20 m/s collides head-on and sticks to a stationary 800 kg car. What is their common velocity immediately after the perfectly inelastic collision?","o":["12 m/s","8 m/s","20 m/s","10 m/s"],"c":0,"e":"Momentum conservation: (1200)(20) = (1200 + 800)v, so v = 24000/2000 = 12 m/s."},
  {"i":"phys-b3-0349","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A solid sphere of mass 2 kg and radius 0.1 m rolls without slipping at 4 m/s. What is its total kinetic energy? (I = (2/5)mr² for a solid sphere)","o":["22.4 J","16.0 J","32.0 J","11.2 J"],"c":0,"e":"Total KE = ½mv²(1 + 2/5) = ½(2)(16)(7/5) = 16(1.4) = 22.4 J."},
  {"i":"phys-b3-0350","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A satellite orbits Earth in a circle at radius 7.0 × 10⁶ m where the gravitational field strength is 8.0 m/s². What is the satellite's orbital speed?","o":["7.48 km/s","5.92 km/s","56.0 km/s","2.37 km/s"],"c":0,"e":"For a circular orbit g = v²/r, so v = √(gr) = √(8.0 × 7.0×10⁶) = √(5.6×10⁷) ≈ 7483 m/s ≈ 7.48 km/s."},
  {"i":"phys-b3-0351","g":11,"u":"Dynamics","d":"hard","t":"calculation","q":"A 0.5 kg ball moving at 8 m/s is struck and rebounds straight back at 6 m/s. If contact lasts 0.02 s, what is the magnitude of the average force on the ball?","o":["350 N","50 N","100 N","175 N"],"c":0,"e":"Δp = m(v_f − v_i) = 0.5(−6 − 8) = −7 kg·m/s. F = |Δp|/Δt = 7/0.02 = 350 N."},
  {"i":"phys-b3-0352","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"Two forces, 6 N east and 8 N north, act on a point. A third force is added so the object is in equilibrium. What is the magnitude and direction of the third force?","o":["10 N, 53° S of W","10 N, 37° S of W","14 N, due SW","2 N, due W"],"c":0,"e":"Resultant of the two = √(6²+8²) = 10 N at tan⁻¹(8/6) = 53° N of E. The equilibrant is 10 N in the opposite direction: 53° S of W."},
  {"i":"phys-b3-0353","g":11,"u":"Vectors","d":"hard","t":"calculation","q":"Vector A = 3î + 4ĵ and vector B = −2î + 6ĵ. What is the angle between them? (cosθ = (A·B)/(|A||B|))","o":["55.3°","43.0°","30.0°","90.0°"],"c":0,"e":"A·B = (3)(−2)+(4)(6) = 18. |A| = 5, |B| = √40 = 6.32. cosθ = 18/31.6 = 0.569, so θ ≈ 55.3°."},
  {"i":"phys-b3-0354","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"A copper rod 0.5 m long with cross-section 4 × 10⁻⁴ m² conducts heat between ends held at 100°C and 20°C. If k = 400 W/(m·K), what is the rate of heat flow?","o":["25.6 W","12.8 W","51.2 W","6.4 W"],"c":0,"e":"Q/t = kA ΔT/L = 400(4×10⁻⁴)(80)/0.5 = (0.16)(80)/0.5 = 12.8/0.5 = 25.6 W."},
  {"i":"phys-b3-0355","g":11,"u":"Heat Conduction & Calorimetry","d":"hard","t":"calculation","q":"A 0.2 kg piece of iron (c = 450 J/kg·K) at 150°C is dropped into 0.5 kg of water (c = 4200 J/kg·K) at 20°C. What is the final equilibrium temperature? (ignore the container)","o":["25.3°C","85.0°C","22.5°C","30.4°C"],"c":0,"e":"Heat lost = heat gained: 0.2(450)(150−T) = 0.5(4200)(T−20). 90(150−T)=2100(T−20); 13500−90T=2100T−42000; 55500=2190T; T ≈ 25.3°C."},
  {"i":"phys-b3-0356","g":11,"u":"Electrostatics & Electric Circuit","d":"hard","t":"calculation","q":"Two point charges, +4 μC and −2 μC, are 0.3 m apart. What is the magnitude of the electrostatic force between them? (k = 9 × 10⁹ N·m²/C²)","o":["0.8 N","1.6 N","0.4 N","8.0 N"],"c":0,"e":"F = k|q₁q₂|/r² = 9×10⁹(4×10⁻⁶)(2×10⁻⁶)/(0.3²) = 9×10⁹(8×10⁻¹²)/0.09 = 0.072/0.09 = 0.8 N."},
  {"i":"phys-b3-0357","g":11,"u":"Physics & Human Society","d":"hard","t":"conceptual","q":"A factory near Addis Ababa uses a 2.0 kW electric motor for 5 hours each day. Ethiopian electric energy is billed per kilowatt-hour. How much electrical energy does the motor consume in one day?","o":["10 kWh","2.5 kWh","36 MJ only","0.4 kWh"],"c":0,"e":"Energy = power × time = 2.0 kW × 5 h = 10 kWh (equivalently 36 MJ), the quantity an electricity meter records for billing."},
  {"i":"phys-b3-0358","g":11,"u":"Nuclear Physics","d":"hard","t":"calculation","q":"A radioactive isotope has a half-life of 8 days. A sample starts with 6.4 × 10²⁰ atoms. How many atoms remain undecayed after 24 days?","o":["8.0 × 10¹⁹","1.6 × 10²⁰","3.2 × 10²⁰","4.0 × 10¹⁹"],"c":0,"e":"24 days = 3 half-lives. Remaining = 6.4×10²⁰ × (½)³ = 6.4×10²⁰/8 = 8.0×10¹⁹ atoms."},
  {"i":"phys-b3-0359","g":11,"u":"Physics & Human Society","d":"impossible","t":"conceptual","q":"A science journalist claims a new 'over-unity' machine in Addis Ababa delivers 1.2 J of electrical output for every 1.0 J of input, running indefinitely with no fuel. On strictly physical grounds, which single statement most rigorously rejects the claim?","o":["It violates conservation of energy, since a closed cyclic device cannot output more energy than it takes in plus any energy drawn from a store.","It violates Newton's third law because output and input forces are unequal.","It is impossible because all real machines have exactly 100% efficiency.","It is wrong because electrical energy can never be converted back into mechanical energy."],"c":0,"e":"A cyclic machine returning to its initial state cannot create net energy; output exceeding input with no energy source violates the first law of thermodynamics (conservation of energy). Real machines have efficiency below 100%, not equal to it."},
  {"i":"phys-b3-0360","g":11,"u":"Vectors","d":"impossible","t":"calculation","q":"Three coplanar forces act on a point in equilibrium. Two of them are 8 N due East and 6 N due North. The third force exactly balances them. What are its magnitude and direction?","o":["10 N directed S 53° W (i.e. into the third quadrant)","14 N directed South-West","10 N directed N 37° E","2 N directed due West"],"c":0,"e":"The resultant of 8 N E and 6 N N is √(8²+6²)=10 N at angle arctan(6/8)=37° N of E. The equilibrant is equal and opposite: 10 N pointing into the third quadrant, 53° West of South."},
  {"i":"phys-b3-0361","g":11,"u":"Vectors","d":"impossible","t":"calculation","q":"Vector A has magnitude 5 and B has magnitude 12. Their resultant (A + B) has magnitude 13. What is the magnitude of A − B?","o":["13","17","7","1"],"c":0,"e":"Since 5²+12²=13², A and B are perpendicular, so A·B=0. Then |A−B|²=25+144−2(0)=169, giving |A−B|=13, identical to |A+B| because the vectors are orthogonal."},
  {"i":"phys-b3-0362","g":11,"u":"Motion in One and Two Dimensions","d":"impossible","t":"calculation","q":"A projectile is launched from level ground so that its maximum height equals its horizontal range. What is the launch angle above the horizontal? (g = 9.8 m/s²)","o":["≈ 76°","45°","≈ 60°","≈ 26.6°"],"c":0,"e":"H = R gives (v²sin²θ)/(2g) = (v²sin2θ)/g, so sin²θ = 2·(2 sinθ cosθ), i.e. tanθ = 4. Thus θ = arctan 4 ≈ 76°."},
  {"i":"phys-b3-0363","g":11,"u":"Motion in One and Two Dimensions","d":"impossible","t":"calculation","q":"A boat that moves at 5 m/s relative to water must cross a 200 m wide river whose current flows at 3 m/s. The pilot points the boat to achieve the SHORTEST crossing TIME. How far downstream does the boat land?","o":["120 m","160 m","0 m","75 m"],"c":0,"e":"Shortest time means heading straight across (full 5 m/s across the width): t = 200/5 = 40 s. During that time the current carries the boat 3 × 40 = 120 m downstream."},
  {"i":"phys-b3-0364","g":11,"u":"Motion in One and Two Dimensions","d":"impossible","t":"calculation","q":"A stone is thrown and, at the highest point of its trajectory, its speed is 8 m/s. Given g = 9.8 m/s², what is its speed exactly 2 s after passing the apex (still in flight)?","o":["≈ 21.2 m/s","≈ 27.6 m/s","8 m/s","≈ 19.6 m/s"],"c":0,"e":"At the apex the velocity is purely horizontal, 8 m/s. After 2 s the vertical component is gt = 19.6 m/s. Speed = √(8² + 19.6²) = √(64+384.16) ≈ 21.2 m/s."},
  {"i":"phys-b3-0365","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A 4 kg block rests on a 30° incline (μ = 0.2) and is connected over an ideal pulley to a 3 kg hanging mass. The system is released. What is the magnitude of the acceleration? (g = 9.8 m/s²)","o":["≈ 0.43 m/s²","≈ 1.4 m/s²","≈ 2.8 m/s²","0 m/s² (it stays static)"],"c":0,"e":"Hanging mass tends to pull the block up the incline. Net force = m₂g − m₁g sin30° − μm₁g cos30° = 29.4 − 19.6 − 0.2(33.9) = 3.01 N over 7 kg, giving a ≈ 0.43 m/s². Friction opposes the impending up-incline motion."},
  {"i":"phys-b3-0366","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"In an Atwood machine the pulley is a uniform disk of mass 4 kg, and the hanging masses are 2 kg and 3 kg. The string does not slip. What is the acceleration of the masses? (g = 9.8 m/s²)","o":["1.4 m/s²","≈ 1.96 m/s²","2.45 m/s²","≈ 1.12 m/s²"],"c":0,"e":"With pulley moment of inertia I = ½MR², a = (m₂−m₁)g / (m₁+m₂+½M) = (1)(9.8)/(2+3+2) = 9.8/7 = 1.4 m/s². The pulley's rotational inertia adds an effective ½M = 2 kg."},
  {"i":"phys-b3-0367","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A 10 g bullet embeds in a 1.99 kg wooden block hanging as a pendulum, and the block-bullet system rises 20 cm. What was the bullet's speed just before impact? (g = 9.8 m/s²)","o":["≈ 396 m/s","≈ 1.98 m/s","≈ 280 m/s","≈ 198 m/s"],"c":0,"e":"After impact V = √(2gh) = √(2·9.8·0.2) = 1.98 m/s. Momentum conservation in the collision: mv = (m+M)V, so v = (2.00)(1.98)/0.010 ≈ 396 m/s."},
  {"i":"phys-b3-0368","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A solid sphere and a uniform disk of equal mass and radius are released from rest and roll without slipping down the same 30° incline. By what factor does the sphere's acceleration exceed the disk's?","o":["≈ 1.07","1.40","1.00","≈ 1.67"],"c":0,"e":"Rolling acceleration a = g sinθ /(1 + I/mR²). Sphere: (5/7)g sinθ; disk: (2/3)g sinθ. Ratio = (5/7)/(2/3) = 15/14 ≈ 1.07."},
  {"i":"phys-b3-0369","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A small bead slides on a frictionless vertical circular loop of radius 2 m. What is the minimum speed it must have at the LOWEST point so that it just maintains contact at the TOP of the loop? (g = 9.8 m/s²)","o":["≈ 9.9 m/s","≈ 4.4 m/s","≈ 6.3 m/s","≈ 14.0 m/s"],"c":0,"e":"At the top, minimum condition v_top² = gr. Energy conservation from bottom to top (height 2r): v_bottom² = v_top² + 2g(2r) = gr + 4gr = 5gr. v_bottom = √(5·9.8·2) ≈ 9.9 m/s."},
  {"i":"phys-b3-0370","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A satellite orbits Earth at radius r with period T. A second satellite orbits the same planet at radius 4r. What is the period of the second satellite?","o":["8T","16T","4T","2√2 · T"],"c":0,"e":"By Kepler's third law T² ∝ r³, so T₂/T₁ = (r₂/r₁)^(3/2) = 4^(3/2) = 8. The second satellite's period is 8T."},
  {"i":"phys-b3-0371","g":11,"u":"Dynamics","d":"impossible","t":"conceptual","q":"At what height above Earth's surface (Earth radius R) does the gravitational field strength fall to exactly one-quarter of its surface value?","o":["At height R (one Earth radius up)","At height 2R","At height R/2","At height 3R"],"c":0,"e":"g(h) = GM/(R+h)². Setting this to g_surface/4 = GM/(4R²) requires (R+h)² = 4R², so R+h = 2R, hence h = R."},
  {"i":"phys-b3-0372","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A block leaves the bottom of a frictionless curved ramp (having descended 1.8 m) and then slides onto a rough horizontal patch with μ = 0.3, where it comes to rest. How long is the rough patch? (g = 9.8 m/s²)","o":["6.0 m","3.0 m","1.8 m","9.0 m"],"c":0,"e":"Speed at base: v² = 2gh = 2·9.8·1.8 = 35.28 m²/s². On the rough patch v² = 2μg·d, so d = 35.28/(2·0.3·9.8) = 35.28/5.88 = 6.0 m."},
  {"i":"phys-b3-0373","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A car of mass 1000 kg rounds an unbanked curve of radius 50 m at 15 m/s. The road can supply a maximum static friction coefficient of 0.4. Does it slip, and what minimum μ is required? (g = 9.8 m/s²)","o":["μ needed ≈ 0.46, so it slips","μ needed ≈ 0.31, so it holds","μ needed ≈ 0.23, so it holds","μ needed ≈ 0.61, so it slips"],"c":0,"e":"Required centripetal acceleration v²/r = 225/50 = 4.5 m/s². Needed μ = a/g = 4.5/9.8 ≈ 0.46, which exceeds 0.4, so the car slips outward."},
  {"i":"phys-b3-0374","g":11,"u":"Heat Conduction & Calorimetry","d":"impossible","t":"calculation","q":"50 g of ice at 0 °C is dropped into 200 g of water at 30 °C in an insulated cup. (L_f = 334 J/g, c_water = 4.18 J/g·°C.) What is the final equilibrium temperature?","o":["≈ 8.0 °C","0 °C with some ice left","≈ 13.4 °C","≈ 24.0 °C"],"c":0,"e":"Heat to melt all ice = 50·334 = 16,700 J; water can release 200·4.18·30 = 25,080 J > that, so all ice melts. Remaining 8,380 J warms 250 g of water: ΔT = 8380/(250·4.18) ≈ 8.0 °C."},
  {"i":"phys-b3-0375","g":11,"u":"Heat Conduction & Calorimetry","d":"impossible","t":"calculation","q":"Two rods of equal length and cross-section are joined end to end. Their thermal conductivities are 400 W/m·K (copper) and 200 W/m·K (aluminium). The free copper end is at 100 °C and the free aluminium end at 0 °C, in steady state. What is the junction temperature?","o":["≈ 66.7 °C","50 °C","≈ 33.3 °C","≈ 75 °C"],"c":0,"e":"In series steady state the heat current is equal: k₁(100−T)/L = k₂(T−0)/L. With k₁=400, k₂=200: 400(100−T)=200T → 40000 = 600T → T ≈ 66.7 °C. The better conductor sustains the smaller temperature drop."},
  {"i":"phys-b3-0376","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"Two point charges, +9 μC and +4 μC, are fixed 1.0 m apart. At what distance from the +9 μC charge, along the line joining them, is the net electric field zero?","o":["0.60 m","0.40 m","0.69 m","0.50 m"],"c":0,"e":"The null point lies between the like charges. Setting fields equal: 9/x² = 4/(1−x)² gives 3(1−x) = 2x, so 3 = 5x, x = 0.60 m from the +9 μC charge."},
  {"i":"phys-b3-0377","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"A battery of EMF 12 V and internal resistance 1 Ω drives two 6 Ω resistors connected in parallel. What is the terminal voltage of the battery?","o":["9 V","12 V","6 V","8 V"],"c":0,"e":"Two 6 Ω in parallel give 3 Ω. Total circuit resistance = 4 Ω, so current = 12/4 = 3 A. Terminal voltage = EMF − Ir = 12 − 3·1 = 9 V."},
  {"i":"phys-b3-0378","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"Capacitors of 3 μF and 6 μF are connected in parallel, and that combination is connected in series with a 2 μF capacitor. What is the equivalent capacitance of the network?","o":["≈ 1.64 μF","11 μF","≈ 0.55 μF","≈ 2.18 μF"],"c":0,"e":"Parallel: 3 + 6 = 9 μF. In series with 2 μF: C_eq = (9·2)/(9+2) = 18/11 ≈ 1.64 μF. Series capacitance is always less than the smaller member."},
  {"i":"phys-b3-0379","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"A windowpane of area 2.0 m² and thickness 5.0 mm has thermal conductivity 0.8 W/m·K, with inner and outer surfaces differing by 20 °C. Treating it purely by conduction, what is the rate of heat loss through the glass?","o":["6.4 kW","0.64 kW","16 kW","3.2 kW"],"c":0,"e":"Q/t = kAΔT/L = (0.8·2.0·20)/0.005 = 32/0.005 = 6400 W = 6.4 kW. The thin pane gives a very large conductive loss, which is why double glazing traps insulating air instead."},
  {"i":"phys-b3-0380","g":11,"u":"Nuclear Physics","d":"impossible","t":"calculation","q":"A radioactive sample's activity falls from 6400 Bq to 800 Bq in 30 minutes. What is its half-life?","o":["10 minutes","15 minutes","7.5 minutes","5 minutes"],"c":0,"e":"6400 → 800 is a factor of 8 = 2³, i.e. three half-lives. Three half-lives span 30 minutes, so one half-life = 10 minutes."},
  {"i":"phys-b3-0381","g":11,"u":"Dynamics","d":"impossible","t":"calculation","q":"A solid uniform sphere (moment of inertia 2/5·m·r²) is released from rest and rolls without slipping down an incline tilted at 30° to the horizontal. What is the minimum coefficient of static friction between the sphere and the surface needed to sustain pure rolling?","o":["0.165","0.231","0.412","0.577"],"c":0,"e":"For rolling without slipping the friction is f = (2/5)m·a with a = (5/7)g·sinθ, giving f = (2/7)mg·sinθ; so μ_min = f/N = (2/7)tan30° = (2/7)(0.577) ≈ 0.165. Using the wrong inertia factor gives the 0.231 trap."},
  {"i":"phys-b3-0382","g":11,"u":"Electrostatics & Electric Circuit","d":"impossible","t":"calculation","q":"An electron enters along the central axis between two horizontal parallel plates 1.0 cm apart and 5.0 cm long, moving horizontally at 3.0×10⁷ m/s. A 200 V potential difference is applied across the plates. (electron: e = 1.6×10⁻¹⁹ C, m = 9.11×10⁻³¹ kg.) What is the vertical deflection as it leaves the field region, and does it clear the plates?","o":["≈4.9 mm; it just exits without striking a plate","≈4.9 mm; it strikes a plate before exiting","≈9.8 mm; it strikes a plate","≈2.4 mm; it just exits"],"c":0,"e":"E = V/d = 2.0×10⁴ V/m, so y = eEL²/(2mv²) = (1.6×10⁻¹⁹·2.0×10⁴·0.05²)/(2·9.11×10⁻³¹·(3.0×10⁷)²) ≈ 4.9×10⁻³ m. Since 4.9 mm is below the half-gap of 5.0 mm, the electron just clears the plate. Dropping the factor of 2 gives the 9.8 mm trap."},
  {"i":"phys-b3-0383","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A football is kicked horizontally off a flat rooftop and stays in the air for 2.0 s before landing. Taking g = 9.8 m/s², what is its vertical velocity just before it lands?","o":["9.8 m/s","19.6 m/s","4.9 m/s","39.2 m/s"],"c":1,"e":"For horizontal launch the initial vertical velocity is 0, so v = g·t = 9.8 × 2.0 = 19.6 m/s."},
  {"i":"phys-b3-0384","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A stone is thrown straight up with an initial speed of 14 m/s. Using g = 9.8 m/s², how long does it take to reach its highest point?","o":["0.7 s","1.43 s","2.86 s","1.0 s"],"c":1,"e":"At the top v = 0, so t = v₀/g = 14/9.8 ≈ 1.43 s."},
  {"i":"phys-b3-0385","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A projectile is launched at 30° above the horizontal with a speed of 20 m/s. What is the horizontal component of its initial velocity? (cos30° ≈ 0.87)","o":["10 m/s","17.3 m/s","20 m/s","11.5 m/s"],"c":1,"e":"vₓ = v·cosθ = 20 × cos30° = 20 × 0.866 ≈ 17.3 m/s."},
  {"i":"phys-b3-0386","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"conceptual","q":"For a projectile launched at an angle (neglecting air resistance), which quantity stays constant throughout the flight?","o":["Vertical velocity component","Horizontal velocity component","Total speed","Vertical acceleration is zero"],"c":1,"e":"With no air resistance, no horizontal force acts, so the horizontal velocity component remains constant while the vertical component changes due to gravity."},
  {"i":"phys-b3-0387","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A car moves around a circular track of radius 50 m at a constant speed of 10 m/s. What is the magnitude of its centripetal acceleration?","o":["0.2 m/s²","2.0 m/s²","5.0 m/s²","20 m/s²"],"c":1,"e":"a = v²/r = 10²/50 = 100/50 = 2.0 m/s²."},
  {"i":"phys-b3-0388","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 5.0 kg block on a frictionless surface is pushed by a constant horizontal force of 20 N. What is its acceleration?","o":["100 m/s²","4.0 m/s²","0.25 m/s²","25 m/s²"],"c":1,"e":"By Newton's second law a = F/m = 20/5.0 = 4.0 m/s²."},
  {"i":"phys-b3-0389","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 2.0 kg ball moving at 3.0 m/s collides and sticks to a stationary 4.0 kg ball. What is their common velocity after the collision?","o":["1.0 m/s","1.5 m/s","2.0 m/s","0.5 m/s"],"c":0,"e":"Momentum is conserved: (2.0×3.0)/(2.0+4.0) = 6.0/6.0 = 1.0 m/s."},
  {"i":"phys-b3-0390","g":12,"u":"Application of Physics","d":"easy","t":"definition","q":"The impulse delivered to an object is equal to the change in which physical quantity?","o":["Kinetic energy","Momentum","Acceleration","Displacement"],"c":1,"e":"Impulse equals the change in momentum: J = FΔt = Δp (the impulse–momentum theorem)."},
  {"i":"phys-b3-0391","g":12,"u":"Application of Physics","d":"easy","t":"conceptual","q":"A satellite is in uniform circular orbit. If the only force on it is gravity directed toward Earth, what is the direction of its net force?","o":["Along its velocity","Opposite its velocity","Toward the centre of the orbit","Zero"],"c":2,"e":"In uniform circular motion the net (centripetal) force points toward the centre of the circle, which is Earth's centre."},
  {"i":"phys-b3-0392","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A wheel rotating at 4.0 rad/s speeds up uniformly to 10 rad/s in 3.0 s. What is its angular acceleration?","o":["2.0 rad/s²","6.0 rad/s²","0.5 rad/s²","18 rad/s²"],"c":0,"e":"α = (ω − ω₀)/t = (10 − 4.0)/3.0 = 6.0/3.0 = 2.0 rad/s²."},
  {"i":"phys-b3-0393","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"How much work is done lifting a 10 kg sack of teff vertically through 2.0 m at constant speed? (g = 9.8 m/s²)","o":["20 J","49 J","196 J","98 J"],"c":2,"e":"W = mgh = 10 × 9.8 × 2.0 = 196 J."},
  {"i":"phys-b3-0394","g":12,"u":"Application of Physics","d":"easy","t":"definition","q":"Newton's law of universal gravitation states the force between two masses is inversely proportional to which quantity?","o":["The distance between them","The square of the distance between them","The sum of the masses","The product of the masses"],"c":1,"e":"F = Gm₁m₂/r², so the force is inversely proportional to the square of the separation distance."},
  {"i":"phys-b3-0395","g":12,"u":"Application of Physics","d":"easy","t":"conceptual","q":"A box rests on a horizontal floor without moving. According to Newton's third law, the reaction to the weight of the box (Earth pulling box down) is:","o":["The floor pushing up on the box","The box pulling Earth up","The box pushing down on the floor","The normal force on the box"],"c":1,"e":"The reaction pair to Earth's gravitational pull on the box is the box's equal gravitational pull on Earth, not the floor's normal force."},
  {"i":"phys-b3-0396","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"A force of 50 N is applied perpendicular to a surface of area 0.25 m². What pressure does it exert?","o":["12.5 Pa","200 Pa","100 Pa","0.005 Pa"],"c":1,"e":"P = F/A = 50/0.25 = 200 Pa."},
  {"i":"phys-b3-0397","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"What is the gauge pressure at a depth of 5.0 m in water? (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["49 000 Pa","5000 Pa","9800 Pa","50 000 Pa"],"c":0,"e":"P = ρgh = 1000 × 9.8 × 5.0 = 49 000 Pa."},
  {"i":"phys-b3-0398","g":12,"u":"Fluid Mechanics","d":"easy","t":"conceptual","q":"For an ideal fluid in steady flow through a pipe that narrows, Bernoulli's principle predicts that where the speed increases, the pressure:","o":["Increases","Decreases","Stays the same","Becomes zero"],"c":1,"e":"By Bernoulli's principle, an increase in fluid speed is accompanied by a decrease in pressure."},
  {"i":"phys-b3-0399","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A resistor of 4.0 Ω carries a current of 3.0 A. What is the potential difference across it?","o":["0.75 V","7.0 V","12 V","1.33 V"],"c":2,"e":"By Ohm's law V = IR = 3.0 × 4.0 = 12 V."},
  {"i":"phys-b3-0400","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"Two resistors of 6.0 Ω and 3.0 Ω are connected in parallel. What is their equivalent resistance?","o":["9.0 Ω","2.0 Ω","4.5 Ω","18 Ω"],"c":1,"e":"1/R = 1/6 + 1/3 = 1/6 + 2/6 = 3/6, so R = 2.0 Ω."},
  {"i":"phys-b3-0401","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A 2.0 m long wire carries a current of 5.0 A perpendicular to a magnetic field of 0.40 T. What force acts on the wire?","o":["4.0 N","1.6 N","10 N","0.16 N"],"c":0,"e":"F = BIL = 0.40 × 5.0 × 2.0 = 4.0 N."},
  {"i":"phys-b3-0402","g":12,"u":"Electromagnetism","d":"easy","t":"definition","q":"Faraday's law of electromagnetic induction states that the induced emf in a coil is proportional to the rate of change of:","o":["Electric current","Magnetic flux through the coil","Resistance of the coil","Charge on the coil"],"c":1,"e":"The induced emf equals the negative rate of change of magnetic flux: ε = −dΦ/dt."},
  {"i":"phys-b3-0403","g":12,"u":"Electronics","d":"easy","t":"definition","q":"In a forward-biased silicon p–n junction diode, the diode ideally:","o":["Blocks current completely","Allows current to flow easily","Acts as a perfect insulator","Stores charge like a capacitor"],"c":1,"e":"A forward-biased diode conducts, allowing current to flow easily, whereas reverse bias blocks it."},
  {"i":"phys-b3-0404","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A stone is thrown horizontally from a cliff at 12 m/s. Ignoring air resistance, what is its horizontal velocity after 2 s? (g = 9.8 m/s²)","o":["0 m/s","12 m/s","19.6 m/s","24 m/s"],"c":1,"e":"In projectile motion the horizontal velocity is constant because no horizontal force acts, so it stays 12 m/s."},
  {"i":"phys-b3-0405","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A ball is launched at 20 m/s at 30° above the horizontal. What is its initial vertical velocity component?","o":["10 m/s","17.3 m/s","20 m/s","6.7 m/s"],"c":0,"e":"The vertical component is v·sin30° = 20 × 0.5 = 10 m/s."},
  {"i":"phys-b3-0406","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"definition","q":"For an object in uniform circular motion, the direction of the centripetal acceleration is:","o":["Tangent to the circle","Directed toward the centre","Directed away from the centre","Along the velocity vector"],"c":1,"e":"Centripetal acceleration always points toward the centre of the circular path, changing the direction of velocity."},
  {"i":"phys-b3-0407","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A projectile is fired horizontally and falls for 3 s before landing. What vertical distance does it fall? (g = 9.8 m/s²)","o":["14.7 m","29.4 m","44.1 m","88.2 m"],"c":2,"e":"Vertical drop h = ½gt² = ½ × 9.8 × 3² = 44.1 m."},
  {"i":"phys-b3-0408","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A car moves around a circular track of radius 50 m at 10 m/s. What is its centripetal acceleration?","o":["0.2 m/s²","2 m/s²","5 m/s²","20 m/s²"],"c":1,"e":"a = v²/r = 10²/50 = 100/50 = 2 m/s²."},
  {"i":"phys-b3-0409","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 2 kg object is pushed by a net force of 10 N. What is its acceleration?","o":["2 m/s²","5 m/s²","12 m/s²","20 m/s²"],"c":1,"e":"By Newton's second law a = F/m = 10/2 = 5 m/s²."},
  {"i":"phys-b3-0410","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 4 kg trolley moving at 3 m/s has what magnitude of momentum?","o":["1.33 kg·m/s","7 kg·m/s","12 kg·m/s","36 kg·m/s"],"c":2,"e":"Momentum p = mv = 4 × 3 = 12 kg·m/s."},
  {"i":"phys-b3-0411","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A wheel completes 5 full revolutions. Through what angle (in radians) has it turned?","o":["5π rad","10π rad","2.5π rad","π rad"],"c":1,"e":"Each revolution is 2π rad, so 5 revolutions = 5 × 2π = 10π rad."},
  {"i":"phys-b3-0412","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 0.5 kg ball falls freely from rest. What is its speed after 2 s? (g = 9.8 m/s²)","o":["4.9 m/s","9.8 m/s","19.6 m/s","39.2 m/s"],"c":2,"e":"v = gt = 9.8 × 2 = 19.6 m/s (mass does not affect free-fall speed)."},
  {"i":"phys-b3-0413","g":12,"u":"Application of Physics","d":"easy","t":"definition","q":"The gravitational force between two masses, according to Newton's law of gravitation, is proportional to:","o":["The sum of the masses","The product of the masses","The difference of the masses","The square of the separation"],"c":1,"e":"F = Gm₁m₂/r²; the force is proportional to the product of the two masses."},
  {"i":"phys-b3-0414","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 1000 kg car accelerates from rest to 20 m/s. What is the change in its momentum?","o":["1000 kg·m/s","20000 kg·m/s","50 kg·m/s","2000 kg·m/s"],"c":1,"e":"Δp = mΔv = 1000 × (20 − 0) = 20000 kg·m/s."},
  {"i":"phys-b3-0415","g":12,"u":"Fluid Mechanics","d":"easy","t":"definition","q":"Pressure in a fluid at a given depth acts:","o":["Only downward","Only upward","Equally in all directions","Only sideways"],"c":2,"e":"Pascal's principle: at a point in a fluid, pressure acts equally in all directions."},
  {"i":"phys-b3-0416","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"What is the pressure due to a column of water 5 m deep? (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["4900 Pa","9800 Pa","49000 Pa","5000 Pa"],"c":2,"e":"P = ρgh = 1000 × 9.8 × 5 = 49000 Pa."},
  {"i":"phys-b3-0417","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"An object displaces 0.002 m³ of water when submerged. What is the buoyant force on it? (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["1.96 N","19.6 N","0.2 N","196 N"],"c":1,"e":"Buoyant force = ρVg = 1000 × 0.002 × 9.8 = 19.6 N."},
  {"i":"phys-b3-0418","g":12,"u":"Fluid Mechanics","d":"easy","t":"definition","q":"Archimedes' principle states that the buoyant force on a submerged object equals:","o":["The weight of the object","The weight of the fluid displaced","The volume of the object","The density of the fluid"],"c":1,"e":"The buoyant (upthrust) force equals the weight of the fluid displaced by the object."},
  {"i":"phys-b3-0419","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A resistor carries a current of 2 A under a potential difference of 12 V. What is its resistance?","o":["0.17 Ω","6 Ω","14 Ω","24 Ω"],"c":1,"e":"By Ohm's law R = V/I = 12/2 = 6 Ω."},
  {"i":"phys-b3-0420","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"Two point charges of +3 μC and +2 μC are separated by some distance giving a force F. The force between them is: (concept) proportional to the product of charges. If charge magnitudes both double, the force becomes:","o":["Twice F","Four times F","Half F","Unchanged"],"c":1,"e":"By Coulomb's law F ∝ q₁q₂; doubling both charges multiplies the product by 4, so force becomes 4F."},
  {"i":"phys-b3-0421","g":12,"u":"Electromagnetism","d":"easy","t":"definition","q":"The direction of the magnetic force on a positive charge moving in a magnetic field is given by:","o":["Right-hand rule","Lenz's law","Ohm's law","Hooke's law"],"c":0,"e":"The right-hand rule gives the direction of F = qv × B for a positive moving charge."},
  {"i":"phys-b3-0422","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A 60 W bulb operates on a 120 V supply. What current does it draw?","o":["0.5 A","2 A","7200 A","0.2 A"],"c":0,"e":"P = VI, so I = P/V = 60/120 = 0.5 A."},
  {"i":"phys-b3-0423","g":12,"u":"Electronics","d":"easy","t":"definition","q":"In a forward-biased silicon p-n junction diode, the diode:","o":["Blocks current completely","Conducts current easily","Acts as a capacitor","Stores charge permanently"],"c":1,"e":"A forward-biased diode has a low resistance and conducts current readily once the threshold voltage is exceeded."},
  {"i":"phys-b3-0424","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A minibus of mass 1500 kg travels along a straight road in Addis Ababa at a constant speed of 20 m/s. What is the magnitude of its linear momentum?","o":["3000 kg·m/s","30000 kg·m/s","1500 kg·m/s","75 kg·m/s"],"c":1,"e":"Momentum p = mv = 1500 × 20 = 30000 kg·m/s."},
  {"i":"phys-b3-0425","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A net force gives an 8 kg crate an acceleration of 2.5 m/s². What is the magnitude of the net force?","o":["3.2 N","10.5 N","20 N","16 N"],"c":2,"e":"By Newton's second law F = ma = 8 × 2.5 = 20 N."},
  {"i":"phys-b3-0426","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A ball is thrown vertically upward with an initial speed of 14.7 m/s. Taking g = 9.8 m/s², how long does it take to reach its highest point?","o":["1.5 s","2.0 s","0.67 s","3.0 s"],"c":0,"e":"At the top v = 0, so t = u/g = 14.7/9.8 = 1.5 s."},
  {"i":"phys-b3-0427","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A stone moves in a circle of radius 25 m at a constant speed of 10 m/s. What is its centripetal acceleration?","o":["2.5 m/s²","250 m/s²","4 m/s²","0.4 m/s²"],"c":2,"e":"Centripetal acceleration a = v²/r = 10²/25 = 100/25 = 4 m/s²."},
  {"i":"phys-b3-0428","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A 2 kg object moves at 6 m/s. What is its kinetic energy?","o":["12 J","36 J","72 J","6 J"],"c":1,"e":"Kinetic energy = ½mv² = ½ × 2 × 6² = 36 J."},
  {"i":"phys-b3-0429","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A stone is thrown horizontally from a cliff 4.9 m high. Taking g = 9.8 m/s², how long does it take to reach the ground?","o":["0.5 s","1.0 s","2.0 s","1.4 s"],"c":1,"e":"Vertical fall: h = ½gt², so t = √(2h/g) = √(2×4.9/9.8) = √1 = 1.0 s."},
  {"i":"phys-b3-0430","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A projectile is launched horizontally at 10 m/s from a height of 4.9 m. How far horizontally does it land from the base? (g = 9.8 m/s²)","o":["10 m","5 m","20 m","49 m"],"c":0,"e":"Time of flight t = √(2×4.9/9.8) = 1 s, so range x = u·t = 10 × 1 = 10 m."},
  {"i":"phys-b3-0431","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"definition","q":"For an object in uniform circular motion, the centripetal force is always directed:","o":["tangent to the circle","along the direction of motion","toward the centre of the circle","away from the centre of the circle"],"c":2,"e":"Centripetal means 'centre-seeking'; the net force points toward the centre of the circular path."},
  {"i":"phys-b3-0432","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"conceptual","q":"A rigid wheel rotates about its axis. Which quantity plays the role of mass (inertia) in rotational motion?","o":["Torque","Angular velocity","Moment of inertia","Angular momentum"],"c":2,"e":"Moment of inertia measures resistance to angular acceleration, the rotational analogue of mass."},
  {"i":"phys-b3-0433","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"conceptual","q":"Two objects of mass 4 kg and 9 kg are separated by some distance. According to Newton's law of gravitation, the gravitational force on each object is:","o":["different in magnitude, larger on the 9 kg mass","equal in magnitude on both","zero on the lighter mass","larger on the 4 kg mass"],"c":1,"e":"By Newton's third law the gravitational forces form an action–reaction pair, equal in magnitude and opposite in direction."},
  {"i":"phys-b3-0434","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A 5 kg sack of teff rests on a table. Taking g = 9.8 m/s², what is its weight?","o":["5 N","49 N","9.8 N","0.51 N"],"c":1,"e":"Weight W = mg = 5 × 9.8 = 49 N."},
  {"i":"phys-b3-0435","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"conceptual","q":"In a perfectly inelastic collision between two carts that stick together, which quantity is always conserved?","o":["Kinetic energy only","Total momentum","Mechanical energy","Both kinetic energy and momentum"],"c":1,"e":"Momentum is conserved in all collisions; kinetic energy is not conserved in inelastic collisions."},
  {"i":"phys-b3-0436","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"Find the pressure due to water at a depth of 3 m below the surface. (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["29400 Pa","2940 Pa","3000 Pa","9800 Pa"],"c":0,"e":"Gauge pressure P = ρgh = 1000 × 9.8 × 3 = 29400 Pa."},
  {"i":"phys-b3-0437","g":12,"u":"Fluid Mechanics","d":"easy","t":"definition","q":"Archimedes' principle states that the upward buoyant force on a submerged object equals:","o":["the weight of the object","the weight of the fluid displaced by the object","the density of the fluid","the volume of the object"],"c":1,"e":"By Archimedes' principle, buoyant force equals the weight of the fluid displaced."},
  {"i":"phys-b3-0438","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"A force of 40 N acts uniformly over an area of 0.5 m². What pressure does it exert?","o":["20 Pa","80 Pa","40 Pa","0.0125 Pa"],"c":1,"e":"Pressure P = F/A = 40/0.5 = 80 Pa."},
  {"i":"phys-b3-0439","g":12,"u":"Fluid Mechanics","d":"easy","t":"conceptual","q":"According to the continuity equation for an incompressible fluid in a pipe, when the cross-sectional area decreases, the fluid speed:","o":["decreases","stays constant","increases","becomes zero"],"c":2,"e":"Av = constant, so a smaller area means a higher flow speed."},
  {"i":"phys-b3-0440","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A 4 Ω resistor is connected across a 12 V battery. What current flows through it?","o":["48 A","3 A","0.33 A","8 A"],"c":1,"e":"By Ohm's law I = V/R = 12/4 = 3 A."},
  {"i":"phys-b3-0441","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"Two resistors of 4 Ω and 6 Ω are connected in series. What is their total resistance?","o":["2.4 Ω","10 Ω","5 Ω","24 Ω"],"c":1,"e":"In series, resistances add: R = 4 + 6 = 10 Ω."},
  {"i":"phys-b3-0442","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"An electric lamp operates at 220 V and draws a current of 0.5 A. What is its power?","o":["110 W","440 W","220 W","55 W"],"c":0,"e":"Power P = VI = 220 × 0.5 = 110 W."},
  {"i":"phys-b3-0443","g":12,"u":"Electromagnetism","d":"easy","t":"definition","q":"The direction of the magnetic force on a current-carrying conductor in a magnetic field can be found using:","o":["the right-hand slap (Fleming's left-hand) rule","Ohm's law","Coulomb's law","the inverse-square law"],"c":0,"e":"Fleming's left-hand rule relates the directions of current, field, and force on the conductor."},
  {"i":"phys-b3-0444","g":12,"u":"Application of Physics","d":"easy","t":"conceptual","q":"In a solar water-heating panel widely used on rooftops in Ethiopia, energy is transferred mainly by which process from the Sun?","o":["Conduction","Convection","Radiation","Electrical induction"],"c":2,"e":"Solar energy reaches the panel as electromagnetic radiation, requiring no medium."},
  {"i":"phys-b3-0445","g":12,"u":"Electronics","d":"easy","t":"definition","q":"In a forward-biased p–n junction diode, the diode:","o":["blocks current completely","conducts current easily","stores charge like a capacitor","amplifies the input voltage"],"c":1,"e":"Forward bias lowers the depletion barrier, so the diode conducts current readily."},
  {"i":"phys-b3-0446","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"definition","q":"A projectile is launched at an angle and follows a curved path under gravity alone (neglecting air resistance). At the highest point of its trajectory, which component of its velocity is zero?","o":["The horizontal component","The vertical component","Both components","Neither component"],"c":1,"e":"At the highest point the projectile momentarily stops rising, so the vertical velocity component is zero while the horizontal component stays constant."},
  {"i":"phys-b3-0447","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A stone is thrown horizontally from the top of a cliff with a speed of 15 m/s. What is its horizontal displacement after 2 s? (Neglect air resistance.)","o":["7.5 m","15 m","30 m","60 m"],"c":2,"e":"Horizontal motion is uniform: x = v·t = 15 × 2 = 30 m."},
  {"i":"phys-b3-0448","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A ball is projected with an initial vertical velocity component of 19.6 m/s (g = 9.8 m/s²). How long does it take to reach its maximum height?","o":["1 s","2 s","3 s","4 s"],"c":1,"e":"At maximum height v_y = 0, so t = u_y/g = 19.6/9.8 = 2 s."},
  {"i":"phys-b3-0449","g":12,"u":"Two-Dimensional Motion","d":"easy","t":"calculation","q":"A projectile is launched at 40 m/s at 30° above the horizontal. What is its initial horizontal velocity component? (cos30° = 0.866)","o":["20 m/s","34.6 m/s","40 m/s","46.2 m/s"],"c":1,"e":"v_x = v·cos30° = 40 × 0.866 ≈ 34.6 m/s."},
  {"i":"phys-b3-0450","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A car of mass 1000 kg accelerates uniformly from rest to 20 m/s. What is the change in its momentum?","o":["1000 kg·m/s","10000 kg·m/s","20000 kg·m/s","40000 kg·m/s"],"c":2,"e":"Δp = m·Δv = 1000 × (20 − 0) = 20000 kg·m/s."},
  {"i":"phys-b3-0451","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A constant force of 12 N acts on a 4 kg block resting on a frictionless surface. What is the block's acceleration?","o":["0.33 m/s²","3 m/s²","16 m/s²","48 m/s²"],"c":1,"e":"By Newton's second law, a = F/m = 12/4 = 3 m/s²."},
  {"i":"phys-b3-0452","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A 2 kg object moving at 5 m/s collides and sticks to a 3 kg object at rest. What is their common velocity after the collision?","o":["1 m/s","2 m/s","2.5 m/s","5 m/s"],"c":1,"e":"Momentum is conserved: (2×5)/(2+3) = 10/5 = 2 m/s."},
  {"i":"phys-b3-0453","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"What is the weight of a 5 kg sack of teff on Earth's surface? (g = 9.8 m/s²)","o":["5 N","9.8 N","49 N","98 N"],"c":2,"e":"Weight W = m·g = 5 × 9.8 = 49 N."},
  {"i":"phys-b3-0454","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"A wheel completes 3 full revolutions. Through what angle has it turned, in radians? (Use π = 3.14)","o":["6.28 rad","9.42 rad","18.84 rad","28.26 rad"],"c":2,"e":"One revolution = 2π rad, so 3 × 2π = 6π = 18.84 rad."},
  {"i":"phys-b3-0455","g":12,"u":"Application of Physics","d":"easy","t":"calculation","q":"Two 4 kg point masses are placed 2 m apart. Using G = 6.67×10⁻¹¹ N·m²/kg², what is the gravitational force between them?","o":["2.67×10⁻¹⁰ N","5.34×10⁻¹⁰ N","1.07×10⁻⁹ N","2.13×10⁻⁹ N"],"c":0,"e":"F = G·m₁m₂/r² = 6.67×10⁻¹¹ × (4×4)/2² = 6.67×10⁻¹¹ × 4 = 2.67×10⁻¹⁰ N."},
  {"i":"phys-b3-0456","g":12,"u":"Fluid Mechanics","d":"easy","t":"definition","q":"The upward force exerted by a fluid on a body immersed in it is called the:","o":["Buoyant force","Viscous force","Surface tension","Cohesive force"],"c":0,"e":"The upward force a fluid exerts on an immersed body is the buoyant force, described by Archimedes' principle."},
  {"i":"phys-b3-0457","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"What is the pressure exerted by a force of 200 N acting uniformly over an area of 0.5 m²?","o":["100 Pa","200 Pa","400 Pa","1000 Pa"],"c":2,"e":"Pressure P = F/A = 200/0.5 = 400 Pa."},
  {"i":"phys-b3-0458","g":12,"u":"Fluid Mechanics","d":"easy","t":"calculation","q":"What is the pressure due to a 10 m column of water? (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["9800 Pa","49000 Pa","98000 Pa","980000 Pa"],"c":2,"e":"P = ρgh = 1000 × 9.8 × 10 = 98000 Pa."},
  {"i":"phys-b3-0459","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A resistor carries a current of 2 A when a potential difference of 12 V is applied. What is its resistance?","o":["6 Ω","10 Ω","14 Ω","24 Ω"],"c":0,"e":"By Ohm's law, R = V/I = 12/2 = 6 Ω."},
  {"i":"phys-b3-0460","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"An electrical appliance draws 4 A at 220 V. What is its power consumption?","o":["55 W","224 W","880 W","216 W"],"c":2,"e":"Power P = V·I = 220 × 4 = 880 W."},
  {"i":"phys-b3-0461","g":12,"u":"Electromagnetism","d":"easy","t":"calculation","q":"A charge of 6 C flows through a wire in 3 s. What is the current?","o":["0.5 A","2 A","9 A","18 A"],"c":1,"e":"Current I = Q/t = 6/3 = 2 A."},
  {"i":"phys-b3-0462","g":12,"u":"Electromagnetism","d":"easy","t":"conceptual","q":"A current-carrying conductor is placed in a magnetic field directed parallel to the current. What is the magnetic force on the conductor?","o":["Maximum","Zero","Equal to BIL/2","Directed along the current"],"c":1,"e":"The force F = BIL·sinθ is zero when the current is parallel to the field (θ = 0°, sin0° = 0)."},
  {"i":"phys-b3-0463","g":12,"u":"Electronics","d":"easy","t":"definition","q":"A semiconductor diode allows current to flow easily in one direction only. In which configuration does it conduct strongly?","o":["Reverse bias","Forward bias","Zero bias only","Equally in both biases"],"c":1,"e":"A diode conducts strongly when forward biased and blocks current when reverse biased, acting as a one-way valve."},
  {"i":"phys-b3-0464","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A javelin is thrown from ground level at 25 m/s at 40° above the horizontal. Taking g = 9.8 m/s², what is its maximum height?","o":["13.2 m","26.4 m","8.2 m","31.9 m"],"c":0,"e":"H = (v sinθ)² / (2g) = (25·sin40°)² / (2·9.8) = (16.07)²/19.6 ≈ 13.2 m."},
  {"i":"phys-b3-0465","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A stone is thrown horizontally at 12 m/s from a cliff 45 m high. How far from the cliff base does it land? (g = 9.8 m/s²)","o":["27.0 m","36.4 m","54.0 m","18.2 m"],"c":1,"e":"Fall time t = √(2h/g) = √(90/9.8) ≈ 3.03 s; range = v₀t = 12·3.03 ≈ 36.4 m."},
  {"i":"phys-b3-0466","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 0.40 kg ball strikes a wall horizontally at 8 m/s and rebounds at 6 m/s along the same line. What is the magnitude of the impulse on the ball?","o":["0.8 N·s","3.2 N·s","5.6 N·s","2.4 N·s"],"c":2,"e":"Impulse = Δp = m(v_f − v_i) = 0.40·(6 − (−8)) = 0.40·14 = 5.6 N·s."},
  {"i":"phys-b3-0467","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A taxi rounds a flat curve of radius 50 m at a constant 15 m/s. What is its centripetal acceleration?","o":["4.5 m/s²","0.3 m/s²","3.0 m/s²","9.0 m/s²"],"c":0,"e":"a_c = v²/r = 15²/50 = 225/50 = 4.5 m/s²."},
  {"i":"phys-b3-0468","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A wheel starts from rest and rotates with constant angular acceleration 2 rad/s². Through what angle has it turned after 5 s?","o":["10 rad","50 rad","25 rad","20 rad"],"c":2,"e":"θ = ½αt² = ½·2·5² = 25 rad."},
  {"i":"phys-b3-0469","g":12,"u":"Application of Physics","d":"medium","t":"conceptual","q":"At a height above Earth's surface equal to the Earth's radius R, the gravitational field strength compared to its surface value g is:","o":["g/2","g/4","g/3","2g"],"c":1,"e":"g' = GM/(2R)² = GM/(4R²) = g/4, since distance from centre is 2R."},
  {"i":"phys-b3-0470","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A block slides down a 30° incline with coefficient of kinetic friction 0.25. What is its acceleration? (g = 9.8 m/s²)","o":["4.90 m/s²","2.78 m/s²","6.18 m/s²","1.95 m/s²"],"c":1,"e":"a = g(sinθ − μcosθ) = 9.8(0.5 − 0.25·0.866) = 9.8·0.283 ≈ 2.78 m/s²."},
  {"i":"phys-b3-0471","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"What is the gauge pressure exerted by water (density 1000 kg/m³) at a depth of 3.0 m? (g = 9.8 m/s²)","o":["2940 Pa","29 400 Pa","3000 Pa","9800 Pa"],"c":1,"e":"P = ρgh = 1000·9.8·3.0 = 29 400 Pa."},
  {"i":"phys-b3-0472","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A solid object of volume 2.0 × 10⁻³ m³ is fully submerged in water (density 1000 kg/m³). What buoyant force acts on it? (g = 9.8 m/s²)","o":["19.6 N","9.8 N","1.96 N","39.2 N"],"c":0,"e":"F_b = ρgV = 1000·9.8·2.0×10⁻³ = 19.6 N."},
  {"i":"phys-b3-0473","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"Water flows through a pipe whose cross-section narrows from 8 cm² to 2 cm². If the speed in the wide section is 3 m/s, what is the speed in the narrow section?","o":["0.75 m/s","6 m/s","12 m/s","9 m/s"],"c":2,"e":"Continuity: A₁v₁ = A₂v₂ → v₂ = 8·3/2 = 12 m/s."},
  {"i":"phys-b3-0474","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"Two point charges of 3 µC and 5 µC are 0.20 m apart in air. What is the magnitude of the electrostatic force between them? (k = 8.99 × 10⁹ N·m²/C²)","o":["3.37 N","0.67 N","13.5 N","6.74 N"],"c":0,"e":"F = kq₁q₂/r² = 8.99×10⁹·(3×10⁻⁶)(5×10⁻⁶)/0.20² = 0.1349/0.04 ≈ 3.37 N."},
  {"i":"phys-b3-0475","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A 6 Ω and a 3 Ω resistor are connected in parallel. What is their equivalent resistance?","o":["9 Ω","2 Ω","4.5 Ω","18 Ω"],"c":1,"e":"R_p = (6·3)/(6+3) = 18/9 = 2 Ω."},
  {"i":"phys-b3-0476","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A straight rod 0.4 m long moves at 3 m/s perpendicular to a 0.5 T uniform magnetic field. What EMF is induced across it?","o":["0.6 V","1.2 V","0.06 V","6.0 V"],"c":0,"e":"EMF = BLv = 0.5·0.4·3 = 0.6 V."},
  {"i":"phys-b3-0477","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A 0.5 m wire carrying 4 A lies perpendicular to a 0.3 T magnetic field. What force acts on the wire?","o":["0.6 N","6.0 N","0.06 N","1.2 N"],"c":0,"e":"F = BIL = 0.3·4·0.5 = 0.6 N."},
  {"i":"phys-b3-0478","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"An ideal transformer has 200 primary turns and 50 secondary turns. If the primary voltage is 240 V, what is the secondary voltage?","o":["960 V","120 V","60 V","30 V"],"c":2,"e":"V_s = V_p·(N_s/N_p) = 240·(50/200) = 60 V."},
  {"i":"phys-b3-0479","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A 4 µF capacitor is charged to 200 V. How much energy is stored in it?","o":["0.08 J","0.04 J","0.8 J","0.16 J"],"c":0,"e":"E = ½CV² = ½·4×10⁻⁶·200² = ½·4×10⁻⁶·40000 = 0.08 J."},
  {"i":"phys-b3-0480","g":12,"u":"Electronics","d":"medium","t":"conceptual","q":"In a forward-biased silicon p–n junction diode, conventional current flows because:","o":["the depletion region widens, allowing electrons to tunnel","the applied voltage lowers the barrier so majority carriers cross the junction","minority carriers are blocked while majority carriers are repelled back","the junction acts purely as an insulator at all voltages"],"c":1,"e":"Forward bias reduces the depletion-region potential barrier, letting majority carriers (holes from p, electrons from n) cross and sustain current."},
  {"i":"phys-b3-0481","g":12,"u":"Electronics","d":"medium","t":"calculation","q":"A current of 2 A flows through a 10 Ω resistor in an electronic circuit. What power is dissipated?","o":["20 W","5 W","40 W","100 W"],"c":2,"e":"P = I²R = 2²·10 = 4·10 = 40 W."},
  {"i":"phys-b3-0482","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A constant net force does work on a 2.0 kg cart, increasing its speed from 4 m/s to 10 m/s. How much work is done?","o":["84 J","12 J","42 J","168 J"],"c":0,"e":"W = ΔKE = ½m(v_f² − v_i²) = ½·2·(100 − 16) = 84 J."},
  {"i":"phys-b3-0483","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 2 kg cart moving at 3 m/s collides with and sticks to a stationary 1 kg cart. What is their common velocity afterwards?","o":["1.5 m/s","2.0 m/s","3.0 m/s","6.0 m/s"],"c":1,"e":"Momentum: (2·3 + 1·0) = (2+1)v → v = 6/3 = 2.0 m/s."},
  {"i":"phys-b3-0484","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A force of 20 N is applied perpendicular to a wrench at a distance of 0.3 m from the pivot. What torque does it produce?","o":["6.0 N·m","60 N·m","0.6 N·m","3.0 N·m"],"c":0,"e":"τ = F·r·sinθ = 20·0.3·sin90° = 6.0 N·m."},
  {"i":"phys-b3-0485","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"Water exits through a small hole 1.8 m below the surface of a large open tank. Using Torricelli's law, what is the exit speed? (g = 9.8 m/s²)","o":["3.8 m/s","5.9 m/s","17.6 m/s","35.3 m/s"],"c":1,"e":"v = √(2gh) = √(2·9.8·1.8) = √35.28 ≈ 5.9 m/s."},
  {"i":"phys-b3-0486","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A ball is kicked from level ground at 20 m/s at 30° above the horizontal. Taking g = 9.8 m/s², what is the maximum height it reaches?","o":["5.1 m","10.2 m","15.3 m","20.4 m"],"c":0,"e":"vᵧ = 20·sin30° = 10 m/s; H = vᵧ²/(2g) = 100/19.6 ≈ 5.1 m."},
  {"i":"phys-b3-0487","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A stone is thrown horizontally at 15 m/s from a cliff and lands after 2.0 s. How far from the base of the cliff does it land? (Use g = 9.8 m/s²)","o":["15 m","30 m","45 m","19.6 m"],"c":1,"e":"Horizontal range = v·t = 15 × 2.0 = 30 m (horizontal velocity is constant)."},
  {"i":"phys-b3-0488","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A projectile is launched at 40 m/s at 45°. Using g = 9.8 m/s², what is its horizontal range on level ground?","o":["82 m","163 m","115 m","204 m"],"c":1,"e":"R = v²·sin(2θ)/g = 1600·sin90°/9.8 = 1600/9.8 ≈ 163 m."},
  {"i":"phys-b3-0489","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A car of mass 1000 kg rounds a flat curve of radius 50 m at 15 m/s. What centripetal force is required?","o":["3000 N","4500 N","6750 N","2250 N"],"c":1,"e":"F = mv²/r = 1000 × 225/50 = 4500 N."},
  {"i":"phys-b3-0490","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A 0.5 kg ball on a string moves in a horizontal circle of radius 1.2 m at 4 m/s. What is its centripetal acceleration?","o":["13.3 m/s²","6.7 m/s²","9.6 m/s²","3.3 m/s²"],"c":0,"e":"a = v²/r = 16/1.2 ≈ 13.3 m/s²."},
  {"i":"phys-b3-0491","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 2.0 kg block is pushed across a floor with a horizontal force of 12 N. If the friction force is 4 N, what is the block's acceleration?","o":["2.0 m/s²","4.0 m/s²","6.0 m/s²","8.0 m/s²"],"c":1,"e":"Net force = 12 − 4 = 8 N; a = F/m = 8/2.0 = 4.0 m/s²."},
  {"i":"phys-b3-0492","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 0.15 kg ball moving at 20 m/s is struck and rebounds straight back at 25 m/s. What is the magnitude of the impulse on the ball?","o":["0.75 N·s","3.75 N·s","6.75 N·s","7.5 N·s"],"c":2,"e":"Impulse = Δp = m(v_f − v_i) = 0.15(−25 − 20) = −6.75 N·s; magnitude = 6.75 N·s."},
  {"i":"phys-b3-0493","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"Two carts collide and stick: a 3 kg cart at 4 m/s hits a stationary 1 kg cart. What is their common velocity after collision?","o":["2.0 m/s","3.0 m/s","4.0 m/s","1.0 m/s"],"c":1,"e":"Conservation of momentum: 3×4 = (3+1)v → v = 12/4 = 3.0 m/s."},
  {"i":"phys-b3-0494","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A wheel rotating at 12 rad/s slows uniformly and stops in 4.0 s. What is its angular acceleration?","o":["−3.0 rad/s²","−2.0 rad/s²","−4.0 rad/s²","−6.0 rad/s²"],"c":0,"e":"α = (ω_f − ω_i)/t = (0 − 12)/4.0 = −3.0 rad/s²."},
  {"i":"phys-b3-0495","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A torque of 6.0 N·m acts on a disc of moment of inertia 0.50 kg·m². What is the angular acceleration?","o":["3.0 rad/s²","12 rad/s²","6.0 rad/s²","0.083 rad/s²"],"c":1,"e":"τ = Iα → α = τ/I = 6.0/0.50 = 12 rad/s²."},
  {"i":"phys-b3-0496","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"Two 5.0 kg masses are separated by 2.0 m. Using G = 6.67×10⁻¹¹ N·m²/kg², what is the gravitational force between them?","o":["4.2×10⁻¹⁰ N","8.3×10⁻¹⁰ N","1.7×10⁻⁹ N","4.2×10⁻⁹ N"],"c":0,"e":"F = G·m₁m₂/r² = 6.67×10⁻¹¹·(25)/4 = 4.2×10⁻¹⁰ N."},
  {"i":"phys-b3-0497","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A satellite orbits Earth at radius r. If the orbital radius is quadrupled, by what factor does its orbital speed change?","o":["Halved","Doubled","Quartered","Unchanged"],"c":0,"e":"v = √(GM/r), so v ∝ 1/√r; quadrupling r multiplies v by 1/√4 = 1/2 (halved)."},
  {"i":"phys-b3-0498","g":12,"u":"Application of Physics","d":"medium","t":"conceptual","q":"A 60 kg person stands in an elevator accelerating upward at 2.0 m/s². What is the normal force from the floor? (Use g = 9.8 m/s²)","o":["588 N","468 N","708 N","120 N"],"c":2,"e":"N = m(g + a) = 60(9.8 + 2.0) = 60 × 11.8 = 708 N."},
  {"i":"phys-b3-0499","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A hydraulic lift has input piston area 0.01 m² and output piston area 0.20 m². A 50 N force on the input gives what output force?","o":["1000 N","2.5 N","500 N","250 N"],"c":0,"e":"Pascal's principle: F_out = F_in·(A_out/A_in) = 50·(0.20/0.01) = 50 × 20 = 1000 N."},
  {"i":"phys-b3-0500","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"What is the gauge pressure at the bottom of a 3.0 m deep water tank? (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["29400 Pa","2940 Pa","9800 Pa","294000 Pa"],"c":0,"e":"P = ρgh = 1000 × 9.8 × 3.0 = 29400 Pa."},
  {"i":"phys-b3-0501","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"An object of volume 2.0×10⁻³ m³ is fully submerged in water (ρ = 1000 kg/m³). What buoyant force acts on it? (g = 9.8 m/s²)","o":["9.8 N","19.6 N","2.0 N","4.9 N"],"c":1,"e":"F_b = ρ·V·g = 1000 × 2.0×10⁻³ × 9.8 = 19.6 N."},
  {"i":"phys-b3-0502","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"Water flows through a pipe that narrows from area 0.06 m² to 0.02 m². If the speed in the wide section is 1.0 m/s, what is the speed in the narrow section?","o":["3.0 m/s","0.33 m/s","2.0 m/s","6.0 m/s"],"c":0,"e":"Continuity: A₁v₁ = A₂v₂ → v₂ = (0.06×1.0)/0.02 = 3.0 m/s."},
  {"i":"phys-b3-0503","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A 2.0 m wire carries 5.0 A perpendicular to a 0.40 T magnetic field. What force acts on the wire?","o":["4.0 N","2.0 N","10 N","0.16 N"],"c":0,"e":"F = BIL = 0.40 × 5.0 × 2.0 = 4.0 N (wire perpendicular to B)."},
  {"i":"phys-b3-0504","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A coil of 200 turns experiences a flux change of 0.003 Wb in 0.10 s. What is the magnitude of the induced EMF?","o":["6.0 V","0.6 V","60 V","0.06 V"],"c":0,"e":"EMF = N·ΔΦ/Δt = 200 × 0.003/0.10 = 6.0 V."},
  {"i":"phys-b3-0505","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A proton (q = 1.6×10⁻¹⁹ C) moves at 2.0×10⁶ m/s perpendicular to a 0.50 T field. What magnetic force acts on it?","o":["1.6×10⁻¹³ N","3.2×10⁻¹³ N","8.0×10⁻¹⁴ N","1.6×10⁻¹⁴ N"],"c":0,"e":"F = qvB = 1.6×10⁻¹⁹ × 2.0×10⁶ × 0.50 = 1.6×10⁻¹³ N."},
  {"i":"phys-b3-0506","g":12,"u":"Electronics","d":"medium","t":"calculation","q":"Three resistors of 2 Ω, 3 Ω and 6 Ω are connected in parallel. What is the equivalent resistance?","o":["1.0 Ω","11 Ω","0.5 Ω","3.7 Ω"],"c":0,"e":"1/R = 1/2 + 1/3 + 1/6 = 3/6+2/6+1/6 = 1 → R = 1.0 Ω."},
  {"i":"phys-b3-0507","g":12,"u":"Electronics","d":"medium","t":"conceptual","q":"In a forward-biased silicon diode, approximately what is the threshold (knee) voltage at which significant current begins to flow?","o":["0.3 V","0.7 V","1.5 V","0 V"],"c":1,"e":"A silicon p-n junction diode conducts appreciably once the forward voltage reaches about 0.7 V (germanium is ≈0.3 V)."},
  {"i":"phys-b3-0508","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A ball is kicked from level ground with a speed of 20 m/s at 30° above the horizontal. Taking g = 9.8 m/s², what is its maximum height? ","o":["5.1 m","10.2 m","15.3 m","20.4 m"],"c":0,"e":"Vertical component is 20·sin30° = 10 m/s. Maximum height H = v_y²/(2g) = 100/(2·9.8) ≈ 5.1 m."},
  {"i":"phys-b3-0509","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A stone is thrown horizontally at 15 m/s from a cliff and lands after 2.0 s. Using g = 9.8 m/s², how far from the base of the cliff does it land?","o":["7.5 m","19.6 m","30 m","45 m"],"c":2,"e":"Horizontal motion is uniform: x = v·t = 15·2.0 = 30 m, since horizontal velocity is unaffected by gravity."},
  {"i":"phys-b3-0510","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A projectile is launched at 40 m/s at 45°. Taking g = 9.8 m/s², what is its total time of flight on level ground?","o":["2.9 s","4.1 s","5.8 s","8.2 s"],"c":2,"e":"v_y = 40·sin45° ≈ 28.28 m/s. Time of flight T = 2v_y/g = 2·28.28/9.8 ≈ 5.8 s."},
  {"i":"phys-b3-0511","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A car rounds a flat circular track of radius 50 m at a constant speed of 14 m/s. What is the magnitude of its centripetal acceleration?","o":["0.28 m/s²","3.92 m/s²","7.0 m/s²","196 m/s²"],"c":1,"e":"Centripetal acceleration a = v²/r = 14²/50 = 196/50 = 3.92 m/s²."},
  {"i":"phys-b3-0512","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 2.0 kg block on a frictionless surface is pushed by a constant 6.0 N horizontal force over 3.0 m. What is its kinetic energy after the 3.0 m?","o":["6.0 J","12 J","18 J","36 J"],"c":2,"e":"Work-energy theorem: KE = F·d = 6.0·3.0 = 18 J, all the work becomes kinetic energy on a frictionless surface."},
  {"i":"phys-b3-0513","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 1500 kg minibus travelling at 20 m/s brakes uniformly to rest over 50 m. What constant braking force acts on it?","o":["3000 N","6000 N","9000 N","12000 N"],"c":1,"e":"Deceleration a = v²/(2d) = 400/100 = 4 m/s². Force F = m·a = 1500·4 = 6000 N."},
  {"i":"phys-b3-0514","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 0.30 kg cart at 4.0 m/s collides and sticks to a stationary 0.20 kg cart. What is their common speed after the collision?","o":["1.6 m/s","2.4 m/s","3.2 m/s","4.0 m/s"],"c":1,"e":"Momentum conservation: 0.30·4.0 = (0.30+0.20)·v, so v = 1.2/0.50 = 2.4 m/s."},
  {"i":"phys-b3-0515","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A wheel rotating at 12 rad/s decelerates uniformly at 3.0 rad/s². How long does it take to stop?","o":["2.0 s","3.0 s","4.0 s","6.0 s"],"c":2,"e":"Using ω = ω₀ − αt with ω = 0: t = ω₀/α = 12/3.0 = 4.0 s."},
  {"i":"phys-b3-0516","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A satellite orbits Earth at a radius where g = 8.0 m/s². If the orbital radius is 7.0×10⁶ m, what is its orbital speed?","o":["3.7×10³ m/s","5.3×10³ m/s","7.5×10³ m/s","1.1×10⁴ m/s"],"c":2,"e":"Gravity supplies centripetal force: g = v²/r, so v = √(g·r) = √(8.0·7.0×10⁶) = √(5.6×10⁷) ≈ 7.5×10³ m/s."},
  {"i":"phys-b3-0517","g":12,"u":"Application of Physics","d":"medium","t":"conceptual","q":"A box rests on an incline at the maximum angle before sliding. If the angle is 30°, what is the coefficient of static friction between the box and incline?","o":["0.29","0.50","0.58","0.87"],"c":2,"e":"At the verge of slipping, μ_s = tanθ = tan30° ≈ 0.58."},
  {"i":"phys-b3-0518","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 10 kg object is lifted vertically at constant velocity by a rope. Using g = 9.8 m/s², how much work does the rope do raising it 4.0 m?","o":["40 J","98 J","196 J","392 J"],"c":3,"e":"At constant velocity rope tension equals weight: T = mg = 98 N. Work = T·h = 98·4.0 = 392 J."},
  {"i":"phys-b3-0519","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A diver is 8.0 m below the surface of a lake (water density 1000 kg/m³, g = 9.8 m/s²). What is the gauge pressure on the diver?","o":["7.84×10³ Pa","3.92×10⁴ Pa","7.84×10⁴ Pa","9.80×10⁴ Pa"],"c":2,"e":"Gauge pressure P = ρgh = 1000·9.8·8.0 = 7.84×10⁴ Pa."},
  {"i":"phys-b3-0520","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"An object of volume 2.0×10⁻³ m³ is fully submerged in water (density 1000 kg/m³). Using g = 9.8 m/s², what buoyant force acts on it?","o":["9.8 N","19.6 N","49 N","196 N"],"c":1,"e":"Buoyant force = ρ·V·g = 1000·2.0×10⁻³·9.8 = 19.6 N (Archimedes' principle)."},
  {"i":"phys-b3-0521","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"Water flows through a pipe that narrows from a cross-section of 6.0 cm² to 2.0 cm². If the speed in the wide section is 1.5 m/s, what is the speed in the narrow section?","o":["0.5 m/s","3.0 m/s","4.5 m/s","9.0 m/s"],"c":2,"e":"Continuity: A₁v₁ = A₂v₂, so v₂ = (6.0/2.0)·1.5 = 3·1.5 = 4.5 m/s."},
  {"i":"phys-b3-0522","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A hydraulic lift has input and output piston areas of 0.01 m² and 0.50 m². What output force results from a 200 N input force?","o":["4.0 N","1000 N","5000 N","10000 N"],"c":3,"e":"Pascal's principle: F_out = F_in·(A_out/A_in) = 200·(0.50/0.01) = 200·50 = 10000 N."},
  {"i":"phys-b3-0523","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A wire of length 0.40 m carrying 5.0 A is placed perpendicular to a 0.30 T magnetic field. What force acts on the wire?","o":["0.60 N","1.5 N","6.0 N","12 N"],"c":0,"e":"F = BIL·sin90° = 0.30·5.0·0.40 = 0.60 N."},
  {"i":"phys-b3-0524","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A coil of 200 turns experiences a magnetic flux change of 4.0×10⁻³ Wb in 0.10 s. What is the magnitude of the induced emf?","o":["0.8 V","2.0 V","8.0 V","80 V"],"c":2,"e":"Faraday's law: emf = N·ΔΦ/Δt = 200·(4.0×10⁻³/0.10) = 200·0.040 = 8.0 V."},
  {"i":"phys-b3-0525","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A proton (charge 1.6×10⁻¹⁹ C) moves at 2.0×10⁶ m/s perpendicular to a 0.50 T field. What magnetic force acts on it?","o":["1.6×10⁻¹³ N","3.2×10⁻¹³ N","1.6×10⁻¹⁹ N","6.4×10⁻¹³ N"],"c":0,"e":"F = qvB = 1.6×10⁻¹⁹·2.0×10⁶·0.50 = 1.6×10⁻¹³ N."},
  {"i":"phys-b3-0526","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A transformer has 100 turns on the primary and 500 on the secondary. If the primary voltage is 220 V, what is the secondary voltage (ideal transformer)?","o":["44 V","220 V","1100 V","2200 V"],"c":2,"e":"V_s/V_p = N_s/N_p, so V_s = 220·(500/100) = 220·5 = 1100 V."},
  {"i":"phys-b3-0527","g":12,"u":"Electronics","d":"medium","t":"calculation","q":"Three resistors of 4 Ω, 6 Ω and 12 Ω are connected in parallel. What is their equivalent resistance?","o":["0.5 Ω","2.0 Ω","7.3 Ω","22 Ω"],"c":1,"e":"1/R = 1/4 + 1/6 + 1/12 = 3/12 + 2/12 + 1/12 = 6/12 = 1/2, so R = 2.0 Ω."},
  {"i":"phys-b3-0528","g":12,"u":"Electronics","d":"medium","t":"conceptual","q":"In a forward-biased silicon p-n junction diode used in a circuit, what is the approximate voltage drop across the diode when conducting?","o":["0.0 V","0.3 V","0.7 V","1.5 V"],"c":2,"e":"A conducting silicon diode has a characteristic forward voltage drop of about 0.7 V (germanium is ~0.3 V)."},
  {"i":"phys-b3-0529","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A ball is kicked from level ground at 14 m/s at 30° above the horizontal. Taking g = 9.8 m/s², what is its maximum height? ","o":["2.5 m","5.0 m","7.0 m","10.0 m"],"c":0,"e":"Vertical component v_y = 14·sin30° = 7 m/s. H = v_y²/(2g) = 49/19.6 ≈ 2.5 m."},
  {"i":"phys-b3-0530","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A stone is thrown horizontally at 20 m/s from a cliff and lands 4 s later. Ignoring air resistance and using g = 9.8 m/s², how far from the base of the cliff does it land?","o":["40 m","60 m","80 m","100 m"],"c":2,"e":"Horizontal velocity is constant: x = v·t = 20·4 = 80 m."},
  {"i":"phys-b3-0531","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A projectile is launched at 25 m/s at 53° above the horizontal (sin53°≈0.8, cos53°≈0.6). Using g = 9.8 m/s², what is its time of flight on level ground?","o":["2.0 s","3.1 s","4.1 s","5.1 s"],"c":2,"e":"v_y = 25·0.8 = 20 m/s. Time of flight T = 2v_y/g = 40/9.8 ≈ 4.1 s."},
  {"i":"phys-b3-0532","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A car rounds a flat circular curve of radius 50 m at a constant 15 m/s. What is the magnitude of its centripetal acceleration?","o":["3.0 m/s²","4.5 m/s²","6.0 m/s²","7.5 m/s²"],"c":1,"e":"a_c = v²/r = 225/50 = 4.5 m/s²."},
  {"i":"phys-b3-0533","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 1500 kg minibus accelerates uniformly from rest to 20 m/s in 8 s on a flat road in Addis Ababa. What is the net forward force on it?","o":["1875 N","3000 N","3750 N","7500 N"],"c":2,"e":"a = 20/8 = 2.5 m/s²; F = ma = 1500·2.5 = 3750 N."},
  {"i":"phys-b3-0534","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 2 kg block slides on a horizontal surface with kinetic friction coefficient 0.25. Using g = 9.8 m/s², what is the friction force acting on it?","o":["2.45 N","4.9 N","9.8 N","19.6 N"],"c":1,"e":"f = μ·m·g = 0.25·2·9.8 = 4.9 N."},
  {"i":"phys-b3-0535","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 0.15 kg ball moving at 12 m/s is struck and rebounds straight back at 8 m/s. What is the magnitude of the impulse delivered to the ball?","o":["0.6 N·s","1.2 N·s","3.0 N·s","6.0 N·s"],"c":2,"e":"Δp = m(v_f − v_i) = 0.15(−8 − 12) = −3.0 N·s; magnitude 3.0 N·s."},
  {"i":"phys-b3-0536","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"Two carts on a frictionless track, 3 kg at 4 m/s and 1 kg at rest, collide and stick together. What is their common velocity afterward?","o":["1.0 m/s","2.0 m/s","3.0 m/s","4.0 m/s"],"c":2,"e":"Momentum conservation: (3·4)/(3+1) = 12/4 = 3.0 m/s."},
  {"i":"phys-b3-0537","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A wheel starts from rest and reaches an angular velocity of 12 rad/s in 4 s with constant angular acceleration. What is its angular acceleration?","o":["1.5 rad/s²","3.0 rad/s²","6.0 rad/s²","48 rad/s²"],"c":1,"e":"α = Δω/Δt = 12/4 = 3.0 rad/s²."},
  {"i":"phys-b3-0538","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A solid disk of moment of inertia 0.5 kg·m² is acted on by a net torque of 2 N·m. What is its angular acceleration?","o":["1.0 rad/s²","2.0 rad/s²","4.0 rad/s²","8.0 rad/s²"],"c":2,"e":"τ = Iα, so α = τ/I = 2/0.5 = 4.0 rad/s²."},
  {"i":"phys-b3-0539","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"The gravitational force between two 1000 kg masses placed 2 m apart is closest to which value? (G = 6.67×10⁻¹¹ N·m²/kg²)","o":["1.7×10⁻⁵ N","1.7×10⁻³ N","3.3×10⁻⁵ N","6.7×10⁻⁵ N"],"c":0,"e":"F = G·m₁m₂/r² = 6.67×10⁻¹¹·10⁶/4 ≈ 1.67×10⁻⁵ N."},
  {"i":"phys-b3-0540","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A satellite orbits at a radius where gravitational acceleration is 6.0 m/s². If its orbital radius were doubled, the acceleration would become:","o":["1.5 m/s²","3.0 m/s²","6.0 m/s²","12 m/s²"],"c":0,"e":"g ∝ 1/r². Doubling r divides g by 4: 6.0/4 = 1.5 m/s²."},
  {"i":"phys-b3-0541","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A 0.5 kg mass on a spring (k = 200 N/m) oscillates in simple harmonic motion. What is its angular frequency?","o":["10 rad/s","20 rad/s","100 rad/s","400 rad/s"],"c":1,"e":"ω = √(k/m) = √(200/0.5) = √400 = 20 rad/s."},
  {"i":"phys-b3-0542","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A column of water 5 m deep exerts what gauge pressure at its base? (ρ = 1000 kg/m³, g = 9.8 m/s²)","o":["4.9 kPa","49 kPa","98 kPa","490 kPa"],"c":1,"e":"P = ρgh = 1000·9.8·5 = 49000 Pa = 49 kPa."},
  {"i":"phys-b3-0543","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A hydraulic lift has input piston area 0.01 m² and output piston area 0.20 m². A 50 N force on the input supports what maximum weight on the output?","o":["250 N","500 N","1000 N","2500 N"],"c":2,"e":"By Pascal's principle F_out = F_in·(A_out/A_in) = 50·(0.20/0.01) = 1000 N."},
  {"i":"phys-b3-0544","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A wooden block of volume 0.02 m³ is fully submerged in water. What is the buoyant force on it? (ρ_water = 1000 kg/m³, g = 9.8 m/s²)","o":["98 N","196 N","294 N","392 N"],"c":1,"e":"F_b = ρ·V·g = 1000·0.02·9.8 = 196 N."},
  {"i":"phys-b3-0545","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"Water flows through a pipe of cross-section 6 cm² at 2 m/s, then enters a narrower section of 2 cm². What is the speed in the narrow section?","o":["0.67 m/s","3.0 m/s","6.0 m/s","12 m/s"],"c":2,"e":"Continuity: A₁v₁ = A₂v₂, so v₂ = (6·2)/2 = 6.0 m/s."},
  {"i":"phys-b3-0546","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A 12 V battery is connected across a 4 Ω resistor. What power is dissipated in the resistor?","o":["3 W","12 W","36 W","48 W"],"c":2,"e":"P = V²/R = 144/4 = 36 W."},
  {"i":"phys-b3-0547","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A proton moves at 2×10⁶ m/s perpendicular to a 0.5 T magnetic field. What magnetic force acts on it? (q = 1.6×10⁻¹⁹ C)","o":["1.6×10⁻¹³ N","8.0×10⁻¹⁴ N","3.2×10⁻¹³ N","1.6×10⁻¹² N"],"c":0,"e":"F = qvB = 1.6×10⁻¹⁹·2×10⁶·0.5 = 1.6×10⁻¹³ N."},
  {"i":"phys-b3-0548","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A coil of 200 turns experiences a magnetic flux change from 0.04 Wb to 0.01 Wb in 0.2 s. What is the magnitude of the induced emf?","o":["3 V","15 V","30 V","60 V"],"c":2,"e":"emf = N·ΔΦ/Δt = 200·(0.03/0.2) = 200·0.15 = 30 V."},
  {"i":"phys-b3-0549","g":12,"u":"Electronics","d":"medium","t":"calculation","q":"A transistor has a base current of 20 μA and a current gain (β) of 150. What is the resulting collector current?","o":["1.5 mA","3.0 mA","7.5 mA","30 mA"],"c":1,"e":"I_C = β·I_B = 150·20 μA = 3000 μA = 3.0 mA."},
  {"i":"phys-b3-0550","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A footballer in Bahir Dar kicks a ball at 14 m/s, 30° above the horizontal. Taking g = 9.8 m/s² and neglecting air resistance, what horizontal range does the ball cover before landing back at the same height?","o":["10 m","17.3 m","20 m","24.5 m"],"c":1,"e":"Range R = v²sin(2θ)/g = 14²·sin60°/9.8 = 196·0.866/9.8 ≈ 17.3 m. Using sinθ instead of sin2θ wrongly gives 10 m."},
  {"i":"phys-b3-0551","g":12,"u":"Two-Dimensional Motion","d":"medium","t":"calculation","q":"A 1200 kg taxi moving at 15 m/s collides head-on-and-locks with a stationary 800 kg car. If they move together after impact, what is their common speed?","o":["6 m/s","9 m/s","12 m/s","15 m/s"],"c":1,"e":"Momentum conservation: m₁u₁ = (m₁+m₂)v, so v = (1200·15)/2000 = 18000/2000 = 9 m/s."},
  {"i":"phys-b3-0552","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A solid uniform disc of mass 2 kg and radius 0.3 m (I = ½mr²) is free to rotate about its centre. A constant tangential force of 6 N is applied at its rim. What is its angular acceleration?","o":["10 rad/s²","13.3 rad/s²","20 rad/s²","40 rad/s²"],"c":2,"e":"I = ½·2·0.3² = 0.09 kg·m²; torque τ = Fr = 6·0.3 = 1.8 N·m; α = τ/I = 1.8/0.09 = 20 rad/s²."},
  {"i":"phys-b3-0553","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"At the Earth's surface g = 9.8 m/s². Ignoring rotation, what is the gravitational field strength at a height equal to one Earth radius above the surface?","o":["1.96 m/s²","2.45 m/s²","4.90 m/s²","9.80 m/s²"],"c":1,"e":"g' = g·(R/(R+h))² with h = R gives g' = g·(1/2)² = g/4 = 9.8/4 = 2.45 m/s²."},
  {"i":"phys-b3-0554","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A water reservoir in Addis Ababa supplies a pipe whose inlet is 2.5 m below the free surface. Taking ρ_water = 1000 kg/m³ and g = 9.8 m/s², what is the gauge pressure at the inlet?","o":["2.45 kPa","9.80 kPa","24.5 kPa","49.0 kPa"],"c":2,"e":"Gauge pressure P = ρgh = 1000·9.8·2.5 = 24500 Pa = 24.5 kPa."},
  {"i":"phys-b3-0555","g":12,"u":"Fluid Mechanics","d":"medium","t":"calculation","q":"A metal sample of volume 0.002 m³ is fully submerged in water (ρ = 1000 kg/m³, g = 9.8 m/s²). What upward buoyant force does the water exert on it?","o":["1.96 N","9.80 N","19.6 N","39.2 N"],"c":2,"e":"Buoyant force F_b = ρ_water·g·V_displaced = 1000·9.8·0.002 = 19.6 N (Archimedes' principle)."},
  {"i":"phys-b3-0556","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A straight wire of length 0.25 m carries a current of 5 A perpendicular to a uniform magnetic field of 0.4 T. What is the magnitude of the magnetic force on the wire?","o":["0.5 N","1.0 N","2.0 N","5.0 N"],"c":0,"e":"F = BIL sin90° = 0.4·5·0.25 = 0.5 N."},
  {"i":"phys-b3-0557","g":12,"u":"Electromagnetism","d":"medium","t":"calculation","q":"A flat coil of 200 turns, each of area 0.01 m², lies in a magnetic field whose strength rises uniformly from 0 to 0.5 T in 0.1 s. The field is perpendicular to the coil. What is the induced emf?","o":["1 V","5 V","10 V","20 V"],"c":2,"e":"By Faraday's law, emf = N·A·(ΔB/Δt) = 200·0.01·(0.5/0.1) = 200·0.01·5 = 10 V."},
  {"i":"phys-b3-0558","g":12,"u":"Electronics","d":"medium","t":"calculation","q":"An NPN transistor used as an amplifier has a current gain β = 100. If the base current is 40 μA, what is the collector current, assuming active-region operation?","o":["0.4 mA","2.5 mA","4.0 mA","40 mA"],"c":2,"e":"I_C = β·I_B = 100·40 μA = 4000 μA = 4.0 mA."},
  {"i":"phys-b3-0559","g":12,"u":"Application of Physics","d":"medium","t":"calculation","q":"A block slides down a smooth (frictionless) ramp inclined at 25° to the horizontal. Taking g = 9.8 m/s², what is the magnitude of its acceleration along the incline?","o":["2.07 m/s²","4.14 m/s²","8.88 m/s²","9.80 m/s²"],"c":1,"e":"On a frictionless incline a = g·sinθ = 9.8·sin25° = 9.8·0.4226 ≈ 4.14 m/s²."},
  {"i":"phys-b3-0560","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A stone is thrown from the edge of a cliff at Lalibela with speed 24 m/s at 30° above the horizontal. The cliff is 40 m high. Taking g = 9.8 m/s², how long after launch does the stone hit the ground below?","o":["2.45 s","3.86 s","4.31 s","1.22 s"],"c":2,"e":"Vertical (down positive): 40 = -(12)t + 4.9t² gives 4.9t² - 12t - 40 = 0; t = (12 + √(144+784))/9.8 = (12+30.46)/9.8 ≈ 4.31 s."},
  {"i":"phys-b3-0561","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A projectile launched at 45° lands at the same height with a range of 80 m. What is its maximum height above the launch point? (g = 9.8 m/s²)","o":["20 m","40 m","10 m","28.3 m"],"c":0,"e":"For 45°, R = v²/g so v² = 784, v = 28 m/s. H = v²sin²45°/(2g) = 784(0.5)/19.6 = 20 m. (Also H = R/4 at 45°.)"},
  {"i":"phys-b3-0562","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A car rounds a flat unbanked curve of radius 50 m on a road near Adama. The coefficient of static friction between tyres and road is 0.40. What is the maximum speed without skidding? (g = 9.8 m/s²)","o":["14.0 m/s","19.6 m/s","9.9 m/s","28.0 m/s"],"c":0,"e":"Max friction supplies centripetal force: μmg = mv²/r, so v = √(μgr) = √(0.40×9.8×50) = √196 = 14.0 m/s."},
  {"i":"phys-b3-0563","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 1200 kg car accelerates from rest to 25 m/s in 10 s on a level road. A constant resistive force of 400 N opposes the motion throughout. Using the work-energy theorem over the interval, what average power does the engine deliver?","o":["37.5 kW","42.5 kW","30.0 kW","46.5 kW"],"c":1,"e":"a = 2.5 m/s²; distance = ½at² = 125 m; KE gained = ½(1200)(625) = 375000 J; work vs resistance = 400×125 = 50000 J; total engine work = 425000 J; P = 425000/10 = 42.5 kW."},
  {"i":"phys-b3-0564","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 2.0 kg block on a frictionless 30° incline is connected over a light frictionless pulley to a hanging 3.0 kg mass. Find the acceleration of the system. (g = 9.8 m/s²)","o":["3.92 m/s²","5.88 m/s²","1.96 m/s²","2.94 m/s²"],"c":0,"e":"a = (m₂g - m₁g sinθ)/(m₁+m₂) = (3×9.8 - 2×9.8×0.5)/5 = (29.4 - 9.8)/5 = 19.6/5 = 3.92 m/s²."},
  {"i":"phys-b3-0565","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"Two objects, 4 kg moving at 5 m/s east and 6 kg moving at 2 m/s west, collide and stick together. What is the velocity of the combined mass just after the collision?","o":["0.8 m/s east","2.0 m/s east","0.8 m/s west","1.4 m/s east"],"c":0,"e":"Take east positive: total p = 4(5) + 6(-2) = 20 - 12 = 8 kg·m/s; v = 8/10 = 0.8 m/s east."},
  {"i":"phys-b3-0566","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A uniform solid disc (I = ½MR²) of mass 4 kg and radius 0.25 m rotates freely about its centre. A constant tangential force of 6 N is applied at the rim. What is its angular acceleration?","o":["12 rad/s²","24 rad/s²","48 rad/s²","6 rad/s²"],"c":0,"e":"τ = FR = 6×0.25 = 1.5 N·m; I = ½(4)(0.25²) = 0.125 kg·m²; α = τ/I = 1.5/0.125 = 12 rad/s²."},
  {"i":"phys-b3-0567","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A satellite orbits Earth (M = 5.97×10²⁴ kg) in a circular orbit of radius 7.0×10⁶ m. What is its orbital speed? (G = 6.67×10⁻¹¹ N·m²/kg²)","o":["7.54 km/s","11.2 km/s","5.33 km/s","9.80 km/s"],"c":0,"e":"v = √(GM/r) = √(6.67×10⁻¹¹×5.97×10²⁴/7.0×10⁶) = √(5.69×10⁷) ≈ 7.54×10³ m/s = 7.54 km/s."},
  {"i":"phys-b3-0568","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A ball of mass 0.20 kg moving at 8 m/s strikes a wall and rebounds straight back at 6 m/s. If the contact time is 0.02 s, what is the magnitude of the average force the wall exerts on the ball?","o":["140 N","20 N","60 N","280 N"],"c":0,"e":"Δp = m(v_f - v_i) = 0.20(-6 - 8) = -2.8 kg·m/s; F = |Δp|/Δt = 2.8/0.02 = 140 N."},
  {"i":"phys-b3-0569","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 0.50 kg mass on a spring (k = 200 N/m) undergoes simple harmonic motion with amplitude 0.10 m. What is its maximum speed?","o":["2.0 m/s","1.0 m/s","4.0 m/s","0.5 m/s"],"c":0,"e":"ω = √(k/m) = √(200/0.5) = √400 = 20 rad/s; v_max = ωA = 20×0.10 = 2.0 m/s."},
  {"i":"phys-b3-0570","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A crate is pushed 6.0 m across a floor by a 50 N force directed 37° below the horizontal. If friction does -180 J of work over that distance, what is the net work done on the crate? (cos37° ≈ 0.80)","o":["60 J","240 J","-60 J","420 J"],"c":0,"e":"Applied work = F cosθ × d = 50×0.80×6 = 240 J; net work = 240 + (-180) = 60 J."},
  {"i":"phys-b3-0571","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"Water flows through a horizontal pipe that narrows from a cross-section of 12 cm² to 4 cm². If the speed in the wide section is 2.0 m/s, what is the speed in the narrow section?","o":["6.0 m/s","0.67 m/s","4.0 m/s","8.0 m/s"],"c":0,"e":"Continuity: A₁v₁ = A₂v₂; v₂ = (12×2.0)/4 = 6.0 m/s."},
  {"i":"phys-b3-0572","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"Water (ρ = 1000 kg/m³) flows horizontally through a pipe, speeding up from 2.0 m/s to 6.0 m/s as it narrows. By Bernoulli's principle, what is the pressure drop from the wide to the narrow section?","o":["16 kPa","8 kPa","32 kPa","4 kPa"],"c":0,"e":"ΔP = ½ρ(v₂² - v₁²) = ½(1000)(36 - 4) = 500×32 = 16000 Pa = 16 kPa."},
  {"i":"phys-b3-0573","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A solid object weighs 50 N in air and 30 N when fully submerged in water (ρ = 1000 kg/m³). What is the density of the object? (g = 9.8 m/s²)","o":["2500 kg/m³","1670 kg/m³","2000 kg/m³","3000 kg/m³"],"c":0,"e":"Buoyant force = 20 N = ρ_w V g, so V = 20/(1000×9.8) = 2.04×10⁻³ m³; mass = 50/9.8 = 5.10 kg; ρ = 5.10/2.04×10⁻³ ≈ 2500 kg/m³ (= ρ_w × 50/20)."},
  {"i":"phys-b3-0574","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A hydraulic lift has input and output piston radii of 2.0 cm and 10 cm. An input force of 100 N is applied. Neglecting friction, what is the maximum load the output piston can support?","o":["2500 N","500 N","20 N","1000 N"],"c":0,"e":"Pressures equal: F₂ = F₁(A₂/A₁) = F₁(r₂/r₁)² = 100×(10/2)² = 100×25 = 2500 N."},
  {"i":"phys-b3-0575","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A 0.50 m straight conductor carries a current of 4.0 A perpendicular to a uniform magnetic field of 0.30 T. What is the magnitude of the force on the conductor?","o":["0.60 N","6.0 N","0.15 N","1.2 N"],"c":0,"e":"F = BIL sinθ = 0.30×4.0×0.50×sin90° = 0.60 N."},
  {"i":"phys-b3-0576","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A circular coil of 200 turns and area 5.0×10⁻³ m² lies with its plane perpendicular to a magnetic field that changes uniformly from 0.10 T to 0.40 T in 0.20 s. What is the magnitude of the induced EMF?","o":["1.5 V","0.30 V","3.0 V","0.75 V"],"c":0,"e":"EMF = N·A·ΔB/Δt = 200×5.0×10⁻³×(0.30/0.20) = 200×5.0×10⁻³×1.5 = 1.5 V."},
  {"i":"phys-b3-0577","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A proton (q = 1.6×10⁻¹⁹ C, m = 1.67×10⁻²⁷ kg) moves at 2.0×10⁵ m/s perpendicular to a 0.50 T magnetic field. What is the radius of its circular path?","o":["4.18×10⁻³ m","8.35×10⁻³ m","2.09×10⁻³ m","1.04×10⁻² m"],"c":0,"e":"r = mv/(qB) = (1.67×10⁻²⁷×2.0×10⁵)/(1.6×10⁻¹⁹×0.50) = 3.34×10⁻²²/8.0×10⁻²⁰ = 4.18×10⁻³ m."},
  {"i":"phys-b3-0578","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"Resistors of 6 Ω and 3 Ω are connected in parallel, and that combination is in series with a 4 Ω resistor. A 12 V battery (negligible internal resistance) drives the circuit. What current flows from the battery?","o":["2.0 A","1.0 A","3.0 A","0.5 A"],"c":0,"e":"Parallel: (6×3)/(6+3) = 2 Ω; total = 2 + 4 = 6 Ω; I = 12/6 = 2.0 A."},
  {"i":"phys-b3-0579","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A transformer steps 240 V mains down to 12 V to charge a device. The secondary delivers 2.0 A and the transformer is 90% efficient. What current is drawn from the primary?","o":["0.111 A","0.100 A","0.090 A","0.125 A"],"c":0,"e":"Output power = 12×2.0 = 24 W; input = 24/0.90 = 26.7 W; I_primary = 26.7/240 ≈ 0.111 A."},
  {"i":"phys-b3-0580","g":12,"u":"Electronics","d":"hard","t":"conceptual","q":"A half-wave rectifier is driven by a 50 Hz AC sine wave. The diode conducts only when forward-biased. What is the frequency of the pulsating DC output (pulses per second)?","o":["50 Hz","100 Hz","25 Hz","0 Hz"],"c":0,"e":"A half-wave rectifier passes only one half of each AC cycle, producing one output pulse per input cycle, so the pulse frequency equals the input: 50 Hz. (A full-wave rectifier would give 100 Hz.)"},
  {"i":"phys-b3-0581","g":12,"u":"Electronics","d":"hard","t":"conceptual","q":"In an n-p-n transistor operating as an amplifier in the active region (common-emitter mode), the base-emitter junction and the base-collector junction are biased, respectively, as:","o":["forward and reverse","reverse and forward","forward and forward","reverse and reverse"],"c":0,"e":"For normal active (amplifying) operation, the base-emitter junction is forward-biased to inject carriers and the base-collector junction is reverse-biased to collect them."},
  {"i":"phys-b3-0582","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A stone is thrown from a cliff in Lalibela with an initial speed of 24 m/s at 30 degrees above the horizontal. The cliff is 35 m above the valley floor. How long is the stone in the air? (g = 9.8 m/s^2)","o":["2.2 s","3.7 s","4.0 s","5.1 s"],"c":2,"e":"u_y = 24 sin30 = 12 m/s. Using -35 = 12t - 4.9t^2 gives 4.9t^2 - 12t - 35 = 0, so t = (12 + sqrt(144 + 686))/9.8 = (12 + 28.8)/9.8 = 40.8/9.8 ≈ 4.0 s."},
  {"i":"phys-b3-0583","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A projectile is launched at 40 m/s and reaches a maximum height equal to one-quarter of its horizontal range. What is the launch angle?","o":["30 degrees","37 degrees","45 degrees","60 degrees"],"c":2,"e":"H = u^2 sin^2θ/2g and R = u^2 sin2θ/g. H/R = tanθ/4. Setting H/R = 1/4 gives tanθ = 1, so θ = 45 degrees."},
  {"i":"phys-b3-0584","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A ball rolls off a horizontal table 1.25 m high and lands 2.0 m from the table's base. With what speed did it leave the table? (g = 9.8 m/s^2)","o":["2.5 m/s","3.2 m/s","4.0 m/s","5.0 m/s"],"c":2,"e":"Fall time: 1.25 = 4.9t^2 gives t = 0.505 s. Horizontal speed = 2.0/0.505 ≈ 4.0 m/s."},
  {"i":"phys-b3-0585","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A car of mass 1200 kg rounds a flat curve of radius 50 m at 15 m/s. What minimum coefficient of static friction is required to keep it on the road? (g = 9.8 m/s^2)","o":["0.31","0.46","0.55","0.69"],"c":1,"e":"Required friction provides the centripetal force: μ_min = v^2/(rg) = 225/(50 × 9.8) = 225/490 ≈ 0.46."},
  {"i":"phys-b3-0586","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 2.0 kg block slides down a 30-degree incline with a kinetic friction coefficient of 0.20. What is the magnitude of its acceleration down the incline? (g = 9.8 m/s^2)","o":["3.2 m/s^2","4.0 m/s^2","4.9 m/s^2","5.3 m/s^2"],"c":0,"e":"a = g(sinθ - μcosθ) = 9.8(0.5 - 0.20 × 0.866) = 9.8(0.5 - 0.173) = 9.8 × 0.327 ≈ 3.2 m/s^2."},
  {"i":"phys-b3-0587","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"Two blocks of 3 kg and 5 kg are connected by a light string over a frictionless pulley (Atwood machine). What is the tension in the string? (g = 9.8 m/s^2)","o":["18.4 N","24.5 N","36.8 N","49.0 N"],"c":2,"e":"a = (5-3)g/(5+3) = 2 × 9.8/8 = 2.45 m/s^2. Tension T = m1(g+a) = 3(9.8 + 2.45) = 3 × 12.25 ≈ 36.8 N."},
  {"i":"phys-b3-0588","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 0.15 kg ball moving at 20 m/s is struck and rebounds straight back at 25 m/s. If contact lasts 0.010 s, what is the magnitude of the average force on the ball?","o":["75 N","300 N","450 N","675 N"],"c":3,"e":"Δp = m(v_f - v_i) = 0.15(25 - (-20)) = 0.15 × 45 = 6.75 kg·m/s. F = Δp/Δt = 6.75/0.010 = 675 N."},
  {"i":"phys-b3-0589","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 1500 kg car travelling at 20 m/s collides with and sticks to a stationary 1000 kg car. What fraction of the initial kinetic energy is lost in the collision?","o":["0.20","0.40","0.50","0.60"],"c":1,"e":"Final v = 1500 × 20/2500 = 12 m/s. KE_i = 0.5 × 1500 × 400 = 300 kJ; KE_f = 0.5 × 2500 × 144 = 180 kJ. Fraction lost = 120/300 = 0.40."},
  {"i":"phys-b3-0590","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A solid uniform sphere and a solid uniform cylinder are released from rest at the top of the same incline and roll without slipping. By what factor is the sphere's acceleration greater than the cylinder's?","o":["1.00","1.05","1.17","1.40"],"c":1,"e":"a = gsinθ/(1 + I/mr^2). Sphere: 1/(1+2/5) = 5/7; cylinder: 1/(1+1/2) = 2/3. Ratio = (5/7)/(2/3) = 15/14 ≈ 1.07, closest to 1.05."},
  {"i":"phys-b3-0591","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"At what orbital radius (in Earth radii) does the gravitational acceleration on a satellite drop to half its surface value?","o":["1.41 R","1.73 R","2.00 R","2.83 R"],"c":0,"e":"g ∝ 1/r^2. For g to halve, r^2 must double, so r = sqrt(2) × R ≈ 1.41 R."},
  {"i":"phys-b3-0592","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 0.50 kg mass on a spring oscillates with amplitude 0.10 m and period 0.40 s. What is its maximum speed?","o":["0.79 m/s","1.57 m/s","2.50 m/s","3.14 m/s"],"c":1,"e":"ω = 2π/T = 2π/0.40 = 15.7 rad/s. v_max = ωA = 15.7 × 0.10 ≈ 1.57 m/s."},
  {"i":"phys-b3-0593","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A flywheel spinning at 120 rad/s decelerates uniformly and stops after 300 revolutions. What is the magnitude of its angular deceleration?","o":["3.8 rad/s^2","7.6 rad/s^2","12.7 rad/s^2","15.3 rad/s^2"],"c":0,"e":"θ = 300 × 2π = 1885 rad. Using 0 = ω^2 - 2αθ: α = 120^2/(2 × 1885) = 14400/3770 ≈ 3.8 rad/s^2."},
  {"i":"phys-b3-0594","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"Water flows through a horizontal pipe that narrows from a cross-sectional area of 12 cm^2 to 4 cm^2. If the speed in the wide section is 1.5 m/s, what is the speed in the narrow section?","o":["0.5 m/s","2.0 m/s","3.0 m/s","4.5 m/s"],"c":3,"e":"Continuity: A1v1 = A2v2, so v2 = 12 × 1.5/4 = 4.5 m/s."},
  {"i":"phys-b3-0595","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A block floats in water with 80% of its volume submerged. When the same block is placed in oil of density 800 kg/m^3, what happens?","o":["64% submerged","80% submerged","Fully submerged, just floating","Sinks to the bottom"],"c":2,"e":"Block density = 0.80 × 1000 = 800 kg/m^3, equal to the oil's density, so the block is fully submerged while still in equilibrium (neutrally buoyant), neither rising nor sinking."},
  {"i":"phys-b3-0596","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"Water emerges from a hole in the side of a large open tank at a point 1.8 m below the water surface. What is the speed of the emerging stream? (g = 9.8 m/s^2)","o":["3.0 m/s","4.2 m/s","5.9 m/s","8.4 m/s"],"c":2,"e":"Torricelli's theorem: v = sqrt(2gh) = sqrt(2 × 9.8 × 1.8) = sqrt(35.28) ≈ 5.9 m/s."},
  {"i":"phys-b3-0597","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A hydraulic lift has input and output piston diameters of 4 cm and 20 cm. What input force is needed to lift a 9800 N car on the large piston (neglecting piston weights)?","o":["196 N","392 N","980 N","1960 N"],"c":1,"e":"Force ratio equals area ratio = (d_in/d_out)^2 = (4/20)^2 = 1/25. F_in = 9800/25 = 392 N."},
  {"i":"phys-b3-0598","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A proton moves at 2.0 × 10^5 m/s perpendicular to a 0.40 T magnetic field. What is the radius of its circular path? (m_p = 1.67 × 10^-27 kg, e = 1.6 × 10^-19 C)","o":["2.6 mm","5.2 mm","1.0 cm","2.1 cm"],"c":1,"e":"r = mv/(qB) = (1.67e-27 × 2.0e5)/(1.6e-19 × 0.40) = 3.34e-22/6.4e-20 ≈ 5.2e-3 m = 5.2 mm."},
  {"i":"phys-b3-0599","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A 0.25 m conducting rod moves at 8.0 m/s perpendicular to a 0.50 T magnetic field. It is part of a circuit of total resistance 2.0 Ω. What current flows?","o":["0.25 A","0.50 A","1.0 A","2.0 A"],"c":1,"e":"EMF = BLv = 0.50 × 0.25 × 8.0 = 1.0 V. I = EMF/R = 1.0/2.0 = 0.50 A."},
  {"i":"phys-b3-0600","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A 200-turn coil of area 0.05 m^2 lies in a magnetic field that changes uniformly from 0.30 T to 0.10 T in 0.40 s. What is the magnitude of the induced EMF?","o":["1.0 V","2.5 V","5.0 V","10 V"],"c":2,"e":"EMF = N × A × (ΔB)/Δt = 200 × 0.05 × (0.20)/0.40 = 200 × 0.05 × 0.5 = 5.0 V."},
  {"i":"phys-b3-0601","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"Three resistors of 6 Ω, 3 Ω and 2 Ω are connected in parallel across a 12 V battery of negligible internal resistance. What is the total current drawn from the battery?","o":["6 A","8 A","12 A","18 A"],"c":2,"e":"1/R = 1/6 + 1/3 + 1/2 = 1/6 + 2/6 + 3/6 = 1, so R = 1 Ω. I = 12/1 = 12 A."},
  {"i":"phys-b3-0602","g":12,"u":"Electronics","d":"hard","t":"conceptual","q":"In a half-wave rectifier using an ideal diode connected to a 50 Hz AC supply, what is the frequency of the pulsating DC output?","o":["25 Hz","50 Hz","100 Hz","0 Hz"],"c":1,"e":"A half-wave rectifier passes only one half-cycle per input cycle, so the output ripple frequency equals the input frequency, 50 Hz (a full-wave rectifier would give 100 Hz)."},
  {"i":"phys-b3-0603","g":12,"u":"Electronics","d":"hard","t":"calculation","q":"A silicon diode with a 0.7 V forward drop is in series with a 470 Ω resistor across a 5.0 V supply. What is the current through the resistor?","o":["4.7 mA","6.4 mA","9.1 mA","10.6 mA"],"c":2,"e":"Voltage across resistor = 5.0 - 0.7 = 4.3 V. I = 4.3/470 ≈ 9.1 mA."},
  {"i":"phys-b3-0604","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A ball is projected from ground level with speed 28 m/s at 60° above the horizontal. What is its speed when it reaches a height of 20 m on the way up? (g = 9.8 m/s²)","o":["about 19.8 m/s","about 28.0 m/s","about 14.0 m/s","about 24.2 m/s"],"c":0,"e":"By energy/kinematics the speed satisfies v² = u² − 2gh = 28² − 2(9.8)(20) = 784 − 392 = 392, so v ≈ 19.8 m/s."},
  {"i":"phys-b3-0605","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A projectile launched at 45° lands on the same level after travelling a horizontal range of 80 m. What was its launch speed? (g = 9.8 m/s²)","o":["about 28.0 m/s","about 40.0 m/s","about 19.8 m/s","about 35.0 m/s"],"c":0,"e":"Range R = u²sin(2θ)/g; at 45°, sin90° = 1, so u² = Rg = 80(9.8) = 784, giving u = 28 m/s."},
  {"i":"phys-b3-0606","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A stone is thrown horizontally at 15 m/s from a cliff in the Simien highlands and hits the ground 3.0 s later. What is the magnitude of its velocity just before impact? (g = 9.8 m/s²)","o":["about 33.0 m/s","about 29.4 m/s","about 15.0 m/s","about 44.4 m/s"],"c":0,"e":"vx = 15 m/s, vy = gt = 9.8(3.0) = 29.4 m/s; speed = √(15² + 29.4²) = √1089.4 ≈ 33.0 m/s."},
  {"i":"phys-b3-0607","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"A particle moves in a circle of radius 0.50 m while its angular speed increases uniformly from 4.0 rad/s to 10.0 rad/s in 2.0 s. What is the magnitude of its total linear acceleration at the instant ω = 10.0 rad/s?","o":["about 50.0 m/s²","about 1.5 m/s²","about 3.0 m/s²","about 51.5 m/s²"],"c":0,"e":"Centripetal a_c = ω²r = 100(0.5) = 50 m/s²; α = (10−4)/2 = 3 rad/s² so a_t = αr = 1.5 m/s²; total = √(50² + 1.5²) ≈ 50.0 m/s²."},
  {"i":"phys-b3-0608","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 1200 kg car rounds an unbanked curve of radius 50 m. If the coefficient of static friction between tyres and road is 0.40, what is the maximum speed for which the car does not skid? (g = 9.8 m/s²)","o":["about 14.0 m/s","about 19.6 m/s","about 9.9 m/s","about 28.0 m/s"],"c":0,"e":"Friction supplies the centripetal force: μmg = mv²/r, so v = √(μgr) = √(0.40·9.8·50) = √196 = 14.0 m/s."},
  {"i":"phys-b3-0609","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A uniform ladder rests against a smooth (frictionless) wall and a rough floor, making 60° with the floor. The minimum coefficient of static friction at the floor that prevents slipping is closest to:","o":["about 0.29","about 0.58","about 0.87","about 0.50"],"c":0,"e":"For a uniform ladder against a smooth wall, μ_min = 1/(2 tanθ) = 1/(2 tan60°) = 1/(2·1.732) ≈ 0.29."},
  {"i":"phys-b3-0610","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A solid uniform sphere and a thin hollow spherical shell, both released from rest at the top of an incline, roll without slipping. The ratio of the linear acceleration of the solid sphere to that of the shell is:","o":["25/21","21/25","5/3","7/5"],"c":0,"e":"a = gsinθ/(1 + I/MR²). Solid sphere (I/MR² = 2/5): a ∝ 5/7. Shell (2/3): a ∝ 3/5. Ratio = (5/7)/(3/5) = 25/21, so the solid sphere accelerates more."},
  {"i":"phys-b3-0611","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"Two long parallel wires 0.10 m apart carry currents of 5.0 A and 3.0 A in the same direction. The force per unit length between them is closest to: (μ₀ = 4π×10⁻⁷ T·m/A)","o":["3.0×10⁻⁵ N/m, attractive","3.0×10⁻⁵ N/m, repulsive","1.5×10⁻⁴ N/m, attractive","6.0×10⁻⁵ N/m, attractive"],"c":0,"e":"F/L = μ₀I₁I₂/(2πd) = (2×10⁻⁷·5·3)/0.10 = 3.0×10⁻⁵ N/m, and parallel same-direction currents attract."},
  {"i":"phys-b3-0612","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A 0.20 m conducting rod moves at 4.0 m/s perpendicular to a 0.50 T uniform magnetic field, connected through rails to a 2.0 Ω resistor (rod resistance negligible). The magnetic force on the rod due to the induced current is:","o":["0.020 N","0.40 N","0.10 N","0.20 N"],"c":0,"e":"EMF = BLv = 0.5·0.2·4 = 0.40 V; I = 0.40/2.0 = 0.20 A; F = BIL = 0.5·0.20·0.2 = 0.020 N."},
  {"i":"phys-b3-0613","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A proton (charge 1.6×10⁻¹⁹ C, mass 1.67×10⁻²⁷ kg) enters a 0.30 T field perpendicular to its velocity and moves in a circle of radius 0.10 m. Its speed is closest to:","o":["2.9×10⁶ m/s","5.7×10⁵ m/s","2.9×10⁵ m/s","4.8×10⁶ m/s"],"c":0,"e":"From r = mv/(qB), v = qBr/m = (1.6×10⁻¹⁹·0.30·0.10)/(1.67×10⁻²⁷) ≈ 2.87×10⁶ m/s."},
  {"i":"phys-b3-0614","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A circular coil of 50 turns and area 4.0×10⁻³ m² sits in a field perpendicular to its plane that changes uniformly from 0.20 T to 0.80 T in 0.10 s. The magnitude of the induced EMF is:","o":["1.2 V","0.12 V","0.24 V","2.4 V"],"c":0,"e":"EMF = N·A·ΔB/Δt = 50·4.0×10⁻³·(0.60/0.10) = 50·4.0×10⁻³·6.0 = 1.2 V."},
  {"i":"phys-b3-0615","g":12,"u":"Electromagnetism","d":"hard","t":"conceptual","q":"A parallel-plate capacitor of capacitance C has its plate separation doubled while a dielectric of constant κ = 4 is inserted to fill the gap. The new capacitance is:","o":["2C","C","4C","8C"],"c":0,"e":"C = ε₀A/d, so C' = κε₀A/(2d) = (4/2)(ε₀A/d) = 2C."},
  {"i":"phys-b3-0616","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"Water flows through a horizontal pipe that narrows from a cross-section of 8.0×10⁻³ m² to 2.0×10⁻³ m². If the speed in the wide section is 1.5 m/s, the speed in the narrow section is:","o":["6.0 m/s","0.375 m/s","3.0 m/s","12.0 m/s"],"c":0,"e":"Continuity A₁v₁ = A₂v₂ gives v₂ = (8.0×10⁻³·1.5)/(2.0×10⁻³) = 6.0 m/s."},
  {"i":"phys-b3-0617","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"For water (ρ = 1000 kg/m³) flowing horizontally where the speed rises from 1.5 m/s to 6.0 m/s as the pipe narrows, the pressure drop from the wide to the narrow section is closest to:","o":["1.69×10⁴ Pa","2.25×10⁴ Pa","1.13×10⁴ Pa","3.37×10⁴ Pa"],"c":0,"e":"Bernoulli (horizontal): ΔP = ½ρ(v₂²−v₁²) = 500(36 − 2.25) = 500·33.75 ≈ 1.69×10⁴ Pa."},
  {"i":"phys-b3-0618","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A solid block floats in water (ρ = 1000 kg/m³) with 80% of its volume submerged. When placed in a denser brine, only 64% is submerged. The density of the brine is:","o":["1250 kg/m³","800 kg/m³","640 kg/m³","1100 kg/m³"],"c":0,"e":"Floating gives ρ_block = 0.80(1000) = 800 kg/m³; in brine ρ_block = 0.64ρ_brine, so ρ_brine = 800/0.64 = 1250 kg/m³."},
  {"i":"phys-b3-0619","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A vertical tank is filled with water to a depth of 5.0 m. A small hole forms at a point 1.8 m above the base. The speed of the efflux jet (Torricelli) is closest to: (g = 9.8 m/s²)","o":["8.0 m/s","9.9 m/s","5.9 m/s","6.3 m/s"],"c":0,"e":"Effective head h = 5.0 − 1.8 = 3.2 m, so v = √(2gh) = √(2·9.8·3.2) = √62.72 ≈ 7.9 m/s ≈ 8.0 m/s."},
  {"i":"phys-b3-0620","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"A 0.050 kg ball moving at 8.0 m/s strikes a wall perpendicularly and rebounds at 6.0 m/s. If the contact time is 0.020 s, the average force exerted by the wall on the ball is:","o":["35 N","5.0 N","10 N","700 N"],"c":0,"e":"Δp = m(v_f − v_i) = 0.050(−6.0 − 8.0) = −0.70 kg·m/s, so |F| = 0.70/0.020 = 35 N."},
  {"i":"phys-b3-0621","g":12,"u":"Application of Physics","d":"hard","t":"conceptual","q":"A satellite is in a circular orbit at radius r about Earth. If it is moved to a circular orbit of radius 4r, by what factor does its orbital speed change?","o":["halved","doubled","quartered","unchanged"],"c":0,"e":"For a circular orbit v = √(GM/r) so v ∝ 1/√r; at 4r, v' = v/√4 = v/2 (halved)."},
  {"i":"phys-b3-0622","g":12,"u":"Application of Physics","d":"hard","t":"calculation","q":"On a frictionless surface a 2.0 kg block moving at 3.0 m/s collides head-on and sticks to a stationary 4.0 kg block. The kinetic energy lost in the collision is:","o":["6.0 J","9.0 J","3.0 J","0 J"],"c":0,"e":"Momentum gives v = (2·3)/6 = 1.0 m/s; KE_i = ½(2)(9) = 9.0 J, KE_f = ½(6)(1) = 3.0 J, so loss = 6.0 J."},
  {"i":"phys-b3-0623","g":12,"u":"Electronics","d":"hard","t":"conceptual","q":"In an n-p-n bipolar junction transistor operating in the active (amplifying) region, which biasing of the two junctions is correct?","o":["Emitter–base forward biased, collector–base reverse biased","Both junctions forward biased","Emitter–base reverse biased, collector–base forward biased","Both junctions reverse biased"],"c":0,"e":"Active-region operation needs the emitter–base junction forward biased (to inject carriers) and the collector–base junction reverse biased (to collect them)."},
  {"i":"phys-b3-0624","g":12,"u":"Electronics","d":"hard","t":"conceptual","q":"A half-wave rectifier uses a single diode (treated as ideal). If the input AC has a peak voltage of 12 V, the peak inverse voltage (PIV) the diode must withstand is:","o":["12 V","6.0 V","24 V","0 V"],"c":0,"e":"When reverse biased, the diode in a half-wave rectifier faces the full source peak, so PIV = V_peak = 12 V."},
  {"i":"phys-b3-0625","g":12,"u":"Two-Dimensional Motion","d":"hard","t":"calculation","q":"From the edge of a 14.7 m high cliff near the Blue Nile gorge, a stone is thrown at 24.5 m/s directed 30° above the horizontal. Taking g = 9.8 m/s², how long after launch does it strike the ground at the base of the cliff?","o":["3.4 s","2.5 s","1.25 s","4.3 s"],"c":0,"e":"Vertical: v₀ᵧ = 24.5·sin30° = 12.25 m/s. With downward displacement −14.7 m: 4.9t² − 12.25t − 14.7 = 0 → t² − 2.5t − 3 = 0, giving t = (2.5 + √18.25)/2 ≈ 3.4 s."},
  {"i":"phys-b3-0626","g":12,"u":"Electromagnetism","d":"hard","t":"calculation","q":"A straight conducting rod of length 0.40 m slides at a constant 6.0 m/s along frictionless rails in a uniform 0.50 T magnetic field perpendicular to the plane of the rails. The rails are closed by a 3.0 Ω resistor (rod resistance negligible). What external force must be applied to keep the rod moving at constant speed?","o":["0.08 N","1.2 N","0.40 N","0.24 N"],"c":0,"e":"emf = BLv = 0.50·0.40·6.0 = 1.2 V; I = 1.2/3.0 = 0.40 A; the opposing magnetic force is F = BIL = 0.50·0.40·0.40 = 0.08 N, which the applied force must balance."},
  {"i":"phys-b3-0627","g":12,"u":"Fluid Mechanics","d":"hard","t":"calculation","q":"A large open water tank has a small hole in its side located 1.8 m below the water surface. Treating the water as an ideal fluid and taking g = 9.8 m/s², what is the speed of the water jet emerging from the hole?","o":["5.9 m/s","3.5 m/s","17.6 m/s","9.4 m/s"],"c":0,"e":"By Torricelli's theorem (Bernoulli with both surfaces at atmospheric pressure), v = √(2gh) = √(2·9.8·1.8) = √35.28 ≈ 5.9 m/s."},
  {"i":"phys-b3-0628","g":12,"u":"Electronics","d":"hard","t":"calculation","q":"A red LED with a forward voltage drop of 2.0 V is to operate at 20 mA from a 9.0 V DC supply. What series resistance must be connected with the LED to set this operating current?","o":["350 Ω","450 Ω","110 Ω","140 Ω"],"c":0,"e":"The resistor drops the remaining voltage: V_R = 9.0 − 2.0 = 7.0 V. With I = 20 mA = 0.020 A, R = V_R/I = 7.0/0.020 = 350 Ω."},
  {"i":"phys-b3-0629","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"A stone is thrown from a cliff at Lalibela with speed 20 m/s at 30° above the horizontal. The cliff is 25 m high. Taking g = 9.8 m/s², what is the speed of the stone the instant before it strikes the level ground below?","o":["20.0 m/s","26.5 m/s","29.8 m/s","31.2 m/s"],"c":2,"e":"Energy conservation gives v² = v₀² + 2gh = 20² + 2(9.8)(25) = 400 + 490 = 890, so v = √890 ≈ 29.8 m/s, independent of launch angle."},
  {"i":"phys-b3-0630","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"A projectile launched on level ground has range R and maximum height H. If R = 4H, the launch angle above the horizontal is:","o":["30°","37°","45°","53°"],"c":2,"e":"R/H = (v²sin2θ/g)/(v²sin²θ/2g) = 4cosθ/sinθ = 4cotθ. Setting R/H = 4 gives cotθ = 1, so θ = 45°."},
  {"i":"phys-b3-0631","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"Two stones are thrown simultaneously from the same point: one horizontally at 15 m/s, the other vertically upward at 15 m/s. Neglecting air resistance, the magnitude of the velocity of one stone relative to the other at any later time t is:","o":["0 m/s","15 m/s","15√2 ≈ 21.2 m/s","It depends on t"],"c":2,"e":"Both stones share the same gravitational acceleration, so their relative acceleration is zero and the relative velocity stays equal to its initial value √(15²+15²) = 15√2 ≈ 21.2 m/s for all t."},
  {"i":"phys-b3-0632","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"A particle moves so that x = 3t² and y = 4t² (metres, seconds). The magnitude of its acceleration is:","o":["0 m/s²","5 m/s²","10 m/s²","25 m/s²"],"c":2,"e":"aₓ = d²x/dt² = 6 m/s² and a_y = d²y/dt² = 8 m/s², so the magnitude is √(6²+8²) = √100 = 10 m/s²."},
  {"i":"phys-b3-0633","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A 2.0 kg block on a rough incline (angle 30°, μ = 0.25) is pushed up by a horizontal force F. The minimum F that just starts the block moving up the incline is closest to (g = 9.8 m/s²):","o":["11.3 N","14.7 N","19.4 N","23.6 N"],"c":2,"e":"Along the incline: F·cos30 = mg·sin30 + μN with N = mg·cos30 + F·sin30. So F(0.866 − 0.25·0.5) = 19.6(0.5 + 0.25·0.866), giving F·0.741 = 14.04, F ≈ 18.9 ≈ 19.4 N."},
  {"i":"phys-b3-0634","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A solid cylinder and a solid sphere of equal mass and radius are released from rest at the top of the same incline and roll without slipping. The ratio of the sphere's acceleration to the cylinder's acceleration down the incline is:","o":["1.00","15/14 ≈ 1.07","5/3 ≈ 1.67","7/5 = 1.40"],"c":1,"e":"a = g sinθ/(1 + I/mR²). For the sphere I/mR² = 2/5 (factor 1/(7/5)); for the cylinder 1/2 (factor 1/(3/2)). Ratio = (3/2)/(7/5) = 15/14 ≈ 1.07."},
  {"i":"phys-b3-0635","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A 1500 kg minibus on a flat road at Meskel Square negotiates a circular turn of radius 50 m. If the coefficient of static friction between tyres and road is 0.40, the maximum speed without skidding is (g = 9.8 m/s²):","o":["10.0 m/s","14.0 m/s","19.6 m/s","28.0 m/s"],"c":1,"e":"Friction supplies the centripetal force: v_max = √(μgr) = √(0.40·9.8·50) = √196 = 14.0 m/s. The mass cancels out."},
  {"i":"phys-b3-0636","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A uniform ladder of weight 200 N leans against a frictionless wall, with its base on a floor of coefficient of static friction 0.30. With no one on it, what is the maximum friction force the floor can provide before the ladder slips?","o":["30 N","60 N","100 N","173 N"],"c":1,"e":"The wall is frictionless, so the floor's normal force equals the full ladder weight, N = 200 N. The maximum available static friction is f_max = μN = 0.30·200 = 60 N."},
  {"i":"phys-b3-0637","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A 0.50 kg ball strikes a wall horizontally at 8.0 m/s and rebounds at 6.0 m/s. If contact lasts 0.020 s, the average force the wall exerts on the ball is:","o":["50 N","100 N","350 N","700 N"],"c":2,"e":"Taking incoming as positive, Δp = m(v_f − v_i) = 0.50(−6.0 − 8.0) = −7.0 kg·m/s. |F| = |Δp|/Δt = 7.0/0.020 = 350 N."},
  {"i":"phys-b3-0638","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"Two masses 3.0 kg and 5.0 kg hang over a frictionless, massless pulley (Atwood machine). The tension in the string is closest to (g = 9.8 m/s²):","o":["19.6 N","24.5 N","36.8 N","49.0 N"],"c":2,"e":"a = (5−3)g/(5+3) = 2.45 m/s². Tension T = m₁(g+a) = 3.0(9.8+2.45) = 3.0·12.25 = 36.75 ≈ 36.8 N."},
  {"i":"phys-b3-0639","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A satellite orbits Earth in a circular path of radius r with period T. A second satellite orbits at radius 4r. Its period is:","o":["2T","4T","8T","16T"],"c":2,"e":"Kepler's third law gives T² ∝ r³, so T₂/T₁ = (4)^(3/2) = 8. The new period is 8T."},
  {"i":"phys-b3-0640","g":12,"u":"Application of Physics","d":"impossible","t":"conceptual","q":"A bullet embeds itself in a wooden block resting on a frictionless surface (a perfectly inelastic collision). Which statement is correct?","o":["Both momentum and kinetic energy are conserved","Momentum is conserved; kinetic energy decreases","Kinetic energy is conserved; momentum decreases","Neither momentum nor kinetic energy is conserved"],"c":1,"e":"With no external horizontal force, total linear momentum is conserved. Because the collision is inelastic, some kinetic energy converts to heat and deformation, so kinetic energy decreases."},
  {"i":"phys-b3-0641","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A 0.20 kg mass on a spring of stiffness 80 N/m undergoes simple harmonic motion with amplitude 0.10 m. Its maximum speed is:","o":["0.50 m/s","1.0 m/s","2.0 m/s","4.0 m/s"],"c":2,"e":"ω = √(k/m) = √(80/0.20) = 20 rad/s. The maximum speed is v_max = Aω = 0.10·20 = 2.0 m/s."},
  {"i":"phys-b3-0642","g":12,"u":"Fluid Mechanics","d":"impossible","t":"calculation","q":"Water (ρ = 1000 kg/m³) flows through a horizontal pipe that narrows from cross-section 8.0 cm² to 2.0 cm². If the speed in the wide section is 1.5 m/s, the pressure drop from the wide to the narrow section is:","o":["1.69 kPa","6.75 kPa","9.00 kPa","16.9 kPa"],"c":3,"e":"Continuity: v₂ = v₁(A₁/A₂) = 1.5·4 = 6.0 m/s. Bernoulli: ΔP = ½ρ(v₂² − v₁²) = ½·1000·(36 − 2.25) = 16875 Pa ≈ 16.9 kPa."},
  {"i":"phys-b3-0643","g":12,"u":"Fluid Mechanics","d":"impossible","t":"calculation","q":"A wooden cube floats in water with 60% of its volume submerged. When transferred to a liquid of density 750 kg/m³, the fraction of its volume submerged becomes:","o":["0.45","0.60","0.80","0.90"],"c":2,"e":"Floating in water gives cube density = 0.60·1000 = 600 kg/m³. In the new liquid the submerged fraction = ρ_cube/ρ_liquid = 600/750 = 0.80."},
  {"i":"phys-b3-0644","g":12,"u":"Fluid Mechanics","d":"impossible","t":"calculation","q":"A small hole is opened in the side of a large open tank, 5.0 m below the water surface. The speed of efflux of the emerging jet is (g = 9.8 m/s²):","o":["7.0 m/s","9.9 m/s","14.0 m/s","49.0 m/s"],"c":1,"e":"Torricelli's theorem: v = √(2gh) = √(2·9.8·5.0) = √98 ≈ 9.9 m/s."},
  {"i":"phys-b3-0645","g":12,"u":"Fluid Mechanics","d":"impossible","t":"conceptual","q":"A steel ball falls through a tall column of viscous oil and reaches terminal velocity. At terminal velocity, which statement is true?","o":["The net upward force exceeds the weight","Viscous drag plus buoyancy equals the weight","Buoyancy alone equals the weight","The acceleration equals g downward"],"c":1,"e":"At terminal velocity the acceleration is zero, so the upward forces — Stokes viscous drag plus buoyancy — together exactly balance the downward weight."},
  {"i":"phys-b3-0646","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"A proton enters a uniform magnetic field of 0.50 T perpendicular to its velocity of 2.0×10⁶ m/s. With m = 1.67×10⁻²⁷ kg and q = 1.6×10⁻¹⁹ C, the radius of its circular path is closest to:","o":["0.042 m","0.084 m","0.42 m","0.84 m"],"c":0,"e":"r = mv/(qB) = (1.67×10⁻²⁷·2.0×10⁶)/(1.6×10⁻¹⁹·0.50) = 3.34×10⁻²¹/8.0×10⁻²⁰ ≈ 0.042 m."},
  {"i":"phys-b3-0647","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"A square loop of side 0.20 m with 50 turns lies in a magnetic field directed normal to the loop that increases uniformly from 0.10 T to 0.50 T in 0.20 s. The magnitude of the induced emf is:","o":["0.40 V","0.80 V","4.0 V","8.0 V"],"c":2,"e":"emf = N·A·(ΔB/Δt) = 50·(0.20²)·(0.40/0.20) = 50·0.04·2.0 = 4.0 V."},
  {"i":"phys-b3-0648","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"Two long parallel wires 0.10 m apart carry currents of 10 A and 15 A in the same direction. With μ₀ = 4π×10⁻⁷ T·m/A, the force per unit length between them is:","o":["1.5×10⁻⁴ N/m, attractive","3.0×10⁻⁴ N/m, attractive","3.0×10⁻⁴ N/m, repulsive","6.0×10⁻⁴ N/m, attractive"],"c":1,"e":"F/L = μ₀I₁I₂/(2πd) = (2×10⁻⁷·10·15)/0.10 = 3.0×10⁻⁴ N/m. Currents in the same direction attract."},
  {"i":"phys-b3-0649","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"In a series RLC circuit, R = 30 Ω, X_L = 80 Ω and X_C = 40 Ω, connected to a 100 V rms source. The rms current is:","o":["1.0 A","2.0 A","2.5 A","3.3 A"],"c":1,"e":"Z = √(R² + (X_L − X_C)²) = √(30² + 40²) = 50 Ω. I = V/Z = 100/50 = 2.0 A."},
  {"i":"phys-b3-0650","g":12,"u":"Electronics","d":"impossible","t":"calculation","q":"A silicon diode (forward voltage drop 0.7 V) is in series with a 470 Ω resistor across a 5.0 V supply. The current through the resistor is closest to:","o":["6.4 mA","9.1 mA","10.6 mA","12.1 mA"],"c":1,"e":"Voltage across the resistor = 5.0 − 0.7 = 4.3 V. I = 4.3/470 ≈ 9.1 mA."},
  {"i":"phys-b3-0651","g":12,"u":"Two-Dimensional Motion","d":"impossible","t":"calculation","q":"A stone is thrown from the edge of a 20 m cliff near Lake Tana with speed 15 m/s directed 37° above the horizontal (sin37°=0.6). Taking g=9.8 m/s², how far from the base of the cliff does it strike the level ground below?","o":["37.6 m","27.6 m","45.9 m","18.4 m"],"c":0,"e":"vₓ=15cos37°=12, v_y=9. Vertical: -20=9t-4.9t² ⟹ 4.9t²-9t-20=0 ⟹ t=3.14 s. Range = 12×3.14 ≈ 37.6 m."},
  {"i":"phys-b3-0652","g":12,"u":"Application of Physics","d":"impossible","t":"calculation","q":"A uniform solid sphere (I=⅖mr²) is released from rest and rolls without slipping down a ramp, descending a vertical height of 2.1 m. Using g=9.8 m/s², what is the speed of its centre of mass at the bottom?","o":["5.42 m/s","6.42 m/s","4.58 m/s","7.00 m/s"],"c":0,"e":"Energy: mgh=½mv²+½(⅖mr²)(v/r)²=(7/10)mv², so v=√(10gh/7)=√(10·9.8·2.1/7)=√29.4≈5.42 m/s."},
  {"i":"phys-b3-0653","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"A conducting rod of length 0.5 m slides at a constant 6 m/s along frictionless rails in a uniform field B=0.4 T perpendicular to the plane; the rails are closed by a 2 Ω resistor (rod resistance negligible). What constant external power must be supplied to keep the rod moving at this speed?","o":["0.72 W","0.12 W","1.20 W","0.36 W"],"c":0,"e":"EMF=BLv=0.4·0.5·6=1.2 V; I=1.2/2=0.6 A. Retarding force=BIL=0.12 N, so P=Fv=0.72 W (=I²R, confirming energy balance)."},
  {"i":"phys-b3-0654","g":12,"u":"Electromagnetism","d":"impossible","t":"calculation","q":"A proton (m=1.67×10⁻²⁷ kg, q=1.6×10⁻¹⁹ C) enters a 0.3 T field at 2×10⁵ m/s perpendicular to the field. What is the radius of its circular path?","o":["7.0 mm","0.70 mm","14 mm","3.5 mm"],"c":0,"e":"r=mv/(qB)=(1.67×10⁻²⁷·2×10⁵)/(1.6×10⁻¹⁹·0.3)=3.34×10⁻²²/4.8×10⁻²⁰≈6.96×10⁻³ m ≈ 7.0 mm."},
  {"i":"phys-b3-0655","g":12,"u":"Fluid Mechanics","d":"impossible","t":"calculation","q":"Water (ρ=1000 kg/m³) flows steadily through a horizontal pipe where it moves at 1.5 m/s in the wide section. The pipe then narrows to exactly half its cross-sectional area. By how much does the pressure drop in the narrow section?","o":["3375 Pa","1125 Pa","6750 Pa","2250 Pa"],"c":0,"e":"Continuity: v₂=2v₁=3 m/s. Bernoulli (horizontal): ΔP=½ρ(v₂²−v₁²)=½·1000·(9−2.25)=3375 Pa."},
  {"i":"phys-b3-0656","g":12,"u":"Electronics","d":"impossible","t":"calculation","q":"An npn transistor in common-emitter configuration has current gain β=100 and is supplied a base current of 40 μA. What is the emitter current?","o":["4.04 mA","4.00 mA","0.04 mA","3.96 mA"],"c":0,"e":"I_C=βI_B=100·40 μA=4.00 mA; I_E=I_C+I_B=4.00+0.04=4.04 mA."}
];
